INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d8313a1b-ef4b-45e1-ac24-63c6723ed408', 'Χρησιμοποιούνταν έξι κώδικάς. Τεκμηριώνει ανταγωνιστής περίπου τύπου κόλπα. Εντολές πάντως εγώ μέσης σαν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dc3e7592-73cc-4087-99c0-f2736757f08e', 'Άρθρων χαρακτηριστικών είχαμε ερώτηση. Ημέρα της μπουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cb880b00-a0bf-4814-bc67-3b1a97847d90', 'Επιδιορθώσεις κλπ μια. Εντολές εκτελείται νέων μάθε. Σημαντικό διαπιστώνεις σου από χρησιμοποίησέ.', '74', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('de25344c-a557-4a97-803f-f3169b51aae6', 'Όταν διαπιστώνεις εργαζόμενοι εγώ να αποδείξεις. Επί τα γειτονιάς λιγότερο κόψεις ημέρα είχαμε.', '127', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c212209-14aa-4c30-b88d-d4b880d7d7b9', 'Στη για την άρα γεγονός πάντως εφαρμογής αποφάσισε. Δεν δουλεύει ένα κόψεις αυτήν.', '119', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c069d2e1-771a-40ff-aaa5-d3aeef6b57b4', 'Τοπικές αρέσει γραμμής βρίσκονται έτοιμος ερώτηση περισσότερες κοιτάζοντας. Ερωτήσεις διολισθήσεις εκτός σημαντικό σχεδιαστής σας του προσπαθούν. Άτομο διορθώσεις όταν πάντως να έστελνε αυτήν.', '141', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('104727b5-1646-4902-a564-ada61d1ea87d', 'Βιαστικά ατόμου ως κάτι αποδείξεις πήρε. Γνωστή την στήλες πακέτων απαραίτητο.', '53', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39f232a8-8394-4cae-851e-8616f3b32427', 'Έλεγχος μπορούσες δεν δε ίδιο μπορούσες μάθε. Αντιλήφθηκαν μετράει διακοπή αν δουλεύει έρθει. Πόρτες σωστά μερικούς.', '124', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0dda24d8-9d44-48d9-8606-ecd723f865bc', 'Εκθέσεις φακέλους πλέον κλπ δεδομένων διακόψουμε μου παίρνει. Δύο διολισθήσεις πάντα δημιουργήσεις.', '4', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02c0d987-1895-48b3-bb6b-934aead4a049', 'Τελειώσει εικόνες κάτι βουτήξουν ειδικά. Ναι σαν χειρότερα υπηρεσία μην. Θέλεις δεν σου κειμένων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('038a597f-bd45-4a2c-9da3-671ba34c0ce8', 'Ποια δείξει έχω πάρεις πολύ τι. Κώδικάς απαρατήρητο δε ειδικά εργαζόμενων θέλεις παράδειγμα. Ροή απίστευτα μάλλον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07d679ef-d5f4-4962-b4f8-3171bc470c1a', 'Συνάδελφος αποφάσισε τις προκαλείς. Πιο πάντα δούλευε ποσοστό σκεφτείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8401b5f0-6b80-4c5f-b9ac-9ca8c393d8f8', 'Της χαμηλός ήδη τρόποι ρουτίνα παράδειγμα εργαζόμενων. Να συνεντεύξεις μια προσθέσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b122017a-8ea6-410e-9f43-30f0595f402d', 'Πιο δυστυχής είχαμε έξι απαράδεκτη χρονοδιαγράμματος. Γραμμές αποκλειστικούς μας. Κι τρόπο κάνεις προκύπτουν έτσι.', '79', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('138f6985-09b4-43e2-a63b-892d66710656', 'Να υπηρεσία για κόλπα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f64fe56e-d6ca-4fe3-b809-550ecf14f80f', 'Βγήκε αποφάσισε όχι αλγόριθμου προγραμματιστές σίγουρος ημέρα. Πήρε πακέτων μπουν αθόρυβες. Γραφικά ένα σας δουλεύει μεταφραστής.', '5', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('53bac389-1373-4185-958b-e20a84ebd8d2', 'Συγκεντρωμένοι όσο μην. Επί αλγόριθμου σου πως. Μερικούς σχεδιαστής παράδειγμα έξι στις ξέχασε με.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('221420f8-32b2-4423-9be7-a6ae0807015b', 'Διάβασε κοιτάζοντας μάλλον εκδόσεις. Κρατάει πάντως τον έξι κειμένων δοκιμάσεις. Των νόμιζες χαρτιού ερωτήσεις στέλνοντάς τεκμηριώνει.', '99', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f3adc12-0d69-4cdb-bea8-391116cc65f4', 'Ένας περίπου προγραμματιστής μα γραφικά αποκλειστικούς. Με φράση έχω.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af70d1bc-b898-42e0-a5f6-4ef7b5c9f36d', 'Έτσι τελειώσει ως σημαντικός αναφορά τρόπο δυστυχώς. Ένας δοκιμάσεις μας ευκολότερο πετάξαμε εγώ ατόμου. Περιβάλλοντος δε επί ποια συνέχεια παραδώσεις τρέξει.', '97', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e442bb1e-91d2-4510-bde7-de1abaff57f7', 'Μου αποστηθίσει έστελνε εδώ σαν εφαμοργής βρίσκονται. Ρωτάει ως όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c62231b1-c8d3-4abf-add1-2ee7a21f446a', 'Ατόμου περιβάλλον μην πάντως. Κοιτάζοντας απόλαυσε αναφέρονται συνηθίζουν τεκμηριώνει πρώτοι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('46ecc25a-3ab6-4917-999b-3599b3e5cc6c', 'Χρησιμοποίησέ αφήσεις μάτσο. Εργοστασίου τελειώσει έξι δύο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8fd0ac7b-5824-479c-826b-f80bc57f64a9', 'Της άλγεβρα δίνοντας να σίγουρος συγχωνευτεί ειδικά. Βάζοντας επενδυτής μέρος και κώδικάς πολύ ποια. Εγώ ποια πλέον δε παραπάνω.', '105', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('167aa67d-5ecc-404a-86ee-2a3b71d51f61', 'Εκτός απομόνωση αθόρυβες στο απίστευτα. Παραδοτέου έχω γεύματος υψηλότερη προκύπτουν μια τρόπο.', '112', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f50e999-fcc1-40c4-9e78-fb27b8a22720', 'Εργασίας χρειάζονται εκτός γραμμής και στο πολύ εργαλείων. Εκτός οι νέο πρώτοι χρονοδιαγράμματα εικόνες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('47f54d56-e541-424e-a6b6-57a1edf7bb53', 'Αφήσεις ένας μέσης εργαζόμενοι. Μας της μιας τις μάθε κάνε εργαζόμενων. Ότι ορίστε διακοπής ιδιαίτερα περίπου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('380f7af2-0226-4a38-9e1e-40515bcfb921', 'Είχαμε πολύ το. Ένας όσο πρώτο τις να ίδιο δύο. Τρόπο κανείς αρχεία. Τρέξει τρέξει έτοιμος ποσοστό συγχωνευτεί πρώτης.', '61', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('139c480e-a8a0-4bba-a1cf-3552903bfddd', 'Της δίνοντας ροή λίγο μέρος. Τεσσαρών ανά επιδιόρθωση λαμβάνουν θα απαραίτητο θέμα. Εργαζόμενοι τους μπουν.', '1', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ca1e9dbd-db94-483e-aec9-46803fb453cc', 'Φίλος προϊόντα περιβάλλοντος. Μαγικά μέσης δεν μερικούς. Από διοικητικό γραμμές θέλεις ανακλύψεις όχι στα. Από τρόπο λαμβάνουν δύο έλεγχος μέγιστη εκτελέσει.', '72', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('09b6207f-bcd0-4f60-b8ec-bca279bbf837', 'Δύο τις και κλπ της. Την εξακολουθεί μεταφραστής θέμα υποψήφιο άρθρων μέχρι. Συγγραφής γραμμής καταλάθος θέμα οι.', '96', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('53a8e5b7-2d69-4446-9278-4e028d204fc1', 'Πάντα απαράδεκτη εργοστασίου. Εγώ έγραψες χάος ρωτάει στις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('388f5b33-1912-4916-8dd7-ba007e99b3a7', 'Για δούλευε στήλες εκτελέσεις. Υπηρεσία διαφήμιση πάντα. Πολύ ρωτήσει έλεγχος μεταγλωτίσει μεταφραστής ερωτήσεις ήδη μάτσο.', '55', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('349c1cc0-cbf9-4e8c-9f9c-53a7014a57ff', 'Διαπιστώνεις συνεχώς νέου. Αθόρυβες αν ένας τα βαθμό εργαζόμενοι. Χρησιμοποιούνταν μέρος μάτσο συγγραφείς γεύματος δύο λετπά. Γράψει λαμβάνουν που περίπου λετπά παίρνουν.', '56', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ca50a010-f7b6-4834-9cf9-79896ec2384b', 'Δυστυχής τεσσαρών σημαντικό τρόποι παίρνουν έρθει. Μπορούσες γιαυτό μια φαινόμενο αθόρυβες ιδιαίτερα ο. Αρπάζεις χαρτιού απαραίτητο στέλνοντάς χάος τον.', '47', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0aa60583-65e2-4caa-905a-5409f1c01c07', 'Σαν άρα αναφορά δημιουργείς εδώ αλγόριθμου συγχωνευτεί. Πήρε τον βασανίζουν απίστευτα πάρεις πως σαν. Ότι κειμένων φράση αρχεία πάντα.', '53', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('09d21544-3024-42cd-b7fd-5881c650698c', 'Πρώτης από αναγκάζονται γραμμές ωραίο. Και συνεχώς μερικούς νέων. Της πως κάνεις μερικούς.', '120', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7919c6e4-42e4-4ff5-8349-c44d33b58bdf', 'Το αν θα δουλεύει προσπαθήσεις δούλευε. Υποψήφιο πάντα κανόνα χαμηλός από ρουτίνα απαραίτητο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('593db81d-58a7-4951-a080-e2008a693c98', 'Το εκτός αγοράζοντας επεξεργασία συγγραφείς χρησιμοποιούνταν. Αποστηθίσει ανακλύψεις μετρήσεις εκτός ήδη νέων. Να θέλεις για εγώ μου πακέτων.', '75', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cb9728c2-c375-4b30-9d06-c12cccdf671c', 'Εγώ εργαζόμενων στις προγραμματιστής. Χαρακτηριστικών της εργαζόμενοι χρησιμοποιούνταν μια μας.', '115', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2afd56f-43b0-47bf-8231-1354edf66ad5', 'Ζητήσεις ώρα και αν διευθυντές απόλαυσε χρησιμοποιώντας. Λιγότερο που χρονοδιαγράμματος υόρκη αντιλήφθηκαν που. Μας από ωραίο τον νέα διορθώσεις δουλεύει.', '36', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6966eca5-bb59-4d86-a610-a235cc3923d1', 'Διορθώσει για όσο αθόρυβες άρα. Ερώτηση γεγονός άρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ee0c84a6-3c53-4ed9-ab34-63e89da9ee45', 'Δύο κανόνα ορίστε άλγεβρα στις στο επί μιας. Πάντα χρησιμοποιούσες τεκμηριώνει αποφάσισε σωστά μερικούς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5d534535-0d7c-4492-accf-59bf2ae0a3ab', 'Χαρακτηριστικό γραφικά κλπ κάτι κειμένων. Εκτός κάνε δημιουργήσεις διαφήμιση διαδίκτυο. Επί έτσι πρώτοι ότι διευθυντές της.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7f905e96-acdb-4ad3-b8c0-cda1c5635c12', 'Έξι δύο πιο καταλάθος συγκεντρωμένοι στο μη διάβασε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('83f90323-eee8-4143-9fb0-cf8ed508bb95', 'Γνωρίζουμε πήρε στο. Δυστυχώς τοπικές εκτός αλγόριθμου ότι ένα διαχειριστής. Ότι μιας χρονοδιαγράμματος τι τα.', '67', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('76e26f39-af41-4746-96b2-80c44be55c44', 'Εκτελέσεις ροή τι επιδιορθώσεις. Πιο νέο συγγραφείς σχεδιαστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e7a9f809-0fd4-400d-b9f7-15cc6e9f9754', 'Ειδικά αν αν σχεδιαστής. Περιμένουν εγώ περιβάλλον εργαζόμενοι δωροδοκηθούν εργαζόμενων. Σαν ωραίο παίρνουν προϊόντα χρησιμοποιούνταν εκτός που.', '91', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c23b7ada-c00f-4609-9142-e29d8b6bb65d', 'Ερωτήσεις σαν ότι ποσοστό χρησιμοποίησέ αρχεία παραδώσεις. Θα αγοράζοντας αναφορά κάνεις. Βιβλίο ποσοστό σημαντικός περισσότερες εκτελείται ότι.', '98', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('743baf19-e8ea-4c37-a39c-c6e14ddd44fc', 'Το κύκλο άρθρων νέο διευθυντές ανά μιας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4caa9180-e45e-4049-83b4-6eecbb8d94aa', 'Ένα ναι συνεχώς στραβά εκτός σίγουρος κανείς μάθε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('414dc8a3-4a2d-4d24-a5e5-68ac6f2f588a', 'Αντιλήφθηκαν πόρτες τρόποι πάντως χαμηλός εδώ αθόρυβες. Γεύματος προγραμματιστής εργαζόμενοι κάτι. Πολύ παράγοντες κάνε λαμβάνουν.', '62', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c596316b-83e2-45dc-aa5a-6227ce68f69f', 'Κάνεις διακοπής ακούσει που διάσημα για νέο.', '5', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ef5bec58-2331-462d-9709-1389435c8233', 'Σας συνέχεια πρόσληψη οι σας. Ότι βιβλίο ας στα γέλασαν έτσι εκτελέσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ba2470b-9529-420b-b622-50eee38f1540', 'Θέματα πολύ ελέγχου παίρνουν. Όταν επιχείριση υπηρεσία πιο επί και. Κειμένων υόρκη διαδίκτυο παράδειγμα το χρησιμοποίησέ μέχρι έρθει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c1990cca-13e6-4296-89e4-acd6f3f82c68', 'Ατόμου αναφέρονται μάτσο μιας παίρνει λοιπόν. Όσο εφαμοργής επί θέμα δεν. Πλέον απαρατήρητο μα θυμάμαι συγγραφείς. Απαράδεκτη μια μας να σε μιας μεταφραστής.', '89', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91778be0-49a2-4ba0-a139-5751a1c8e23b', 'Μερικούς θέματα ποσοστό αποφάσισε προσπαθήσεις εφαρμογής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c444567-1d38-4113-9965-1f9ebb58b74a', 'Χρειάζονται πιο μέχρι προκαλείς προσπαθούν έστελνε. Εκθέσεις πιο σε προγραμματιστής. Των πάντως διοικητικό συγκεντρωμένοι κάνεις θα αποδείξεις σκεφτείς.', '139', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c4a908f-dfd0-4bcf-8f56-1af4e5da4568', 'Δύο γράψει προϊόντα σίγουρος επί διακοπής εκθέσεις δύο. Δεν κι λετπά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2da03a37-bd67-4b81-a3d5-65f9fe60b662', 'Άτομο ποια ταξινομεί τις περισσότερη. Κάτι κλπ προσθέσει μιας μη δουλεύει πετάνε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('63190e1d-2a32-4e41-be0c-83f4663e7d54', 'Διορθώσεις έξι περισσότερη πεδία. Εντολές υποψήφιο μάλλον μετρήσεις. Τον τι οι μα υψηλότερη ειδικά αυτός με.', '76', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ef31a989-e654-4a70-ad86-3f094e04e157', 'Ωραίο πιο διορθώσει έτσι σκεφτείς επί φαινόμενο. Τη νιρβάνα προγραμματιστής διευθυντές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7d54ee91-e238-4bcd-abbe-11e47ab53ee7', 'Δωροδοκηθούν ότι εργαζόμενοι. Μια παραπάνω ανακλύψεις δύο. Εκτός υόρκη αρέσει υποψήφιο πως διευθυντές προσθέσει προσλάμβανες. Αναγκάζονται νόμιζες ζητήσεις προκαλείς διαπιστώνεις.', '50', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ca5580c4-4051-4d58-9771-018d9fbbd6d1', 'Βάζοντας σωστά δύο χρησιμοποίησέ περιβάλλοντος μάτσο εξαρτάται. Τις να ποια διορθώσεις θα νέο ένας κανένας. Ένας μα προσπαθήσεις μάθε παράδειγμα περιεχόμενα μα.', '4', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ea4fd245-841d-4d06-b700-3699b2b9fe18', 'Λαμβάνουν και φίλος προκύπτουν στη διοικητικό τον ακούσει. Ανά έξι κάτι σταματάς ως. Κανένας γραμμή χαμηλός ανώδυνη το. Φαινόμενο ρουτίνα εκτός νέο εφαμοργής.', '126', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7108a4d5-5f02-47d8-8e06-a6d16ce7f939', 'Χαρτιού χρησιμοποιούνταν σίγουρος μετράει. Των πιο πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('55df11e1-71ed-4aae-9cfb-3a4686bb76f8', 'Ήδη σίγουρος εκείνου όχι. Ανά εφαρμογή πλέον εφαρμογής μεταγλωτίσει εργαλείων μου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9aee31e0-b497-40d9-b947-36b7dba8a707', 'Και μια για. Μέγιστη χρονοδιαγράμματα και.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bbcc8a2d-9ee1-424a-8cf6-17b20fd40187', 'Βασανίζουν γραμμές μας πρώτο άρα. Μπορούσες κάτι σχεδιαστής ακούσει ότι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d9f284b9-f9b7-4d37-ba0a-47e4f19f1961', 'Τον συνηθίζουν περιεχόμενα τον μια συγκεντρωμένοι κάτι. Επιστρέφουν δούλευε να εκδόσεις κειμένων διαδίκτυο καταλάθος. Σε προγραμματιστές παραδώσεις νιρβάνα.', '34', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4d9929f3-20e2-4237-bfa8-3e72675e9a78', 'Ευκολότερο που έχω ένα εκτός πόρτες εργαλείων. Αγοράζοντας ζητήσεις μα εκθέσεις σωστά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('58db790b-5414-4b47-b2bc-abe3228a403d', 'Γιαυτό μέγιστη μη πήρε ανά χαμηλός πιο προσθέσει. Πετάξαμε ιδιαίτερα προβληματική σε μέχρι σημαντικός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d0a4b03b-6440-4404-9f85-fa9dba7a5da0', 'Χρησιμοποιούσες θα χρειάζονται ευκολότερο υπηρεσία. Διαχειριστής εργαλείων καλύτερο κώδικάς εντολές συνηθίζουν παράδειγμα και.', '104', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('853258c3-2968-418a-b9be-b1b276b1fd4c', 'Που τύπους κάτι εξαρτάται διασφαλίζεται μην. Των λαμβάνουν πρώτο. Κρατήσουν τρόποι λιγότερο γραμμές εκδόσεις.', '83', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('37c3132a-2c0b-4827-95c6-13e1db927fce', 'Εσωτερικών κειμένων πάντως πλέον εκτελέσεις όχι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('26603486-deec-4a65-af26-fbd9e8b31477', 'Χρονοδιαγράμματα μπορούσες συνέχεια ένας.', '144', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e4342d5d-f80f-4b76-8df3-6395becf4c33', 'Δίνοντας ροή άρθρων βασανίζουν σου έχω. Εκτός στα βασανίζουν των μάλλον διαφήμιση. Γεγονός μάθε περιβάλλοντος μαγικά δεν.', '41', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9779770e-6bc8-4b1d-88a8-9e8dd5b11e30', 'Απίστευτα εταιρείες όχι ναι ένας τη ήδη εργασίας. Αναφορά που πακέτων μέχρι δημιουργείς συγγραφείς θέματα. Χρησιμοποίησέ σημεία εργαζόμενων σωστά δημιουργήσεις.', '74', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('15f85ece-af00-415b-9145-81eb422323b3', 'Απαραίτητο εφαρμογής επεξεργασία πιο εκτελέσεις μα. Κάτι μου προγραμματιστές πηγαίου. Εκτελέσεις αποθηκευτικού εγώ.', '118', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('12b9e156-a9ea-456c-a555-b95cd1ee93a0', 'Ρωτάει ο ωραίο να δείξει εφαρμογής. Του τρόπο με μας. Μη κάτι ανακλύψεις βάζοντας συγχρόνως επιδιόρθωση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5b55e61c-c976-4c2e-9293-5cd23b6e4bc6', 'Πάντως κανένας εκτελέσει. Μαγικά εργαζόμενοι στις έχω γιαυτό επί τρέξει ναι. Έστελνε πετάνε χαρακτηριστικών άρα πετάξαμε εκτός εκτελέσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94065aa5-f7a8-40a9-808e-9b4dc7156423', 'Περιβάλλοντος δουλεύει δε πως αν. Βάζοντας βγήκε τύπου την τα πακέτων. Ίδιο κειμένων βουτήξουν μα νιρβάνα διακόψουμε ορίστε τοπικές.', '19', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a23f404-aeb0-4024-a20b-30e7ad9e0687', 'Διασφαλίζεται εταιρείες δημιουργείς σαν θυμάμαι συνεντεύξεις. Νέα εγώ μη υπηρεσία κάτι. Περιεχόμενα ώρα έξι ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c94c0c75-3237-4c87-98b2-0f65e5f83f32', 'Έξι ατόμου τη τέλειοι φίλος. Στη δε ελέγχου περιβάλλοντος πάρα συνεχώς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c402ea72-6486-4521-b047-6513100dd584', 'Επιστρέφουν ας με συνεχώς. Πάρεις πάρα μαγικά άπειρα συγχωνευτεί. Έξι θέλεις περιβάλλον πως κώδικάς. Την αρέσει δεν πες.', '139', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7c19d0c0-5bcd-4fc5-94c3-5aaa08d20ee6', 'Διαφήμιση συγγραφείς την γράψει περισσότερες. Μέσης δυστυχώς τη δούλευε φακέλους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4489cafb-4c3f-4ba5-8b65-3aad029cc47e', 'Όσο μάτσο σπίτι χαρακτηριστικών εργαλείων εκτός. Τύπου όταν από ορίστε ανώδυνη νέα έξι.', '102', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7d589dad-91ae-49b9-b20b-3c70e42c6b17', 'Επιστρέφουν πετάξαμε επί άπειρα έξι όσο έγραψες αναγκάζονται. Βουτήξουν δείξει πιο σας. Συγχρόνως από για λετπά ένας πρόσληψη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('331acd5c-ebd0-4a73-84fb-101037361eab', 'Ότι μαγικά δημιουργήσεις που προσπαθούν. Προσεκτικά τη εκτός εκτός στήλες ακούσει.', '40', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2198031a-8596-43ae-95ff-2a3e41304406', 'Χρησιμοποίησέ αποδείξεις γνωρίζουμε πήρε διαδίκτυο μέχρι. Αθόρυβες τη αποθηκευτικού που καλύτερο μου άρθρων. Ίδιο μιας έτσι δημιουργια και χάος εργάστηκε. Ροή δεν αναγκάζονται.', '22', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('baa13686-ae3f-46e9-9d05-9c0ca05b74d4', 'Εξοργιστικά διορθώσει αρέσει οι συγγραφής κι. Κάνε όταν χρειάζονται ωραίο έστειλε διάσημα όσο.', '88', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b37fe3e4-ea0f-433e-90c8-b839ebd39b2e', 'Προκαλείς άρθρων χρησιμοποιούνταν στις γιαυτό κρατάει μα δεν. Τύπους και ανά μας.', '61', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94b4517f-adf4-45e7-850b-b03a35fc2e54', 'Σαν σχεδιαστής ότι έστειλε. Μια γράψει εγώ κάτι στη μεταγλωτίσει θα πως. Έχω βουτήξουν παραγωγικής τεκμηριώνει ποια έστελνε επί.', '133', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5d95499f-3625-4cf1-851f-51b7872b1315', 'Γειτονιάς ίδιο ξέχασε συγγραφής είχαμε δε θυμάμαι. Μα άρα το εργασίας πήρε μέσης.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f8076da-dbf0-4079-ba5d-9cbd2ca1d30d', 'Εγώ κανένας φακέλους αυτήν. Στέλνοντάς εργαζόμενοι εκθέσεις τύπους αποδείξεις ήδη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('191242e3-84f6-4db1-b8e6-0728c02fdd15', 'Παίξουν εκτελέσει κάνεις εκτελέσεις. Στις πετούν περισσότερη το βαθμό προβληματική δε. Δεν σημαντικό δε λέει τι ξέχασε άρα.', '105', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('34eae0a8-98eb-4c53-97cf-62c367d8887b', 'Αναγκάζονται εκτός γειτονιάς λαμβάνουν σχεδιαστής προκύπτουν. Εδώ γραμμές διαδίκτυο όταν. Πλέον καταλάθος διαφήμιση εγώ. Ένα μην κύκλο ορίστε αθόρυβες πως.', '134', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('16f4d113-2c84-4e58-a231-a95157ad7692', 'Βιβλίο γιαυτό τους βιαστικά. Την εργαλείων ήδη συνεχώς πήρε εικόνες ταξινομεί. Επί χαμηλός που.', '55', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('60ee7f62-d141-4060-8e7f-0b49589fcd77', 'Πρώτης νιρβάνα έχω περισσότερη. Του αρπάζεις χρονοδιαγράμματα άτομο διορθώσεις συνηθίζουν νέων.', '34', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('99e978b5-0e93-4bce-af14-626823ea216f', 'Προσπαθούν τύπου λιγότερο φαινόμενο. Φράση μέχρι έτοιμος. Απαρατήρητο ημέρα τέλειοι μεταγλωτίσει τη αν αρέσει εγώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c53e6c37-5b7d-4c24-a20e-69a977d0e621', 'Παράδειγμα ας παραδώσεις μου. Χαρακτηριστικών χρειάζονται εδώ γειτονιάς δημιουργείς. Γνωστή διαπιστώνεις επενδυτής εκτός μην απαραίτητο αποστηθίσει.', '77', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('081cb307-1be6-42be-82b8-9a1f5313bf40', 'Εκθέσεις σημαντικό εγώ πολύ εφαμοργής. Τέλειοι πάντως δουλεύει χρονοδιαγράμματος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('207fef33-73f4-4e3f-9086-dacfcf12fdf7', 'Πάρεις εντολές ο κανόνα. Ωραίο γνωρίζουμε αφήσεις πιο άρα στραβά μέχρι. Τύπους θέμα εργαλείων προγραμματιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af38766f-d247-4de2-b5c4-3f699cfe9085', 'Αναφορά ανώδυνη έστελνε ίδιο. Για επιδιορθώσεις τύπους σημαντικό. Γραμμής μάτσο απαράδεκτη εγώ. Δυστυχής παραδώσεις μεταγλωτιστής ποια.', '146', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3ed48359-2a08-4048-99df-052563c26344', 'Έτοιμος ανά μέχρι οι συγγραφής αποδείξεις. Νέα σαν μηχανής ο σίγουρος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1075fca5-cfa2-4a27-89e6-3ce343188cb6', 'Τη τον μην ελέγχου μην. Παραπάνω ποια κι σου. Άρα εντολές πολύ. Κάτι φακέλους όχι στα δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('01a46e38-a89f-4fe2-8be4-07fff56086c9', 'Επιστρέφουν τους δεδομένων έγραψες περιεχόμενα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6e6bd0b7-a1ef-4b50-87de-141f2b0506d5', 'Διαφήμιση τον παίρνουν. Αθόρυβες μη στέλνοντάς άπειρα εκτελείται πάντα σημεία πεδία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6981de47-5eec-48f5-a4cb-c83c1da969a2', 'Κι εφαμοργής εκτελείται. Πλέον πάρα δε γέλασαν παράδειγμα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('20c3159b-ca74-4e86-8195-16ea03e39ebb', 'Προσπαθούν πάντως παίρνουν εγώ. Την προσπαθήσεις ξέχασε αρπάζεις εκτελέσει ρωτήσει σημαντικός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8940654-e9cb-4848-8ddd-8d6ba04a76d1', 'Αρχεία εκείνου μην ρωτάει δύο κλπ χειρότερα. Συγχωνευτεί γραφικά αν προσλάμβανες μας με για χρόνου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b27cbdf6-e7b1-43d8-9a34-02f858522756', 'Εγώ σωστά διευθυντές ανά λέει χρονοδιαγράμματα συνέχεια. Πλέον σκεφτείς ύψος προβληματική πρώτο έξι. Σημεία εδώ λέει διοικητικό βιαστικά σκεφτείς.', '98', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('81ff5b78-31f3-46dc-95cc-7c1f0d890159', 'Περιεχόμενα περισσότερη άρα μέσης εδώ. Ήδη δυστυχώς κρατήσουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fea8d56b-0ba1-4b19-889b-088e16ef52a2', 'Ειδικά ποσοστό χαμηλός έτσι γειτονιάς μεταφραστής εξοργιστικά. Χαρακτηριστικών γνωρίζουμε μπουν νόμιζες σας. Επί προσεκτικά απαρατήρητο διολισθήσεις.', '65', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('242a39fd-cad7-49bf-be89-459a87275e9b', 'Τρόποι πήρε τέλειοι έξι. Που κόψεις απαράδεκτη εκτός προκύπτουν πετάνε ένας. Πάντα νέο μέρος κανένας οι πολύ του. Να δίνοντας διαφήμιση που προγραμματιστές.', '43', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('78ed8020-bacb-4a2e-b532-f132017b435d', 'Νέων τρόποι μια βγήκε. Φράση μια δίνοντας ως. Λετπά μαγικά βιβλίο που αποστηθίσει ποια των.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c3e2aa45-4c24-43f5-b595-13e6fd7e968d', 'Του απλό εδώ έξι συνεχώς νέο αποδείξεις. Έχω διορθώσει τι όχι πρόσληψη. Έξι της στο εδώ συνεχώς επί χαρακτηριστικών ένα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c03be266-48e6-4e51-b334-1f16b43a867e', 'Ίδιο επί αρέσει προγραμματιστές διορθώσεις εργαζόμενοι που. Τρέξει σας σχεδιαστής εκτελέσει μάτσο μην.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aac034f0-c649-4e5d-8ccc-21015ef4054c', 'Γέλασαν έστειλε έχω διακοπή με διακοπής προσθέσει διοικητικό. Σε οι χρονοδιαγράμματα κρατάει είχαμε ο διευθυντές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24bb075e-aa83-4d43-81ed-1fa5799073e6', 'Τα απαρατήρητο άρθρων στις απαραίτητο ερώτηση. Πάντα άρθρων έτσι ποσοστό επιχείριση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c7cea3af-8aa3-48ea-a4f2-4e712c3fb9a4', 'Προσλάμβανες νόμιζες χρησιμοποιούνταν τη κύκλο χρησιμοποιούνταν. Σημεία απομόνωση δε πάρα κανόνα ανώδυνη γράψει γειτονιάς. Σας γραμμή νέα μέχρι.', '48', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('53872d77-b412-45df-a2e8-c794cef3a4fa', 'Υπηρεσία ορίστε ίδιο εκτελέσει την. Θέματα ζητήσεις συνεχώς ιδιαίτερα νέων. Πλέον βγήκε δυστυχής άρα πάντα κάνε.', '141', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5b83adcb-8e9e-4fdf-8a76-23ab55511ab4', 'Θα κώδικα απαραίτητο μέχρι ρουτίνα ποια. Μέσης ανεπιθύμητη παίξουν έτσι πως κανείς. Διολισθήσεις προσπαθήσεις μας διαχειριστής διοικητικό λίγο απλό.', '30', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8266feb1-9b8c-43d6-b721-9e964fcddcd9', 'Ερώτηση μας πεδία. Κάνεις άπειρα εσωτερικών μετράει μέσης εδώ απαρατήρητο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a6381495-5c7e-46ec-9cf0-9bc57a5bd00e', 'Πιο μηχανής μαγικά περισσότερες. Έχω πιο χρονοδιαγράμματος χρονοδιαγράμματα παίξουν επιστρέφουν. Εκτελέσεις κάνε σαν οι.', '101', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('981e52f0-1856-4640-a846-902be9fc8114', 'Του λες αρχεία δύο εργασίας. Εκθέσεις δεν προγραμματιστές το αποφάσισε απαράδεκτη. Υπηρεσία διολισθήσεις καλύτερο ας. Ναι προϊόντα σε τη αντιλήφθηκαν.', '149', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f886c6da-c301-4537-9c66-456da41e6647', 'Πες τα ναι αντιλήφθηκαν. Ήδη κοιτάζοντας άρα συνηθίζουν για αποστηθίσει πήρε. Μα για πάντως εντολές έξι.', '91', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c639cad4-7368-42f4-967a-ed444c6b71a2', 'Το οι σίγουρος στραβά και μη έτσι. Που ποια με τεκμηριώνει στήλες άρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eff18cb0-1fa1-4483-b1ad-51a303d3015f', 'Διοικητικό μετρήσεις προκύπτουν. Ως ας εντολές ημέρα χρονοδιαγράμματος μετρήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('46c88aaa-2bac-417d-8655-8c539f70d081', 'Εργαλείων τον και. Θέμα από μεταγλωτίσει οι γέλασαν. Επιδιόρθωση πρόσληψη βρίσκονται τρέξει φράση ανεπιθύμητη νιρβάνα. Διορθώσεις κειμένων διαχειριστής πιο νέων ένας σε διασφαλίζεται.', '16', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d73abd64-070f-4c92-9e5d-3aa63047e5b4', 'Συνεντεύξεις έρθει ας βάζοντας εξαρτάται μάτσο. Εδώ έστελνε έτσι περίπου όσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('602e5ec2-e3b3-449f-ae2c-c3d8a10dac8b', 'Να σημαντικό γραμμή επί παραδώσεις διευθυντές τοπικές άρα. Δε κόλπα τις εσωτερικών έστειλε. Πάρα δείξει βιβλίο χρησιμοποιώντας γεγονός περισσότερες σημαντικός περιεχόμενα.', '127', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1fe28685-c329-46aa-92da-25f7d1b458cc', 'Προκαλείς ύψος απαραίτητο μάθε μάτσο. Αντιλήφθηκαν από μετράει άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('38d5d413-66af-4407-8b5a-91203d8995a1', 'Προγραμματιστής τα σημαντικός μιας όχι λετπά. Προσπαθούν ανεπιθύμητη πάντα όταν εσωτερικών ας αναγκάζονται.', '147', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('53d69c24-d1e0-4f16-9523-5e59ba9c3a42', 'Ειδικά πακέτων ο στο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24058362-9d26-4490-b7b1-a84bd90c8d36', 'Λέει κόψεις γραμμές. Άπειρα σου υόρκη δημιουργείς καλύτερο.', '119', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('76d5fc7d-a241-42a5-9d29-46d9754f5189', 'Μη μέρος εφαρμογή όσο. Γραμμής νόμιζες γραφικά εγώ μέχρι. Μπορούσες απαρατήρητο σου ποια χάος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('82b98374-cb5d-47e3-af8f-05ad8dc0c27e', 'Πάντως πρώτο προγραμματιστές εκτελέσει διορθώσεις. Μπουν πλέον μη τελειώσει ας. Νέο σχεδιαστής αυτός μέσης γέλασαν γέλασαν.', '110', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('812e86a8-707b-4ef9-9512-c6131364f3c3', 'Όχι χάος κώδικα προγραμματιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0c74a2f5-ab23-4514-b2d9-f81e973a9f4d', 'Έξι κι εργασίας και κάτι μάλλον το. Περιεχόμενα τον εγώ βιαστικά. Νέα παραγωγικής ευκολότερο πλέον απομόνωση πάντα.', '46', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ea91687d-5392-4c0c-9f41-d17a2c10655d', 'Όχι μιας βγήκε διαχειριστής. Από εφαμοργής χρειάζονται τελειώσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('26e57137-47ea-4459-bbc4-cf88084cae7f', 'Διαφήμιση βρίσκονται υπηρεσία επί μπουν. Θέματα απόλαυσε αποφάσισε οι και. Νέο μέσης ημέρα έρθει πρώτοι δύο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('37a4e34d-1163-4c4c-985d-bcd55639a868', 'Διασφαλίζεται εργασίας πάντα κόψεις προσπαθήσεις προγραμματιστές ζητήσεις. Συγχρόνως διάβασε επιστρέφουν θυμάμαι στο πιο. Πλέον έτσι βιβλίο μια.', '38', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('854c3295-0b0f-46a1-9703-b9c93f86893d', 'Χειρότερα δεδομένων έτοιμος σπίτι. Εργοστασίου έλεγχος αντιλήφθηκαν τρόποι μου διακοπής όταν. Απαράδεκτη επεξεργασία απλό για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e63a4497-9dd8-498b-bab5-ad197b4313e9', 'Εργαζόμενων δυστυχώς παίξουν. Πιο παραπάνω ρουτίνα θα ένας θέματα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('716322db-9500-46b0-824e-2d7b94be7351', 'Τέλειοι μέχρι στο αφήσεις έχω προγραμματιστής. Λες περίπου ανταγωνιστής ο πολύ χρησιμοποιούνταν. Μια λες ερωτήσεις λες διασφαλίζεται.', '66', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af830f51-c81f-407f-ab98-d08689b7ace5', 'Άρθρων εκτός στο στη επί αλγόριθμου ορίστε. Μη των ακούσει λετπά γνωρίζουμε. Πολύ ακούσει έτοιμος άπειρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('75aa02a9-bbf2-4bb9-a22e-8e4f933acc72', 'Βγήκε εγώ ταξινομεί αφήσεις από προϊόντα. Πετάνε παίρνει περισσότερη πακέτων κώδικάς αν μαγικά. Κανένας επιχείριση θέματα από εκτός.', '13', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('98fcd71d-b510-4d75-b1b1-e9a10e01ea9d', 'Συγκεντρωμένοι αρπάζεις συνεντεύξεις. Έξι στη εφαρμογής νόμιζες. Διάβασε απαρατήρητο ύψος ευκολότερο. Ειδικά σου τους ότι εξοργιστικά γειτονιάς.', '87', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('46cc1e3d-3f7b-411d-bae5-86f1f085d638', 'Πιο αποθηκευτικού πως ημέρα έτοιμος νέων τον. Μα εκτός στα που.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ae3db850-7584-447b-a76e-e687adbe99ce', 'Τη διαφήμιση ρωτάει κάτι. Εκτελείται χρονοδιαγράμματος έστελνε γραμμής γειτονιάς άρα συνεντεύξεις. Συγγραφείς μην απίστευτα ελέγχου προκαλείς. Βουτήξουν ήδη εκείνου επιδιόρθωση ανακλύψεις άρα.', '109', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3bd0d4a8-1ddf-4acf-8918-2b14b2ee99d2', 'Αποδείξεις σκεφτείς τους σημαντικός του μου μέσης. Αν ήδη μετράει ορίστε ύψος υπηρεσία πρώτης ελέγχου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6279caa-6505-4819-94fc-16e715b6be27', 'Ύψος μπουν ανά. Ένα χαρτιού παραδοτέου. Υψηλότερη απίστευτα κώδικα λέει έστελνε χαρακτηριστικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1ac56325-9c8c-4356-b86f-4696e215104f', 'Πηγαίου της εφαμοργής πεδία. Διορθώσει αναφέρονται τις ορίστε οι εκτελέσει τελειώσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e31ecdb2-8b69-4bae-a3b9-6fabc88f6f64', 'Στις στις έρθει εργασίας δεν κειμένων. Πάντα με ήδη αφήσεις προκύπτουν προσπαθούν αποκλειστικούς. Θα πολύ τύπου μεταγλωτίσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2eb5a78f-8c28-4d7d-a11c-6349d475792e', 'Έχω προσλάμβανες διαφήμιση διορθώσει ρουτίνα τρόπο μετράει. Κάνεις υόρκη ξέχασε συνέχεια. Επεξεργασία ίδιο από έξι διαπιστώνεις του παράγοντες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bf81c3f6-9adc-4248-9d81-0f9be15109d2', 'Λοιπόν κανόνα θέλεις βιαστικά συγγραφής να. Μαγικά κόλπα κύκλο διαφήμιση.', '50', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('50fbc5e6-6ed6-4693-879c-36bae8e9d7a0', 'Συνάδελφος δωροδοκηθούν τεκμηριώνει ανακλύψεις. Προκύπτουν διοικητικό έξι διαχειριστής σου ποια εκθέσεις περιμένουν. Το επιχείριση ένας άρα γεγονός εσωτερικών.', '48', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bc187979-0dea-403b-a00d-0bbe5efe7593', 'Διαχειριστής μέρος γραφικά. Κρατήσουν μη λοιπόν χαρακτηριστικό επεξεργασία ρωτάει. Στέλνοντάς λες μέγιστη μα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c8f686a-cc82-4a42-93c5-2a5dd72689f0', 'Πιο σαν λες την κανείς ιδιαίτερα χαρακτηριστικών. Αλγόριθμου δείξει διαπιστώνεις χαρτιού. Παίρνει περίπου τη σκεφτείς τι αποδείξεις άρα.', '135', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d794a303-9157-4d54-aeb4-1fcee83a0fe3', 'Τις συγχωνευτεί μεταγλωτιστής. Σπίτι πάρα κόψεις ποια εικόνες της.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7dad961a-2b07-4e07-8ccb-fa3a1ccff9b6', 'Εργοστασίου δε τη εκτός. Γνωστή εσωτερικών τρόποι πετάνε προσπαθήσεις χρονοδιαγράμματα. Χρησιμοποιούνταν τρόποι τα.', '99', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6ab33904-fe84-485f-8ea7-5c6925a56af9', 'Γνωστή δε κώδικάς διορθώσει προσλάμβανες πολύ σου. Γεύματος αρχεία άτομο φράση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('20031cc3-da74-4f64-afd6-5f7f89239a12', 'Κόλπα φακέλους αποστηθίσει ρωτήσει επιχείριση. Ημέρα δεν συνεντεύξεις συνέχεια ανά μέσης όσο τι.', '23', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('93bfbd88-0163-4353-9972-c8058730f9d1', 'Τη ροή χρησιμοποιούσες έξι ποσοστό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6994d403-7668-4485-ab79-f9047e8ec867', 'Εφαρμογής τέλειοι χρόνου συνεχώς εξαρτάται τις. Μέχρι ωραίο τι αποκλειστικούς ήδη. Παραδοτέου που όχι κώδικα όσο έχω άρθρων εκτελέσει.', '69', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f1925d00-bd74-4b5c-9a2a-62e311801f3f', 'Συγγραφής μη λες ποσοστό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('347f8f10-bb98-4cb9-b4fb-88b483e1d07f', 'Απαραίτητο περιβάλλοντος στη συνέχεια δίνοντας δύο προσπαθούν. Αποδείξεις ποσοστό μου απομόνωση δυστυχής διαφήμιση. Άρα τεσσαρών πάντα διορθώσεις.', '119', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('12ce85e7-4044-4e89-aa21-9807384347f1', 'Πιο αποφάσισε κρατάει γνωστή μπορούσες άρα λέει. Πιο ίδιο συνεχώς εδώ. Μάτσο κάνε συνάδελφος πες τα διαφήμιση κοιτάζοντας φίλος. Ρουτίνα συνέχεια μέγιστη διαδίκτυο.', '22', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d26a4f19-69a4-4c6e-8967-c9f007dbfd81', 'Μια γιαυτό τις ανά κειμένων. Λετπά πες από γνωστή ναι σπίτι πάντα. Έτοιμος κανείς εντολές απόλαυσε πήρε μετράει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6d65f939-8899-4d60-86ab-d43513ad62a4', 'Μας θα ότι κώδικα άρθρων αντιλήφθηκαν πετάνε την. Εφαρμογής πάντως δύο άρθρων αναφέρονται περιεχόμενα. Καταλάθος ένα τους ήδη δυστυχώς παραδώσεις εκτελείται.', '130', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('967cbddc-dca8-4532-af44-d02f47cd16f7', 'Κανόνα παραδώσεις διαφήμιση έχω διάσημα στραβά. Νέων ποια να εκθέσεις της.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('de484f61-5313-454d-9a20-182731f4afcb', 'Τύπους πάντα γιαυτό να αρχεία φακέλους εργοστασίου. Δωροδοκηθούν δημιουργια διακόψουμε από. Μην θυμάμαι εσωτερικών κώδικα του.', '31', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f3460e82-83d4-4f5e-81b3-7c85c5907c83', 'Χρειάζονται για ειδικά σου ως νέα φίλος. Υόρκη επί ακούσει περίπου χρειάζονται εξοργιστικά. Σου σου βιαστικά ερώτηση ποια αποστηθίσει.', '145', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('81c505a0-d00c-4a54-832d-58e97d27469c', 'Εδώ έγραψες ένας εκδόσεις. Εργάστηκε μου δημιουργήσεις συγγραφής απομόνωση πόρτες. Θέλεις μεταφραστής συγγραφείς χρονοδιαγράμματα λετπά ταξινομεί απόλαυσε.', '92', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f5ffaf79-134a-4b45-929b-f9f5d7d4db1e', 'Σαν προγραμματιστές και εδώ. Πάντα τελειώσει ένας ωραίο δύο άτομο. Οι σας πιο νέο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c3425995-77a4-4f26-b2cc-372953f4759d', 'Αναγκάζονται εγώ απλό τοπικές σου μα ορίστε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('298912a3-43ba-4256-8ee6-d6458f705d57', 'Τέλειοι έτοιμος ήδη τα. Συγχρόνως ξέχασε συγκεντρωμένοι συνέχεια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a98c31c-e105-4594-9937-41d4b1d98489', 'Ύψος την θέλεις στα συνεχώς έτσι αποθηκευτικού.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e8af3f17-290c-4593-8200-ed0d945f0a7d', 'Εφαρμογή τύπους κόλπα του.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4442f6b1-729f-4fb8-80d7-10ce776ff416', 'Λέει σωστά εργοστασίου ρουτίνα βιβλίο πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('48f4ce71-1d8b-4c36-a36c-5c989b572c55', 'Των ότι ως επί το ήδη σας. Αλγόριθμου νέου εγώ εδώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04f53123-dab3-4c5e-b6a2-57469d466ab3', 'Πλέον περιβάλλοντος έχω από δε περίπου αρέσει. Προσεκτικά στη επεξεργασία άπειρα πάρεις έστελνε λαμβάνουν οι. Τη εφαρμογής του απομόνωση μου παραγωγικής.', '29', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('049cec03-c2a9-49f2-954a-18262e8c1efb', 'Πετάξαμε θα κι βάζοντας. Χρειάζονται τη θα γραμμής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7c283a54-1df7-4dee-aba6-33f305602f6c', 'Πιο αν παραπάνω φράση. Αποκλειστικούς κειμένων οι έστελνε. Προβληματική κόψεις στα δημιουργείς ανταγωνιστής επιστρέφουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a3d96542-9aba-49b1-95b1-0290e4c7ccf3', 'Δημιουργήσεις δημιουργια δημιουργια μάτσο αντιλήφθηκαν τεκμηριώνει. Γνωστή την αποδείξεις δύο.', '113', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e936a08d-98d6-444e-98f7-792c622517ad', 'Ποια σε ταξινομεί δεν. Δε επί μερικούς χειρότερα πάρα καταλάθος της.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cd6acd35-8970-48f0-9438-c924859dbf15', 'Έστειλε μάλλον μη επιδιόρθωση αν για πρώτο. Αθόρυβες πάντα βγήκε έχω πολύ στα μετρήσεις παραγωγικής. Νέα πάντως πάντως ένα κανείς εφαρμογή.', '8', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d3aaf732-c10f-4e05-96ce-1c6265f69b5e', 'Με τρόπο γραμμή στα έστελνε. Μέχρι υψηλότερη χρονοδιαγράμματος αρέσει. Μιας διορθώσει για φράση.', '91', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('92257bdf-7c4e-4aee-843b-17d8475afe34', 'Παραπάνω αλγόριθμου στα εφαμοργής. Τύπους κανένας μεταγλωτίσει γνωστή απόλαυσε. Εγώ ώρα βρίσκονται μια τεσσαρών εκτελέσει.', '33', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('08c1195f-aa5a-4fab-8db9-6c96c1754767', 'Συνέχεια τα σημαντικό κανείς. Νέων όχι ότι δύο σαν.', '40', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ac9d38d1-61e2-4ce7-8fb4-eede08dd6a03', 'Ήδη πρώτοι χάος χειρότερα μεταφραστής ως. Με και κόλπα απόλαυσε τη κι. Έχω πάντως πιο άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2567c9b7-e63b-4972-8936-bd9358cd9e0f', 'Εδώ από είχαμε κι εξοργιστικά. Σπίτι ένας περίπου εταιρείες σε συνεντεύξεις προσπαθήσεις. Χρησιμοποιούσες συγχρόνως έχω προγραμματιστής.', '143', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fbe400c0-1140-4752-bcc8-fefef58bbec1', 'Παραδοτέου γειτονιάς θυμάμαι από είχαμε φακέλους χρόνου. Διακοπή πάντα άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9995963a-7ca4-40e6-a166-e161cf233e4f', 'Διολισθήσεις γραμμή διακοπή εκτελέσεις. Εγώ πάρα τεκμηριώνει ορίστε γεγονός εξακολουθεί ορίστε. Εγώ εξακολουθεί λέει αρέσει προσπαθούν.', '142', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cac94330-0a2b-439d-a79c-c16b65b74515', 'Έτσι απαράδεκτη διακόψουμε περιβάλλον και. Προϊόντα παραγωγικής υόρκη ανταγωνιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1b1cfb3-92b3-41bb-9b02-155e90522535', 'Πιο κόλπα μεταγλωτιστής καλύτερο πάντως έχω μέχρι ήδη. Της στη ας βάζοντας συνηθίζουν καταλάθος μην μέχρι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db959566-ec8b-481a-9ebb-db72bca313b4', 'Από κάνε γραφικά ανά και δεν. Νέων ότι εδώ δημιουργια διασφαλίζεται όσο μα. Άρθρων ποια εκτελέσει ταξινομεί περίπου εξοργιστικά πρόσληψη.', '85', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('436bb7fe-d5c0-4e03-b0a8-01a69e5451d8', 'Όταν διολισθήσεις μηχανής βάζοντας δούλευε μάλλον ανεπιθύμητη. Φαινόμενο προσπαθούν πακέτων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d1b44823-342b-4a0a-a936-4875d9eb9dbb', 'Τη δεν έξι ύψος κανένας κάτι γειτονιάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d9f66d6c-b91a-42ff-bc59-ab7a781f27bb', 'Διαφήμιση συγγραφής πρώτης άρα βαθμό. Ρωτάει διευθυντές χαρακτηριστικό εργαζόμενων ήδη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b3f19494-76ad-4a89-a30e-4811f75706c9', 'Διακόψουμε χρησιμοποιούσες ως κρατάει εξοργιστικά εντολές χώρου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('928ff8cc-6bdf-4041-94ea-df68d1700f72', 'Έστειλε δε νόμιζες ίδιο σκεφτείς. Για τρόποι αρχεία άτομο συγχρόνως προγραμματιστής πολύ περιμένουν. Διακοπής διολισθήσεις που ρωτήσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('298a931c-5e90-42ae-b2a9-c4b1665fde88', 'Όταν έτσι πήρε δε τη εργαζόμενων ίδιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e9b1f244-32ea-4f00-af1d-3316f408bf4c', 'Ατόμου θέλεις ποσοστό χρονοδιαγράμματος αρέσει. Μην καταλάθος τη επιχείριση πως εφαμοργής. Δημιουργείς στήλες ποια χρονοδιαγράμματα αποθηκευτικού.', '121', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f01df3d8-04e6-47d5-8e5d-91644281a719', 'Λέει δωροδοκηθούν μετράει τις παίρνουν εταιρείες ένα. Μας μέχρι συγγραφής κώδικάς έχω αποφάσισε.', '86', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('76609284-a695-4179-bff6-caefcd562ab3', 'Εργοστασίου και εκτός σε έτσι. Δε καλύτερο ρωτήσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('88de29c1-4881-40bc-b7bb-614930340531', 'Δεν επί επιχείριση χρησιμοποιώντας ερωτήσεις αν θέμα. Νέο ανακλύψεις κάτι ένα πιο ήδη. Καταλάθος δίνοντας δωροδοκηθούν δεν αν προϊόντα μαγικά εκτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d4e999ed-88aa-46ee-8183-8b6203a37f59', 'Και προσοχή διολισθήσεις ήδη παραδοτέου. Σκεφτείς δούλευε απαραίτητο σε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d6bc2069-ba5b-4cfa-93e7-dacd69b37758', 'Θέλεις ας κανένας δεν μάλλον κοιτάζοντας θέλεις. Περιβάλλον συγγραφής προσθέσει μετράει αν στραβά. Έγραψες αγοράζοντας θα ένα αλγόριθμου κοιτάζοντας δείξει. Όχι τελειώσει αποφάσισε στραβά στη τη.', '103', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6ad17183-399e-4df8-8896-42ec7a4f4c16', 'Μερικούς άτομο εκδόσεις όσο εικόνες περιβάλλον χρόνου. Προσοχή χαρακτηριστικό γραφικά σε. Πολύ ξέχασε επί συνέχεια έξι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('30d6c7f8-cd5c-4b95-b624-559aed0dfeaf', 'Προσλάμβανες απαράδεκτη στις πες. Εκτός ότι να που εδώ κάνε σε. Και του εκτός απαραίτητο χειρότερα δυστυχώς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ecefcb49-5831-4fde-b8a8-820f810a79b4', 'Μεταγλωτίσει θα στραβά μαγικά ευκολότερο. Δημιουργια αποστηθίσει μερικούς συνεντεύξεις.', '118', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('21807ae1-8c5b-4e25-9d16-241357940e23', 'Θα ρωτήσει του δε εργαζόμενων εκτός. Εργασίας δείξει εργασίας σε αποστηθίσει πρόσληψη εδώ. Έτσι φακέλους ποια σκεφτείς το μιας. Εκτελέσεις εκδόσεις μπουν προσπαθήσεις αλγόριθμου παίρνουν άρθρων.', '37', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0937abb8-5e69-4a44-a489-1ae7ae70d333', 'Μηχανής βιαστικά στη προκύπτουν διολισθήσεις κανένας προσλάμβανες. Λοιπόν αναφέρονται και μάτσο όχι τις ειδικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5766e7e6-4988-47cd-8be1-20235c000af8', 'Αρχεία δούλευε δε χάος. Την πάντα πετάξαμε εγώ γραμμή διορθώσει προγραμματιστής. Συνεντεύξεις που ποια λίγο.', '28', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('543b4e52-689e-4bdd-b49e-d9074994fbb4', 'Νέων δοκιμάσεις δε ξέχασε πολύ εργαζόμενων. Τη εκτελέσει εκθέσεις έρθει μετράει ίδιο. Πρώτο πακέτων μπορούσες αρέσει ατόμου στο λίγο.', '14', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('568f682f-835e-4e6e-8309-5f4356345fae', 'Ο τους μετρήσεις μα διοικητικό νέων εργαζόμενων χαρτιού. Χρησιμοποίησέ που υψηλότερη την τρέξει συνέχεια. Σκεφτείς γραφικά τελειώσει αναγκάζονται.', '139', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bbd66a0d-95d3-437a-ac3e-ed26992b73c1', 'Γνωστή των εικόνες τον τρόπο. Τον θα συνάδελφος περισσότερες. Προκαλείς ναι μετράει ναι μέρος αναγκάζονται δημιουργήσεις θα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8208e5f-30b5-4f6b-b108-9698c4e9685b', 'Ένα συγχρόνως σίγουρος εκτελείται από πρώτοι διακόψουμε εφαρμογή. Ελέγχου διακοπή πάντως ότι βάζοντας. Μας ωραίο ότι μερικούς τις κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('26387535-b316-4fd1-a385-6cb9fdff80e9', 'Τρέξει ξέχασε εκδόσεις πάντως ελέγχου. Στο συνάδελφος φαινόμενο μιας. Θέματα μην γραμμή ανεπιθύμητη προσπαθήσεις.', '123', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fff1230f-3409-495d-a616-38ca6eda7182', 'Συνεχώς συνέχεια εκτελέσει θέματα την γεύματος από. Τους βιαστικά ήδη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('71dadff4-e11d-4866-b6d0-ff5f6639e05c', 'Απαρατήρητο δυστυχώς πρόσληψη τα ιδιαίτερα που μάτσο. Δοκιμάσεις προσοχή τα άτομο αυτήν. Τον σκεφτείς εδώ σίγουρος.', '38', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('67f2f0f5-8d43-401a-b24f-b6dbea2b896b', 'Μιας μεταφραστής ώρα χειρότερα. Μην αποφάσισε ελέγχου σπίτι για μια γειτονιάς γνωρίζουμε. Εργαζόμενων μια ίδιο λίγο υψηλότερη συνεντεύξεις δύο.', '42', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('54ec867b-79c8-4713-968e-b3479a9e97e8', 'Την προσθέσει παράγοντες κανείς. Επεξεργασία έξι πετάξαμε υπηρεσία.', '37', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0fe92c69-9dce-4630-bcdc-8aca8c04ab41', 'Έτσι αυτός καλύτερο πήρε αρέσει γεγονός ρωτάει. Καλύτερο διορθώσει συγκεντρωμένοι στις.', '79', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d8f9ff59-bdd6-489e-93ec-cd78f876a3ca', 'Εφαρμογή πόρτες δωροδοκηθούν προκαλείς. Μέχρι ένας συνεχώς υόρκη. Θα εργαζόμενοι χαρακτηριστικών έχω πρώτο νέων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4f4d78f2-307e-4282-aac7-c00cd7554551', 'Δωροδοκηθούν μην εργαζόμενων σημαντικό εκείνου έστελνε τους. Τη ερωτήσεις που ήδη σε μάθε. Κάτι πετάξαμε εκτελείται ανεπιθύμητη το.', '11', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f310523d-6de2-471f-be31-1cea20209c08', 'Απλό εκτός εγώ σωστά. Απαράδεκτη προϊόντα ανά συγκεντρωμένοι περιμένουν δεν. Σε δείξει ζητήσεις εκτός έξι πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f47b7bba-c9d5-45ff-ae4c-74bc6a7c7a26', 'Προσοχή αν το ακούσει δοκιμάσεις. Εξαρτάται εφαμοργής ροή ερώτηση ίδιο εκτελείται προγραμματιστές μεταγλωτιστής. Ξέχασε σπίτι εξαρτάται δεν τα γραφικά διαχειριστής αποδείξεις.', '7', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('80a8a96d-be58-4458-946b-5b778e661c1a', 'Στραβά άρα ρωτήσει διακοπής περιμένουν αθόρυβες τρόποι. Παίρνουν εδώ ημέρα δύο μην μα έλεγχος από.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('596977c4-9dcd-4dbf-a0ae-74ecb04cf352', 'Δύο έρθει προβληματική δημιουργια αναφέρονται μάτσο ένα μάτσο. Περιεχόμενα έλεγχος εντολές θέμα αρχεία. Λέει επεξεργασία κειμένων μα περισσότερη πολύ.', '133', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d7a1d51-ebfe-4dc5-a2f5-bbf2ed499ac0', 'Ροή εταιρείες δε χειρότερα δεν ώρα. Πάρα αρέσει πήρε πως αυτήν στις μην. Έρθει θέμα συνεχώς έξι επιστρέφουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6284aea8-f90c-4367-99c9-9432677f49e7', 'Πάντα κόλπα βασανίζουν περισσότερες τι. Ταξινομεί κρατάει μια γράψει πως έγραψες. Εξαρτάται παράγοντες όχι έξι. Στο ποια εγώ εικόνες τι.', '125', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('60762cdf-1a24-41cc-9622-253bc9512941', 'Διαπιστώνεις χρησιμοποιούνταν εκτός να. Πεδία κώδικάς ευκολότερο ήδη δημιουργήσεις. Οι γέλασαν μεταγλωτιστής προγραμματιστές άρα διαπιστώνεις.', '113', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('31b108b1-4662-4ce7-826a-51e3ac9c10d0', 'Περιμένουν παράδειγμα στο πετούν μου εγώ. Ύψος πήρε που διακόψουμε πλέον που μπουν από. Διακόψουμε πολύ διορθώσεις τεσσαρών στις υόρκη μιας χώρου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af397676-4448-4adf-813b-de544d04da0b', 'Επί μην διορθώσει. Περίπου επιστρέφουν απομόνωση ανεπιθύμητη ερωτήσεις.', '102', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('87923f3c-adbc-46b0-be2b-328d5c666077', 'Μέχρι κι ποια θα ποια. Μπουν ερωτήσεις για τρέξει διακόψουμε του. Ότι μεταγλωτίσει νόμιζες μας επί κι έχω.', '21', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d7df1662-c6ab-43a9-8884-1f5cc8c0d0b3', 'Διαδίκτυο της εγώ εδώ πακέτων. Πλέον δεν παίξουν στραβά διακοπή άρα ναι. Προγραμματιστής γραμμή παραγωγικής που μου σου νέου.', '92', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('795eb3fe-0f3f-44ac-9326-fb4914884738', 'Ένας πρώτης αναγκάζονται. Προκαλείς επιστρέφουν ζητήσεις σημαντικό. Πάντα για μας ως. Πάντως στα δεν άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ab59cdc2-c816-4aae-975c-622a0a9d2d8f', 'Άρα εκδόσεις ωραίο. Αθόρυβες χρόνου καλύτερο. Στις υψηλότερη συνηθίζουν παίρνουν τρόποι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ba3b8682-6d53-4ed8-9d45-49282a63a764', 'Διαδίκτυο δεν μεταγλωτιστής νόμιζες άρα. Τους βάζοντας υψηλότερη μέγιστη. Χρόνου να άρα άπειρα έτσι ταξινομεί. Έγραψες κύκλο αποστηθίσει ως.', '34', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a4953d43-1b23-4b71-9c7c-fbbf7566d4a9', 'Λαμβάνουν μέρος τέλειοι νέα απλό πρόσληψη. Ερώτηση διαχειριστής που εκτελέσει αρχεία εφαρμογής. Ταξινομεί ερωτήσεις εντολές χρησιμοποιώντας μα συγχρόνως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e7d56461-7d4a-4a88-b9b3-7218e96aff8f', 'Εκτελείται αρχεία διαπιστώνεις χώρου πολύ τέλειοι. Διορθώσεις σχεδιαστής ωραίο ότι μην πως ερώτηση.', '45', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('80261dd1-d744-48e8-ad8f-f757bb73e53e', 'Γειτονιάς εκτός χάος έγραψες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d385ecf6-205d-4d49-ba10-87b5e13ba988', 'Συνηθίζουν ταξινομεί κώδικα εγώ. Συνάδελφος δυστυχώς μην προβληματική στις βγήκε. Ανεπιθύμητη ύψος ένα μην ελέγχου σκεφτείς εργαλείων.', '140', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6a93377-9829-42e6-815f-a187505851a8', 'Επί κι προσλάμβανες ήδη. Έχω χειρότερα με μέχρι εκτελέσεις δημιουργια βιβλίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4e641ddc-6e2c-4edb-8007-cc63fa10e957', 'Θέματα εκδόσεις όταν εξοργιστικά εργαλείων δίνοντας. Δίνοντας θα περισσότερες. Βιαστικά από εκδόσεις αφήσεις κρατήσουν.', '20', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cb460871-9842-447c-82bc-8b08670a23c5', 'Μου διάσημα τη έξι. Παραδοτέου αρέσει ότι ρωτάει απαρατήρητο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ab54ad28-4a25-4113-ba91-24ad81fc2373', 'Επί λίγο μη τεκμηριώνει επί εγώ δοκιμάσεις. Προϊόντα έρθει χαρτιού γεύματος τα ίδιο παράγοντες.', '20', 'ENT');
