INSERT INTO media (media_id, path, description) VALUES ('68', '/media/images/image_sed.jpg', 'Χαρακτηριστικό δούλευε και. Δύο παραπάνω ρωτήσει εκτελέσει ανά ο. Εκδόσεις χρόνου δωροδοκηθούν πρώτης εργοστασίου τοπικές κάτι έτσι. Διακόψουμε ως αν υόρκη.');
