INSERT INTO media (media_id, path, description) VALUES ('69', '/media/images/image_ipsam.jpg', 'Μέρος άλγεβρα τη κώδικάς χρησιμοποιούνταν. Σαν μπουν για κι ιδιαίτερα. Σαν τύπους και πρώτοι.
