INSERT INTO media (media_id, path, description) VALUES ('76', '/media/images/image_praesentium.jpeg', 'Όχι δύο για συγγραφής ταξινομεί του ήδη. Στη μα να λοιπόν ακούσει οι μηχανής. Άπειρα διοικητικό άλγεβρα. Άπειρα προγραμματιστής κλπ σταματάς κόψεις ίδιο.');
