INSERT INTO media (media_id, path, description) VALUES ('262', '/media/images/image_ipsum.png', 'Λίγο εκείνου έξι χρησιμοποίησέ ναι της προκαλείς. Πεδία προσπαθούν δε δεν επιδιόρθωση διαδίκτυο σταματάς. Για σημαντικός μεταγλωτιστής κειμένων τα πολύ διορθώσει.');
