INSERT INTO media (media_id, path, description) VALUES ('311', '/media/images/image_dicta.png', 'Πρώτοι έξι άρα χάος. Περίπου τους αναφορά αναφορά. Του νόμιζες στέλνοντάς θα αφήσεις κειμένων.
