INSERT INTO media (media_id, path, description) VALUES ('312', '/media/images/image_debitis.jpeg', 'Έτσι ο επιστρέφουν μη περισσότερες δημιουργια. Παραδοτέου στέλνοντάς συγγραφής στο έτσι απαραίτητο ωραίο γεγονός.');
