INSERT INTO media (media_id, path, description) VALUES ('313', '/media/images/image_quos.jpeg', 'Στο όσο προκύπτουν θέμα περίπου πακέτων επενδυτής. Μέρος σταματάς άρα εγώ μια δύο προσθέσει. Ρωτήσει υψηλότερη ορίστε σαν.
