INSERT INTO media (media_id, path, description) VALUES ('314', '/media/images/image_eos.png', 'Τι άρθρων διαχειριστής το. Γνωστή λαμβάνουν δημιουργείς όχι μας πετάξαμε πακέτων.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('314', 'c94c0c75-3237-4c87-98b2-0f65e5f83f32');
INSERT INTO media (media_id, path, description) VALUES ('315', '/media/images/image_quaerat.png', 'Χρόνου έχω και μετρήσεις βγήκε. Και τα έτσι πως. Στα περιβάλλοντος περισσότερες προσλάμβανες πρώτης.');
