INSERT INTO media (media_id, path, description) VALUES ('316', '/media/images/image_quos.jpg', 'Γραφικά εγώ θέματα επί ως. Ο σημαντικός κλπ αναφορά σκεφτείς για. Πιο όταν των.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('316', '7c19d0c0-5bcd-4fc5-94c3-5aaa08d20ee6');
INSERT INTO media (media_id, path, description) VALUES ('317', '/media/images/image_ad.jpeg', 'Άλγεβρα ορίστε αντιλήφθηκαν ίδιο εγώ βαθμό. Έτσι που μέχρι των γεγονός περίπου.');
