INSERT INTO media (media_id, path, description) VALUES ('318', '/media/images/image_delectus.png', 'Την πρώτοι σχεδιαστής σταματάς. Ένα αναγκάζονται εντολές ότι το.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('318', '7d589dad-91ae-49b9-b20b-3c70e42c6b17');
INSERT INTO media (media_id, path, description) VALUES ('319', '/media/images/image_expedita.png', 'Διορθώσει μέρος επί αναγκάζονται ως βασανίζουν. Αποκλειστικούς περισσότερη τρόποι μηχανής. Νέου πρόσληψη λέει κώδικάς αναφορά.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('319', '331acd5c-ebd0-4a73-84fb-101037361eab');
INSERT INTO media (media_id, path, description) VALUES ('320', '/media/images/image_nam.jpeg', 'Δεν παίρνουν άρα ότι γραμμής. Χαρτιού συγγραφείς ήδη ρωτήσει ένα. Πόρτες όταν μη λετπά. Από λοιπόν διακοπής μην από κοιτάζοντας ρωτάει δημιουργήσεις.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('320', '2198031a-8596-43ae-95ff-2a3e41304406');
