INSERT INTO media (media_id, path, description) VALUES ('323', '/media/images/image_corrupti.jpeg', 'Δεν γράψει πηγαίου γέλασαν κλπ. Πάντα πετάνε για τύπους. Πρώτης δίνοντας στραβά κώδικα.
