INSERT INTO media (media_id, path, description) VALUES ('324', '/media/images/image_modi.jpg', 'Στο εκτός ρωτάει τεκμηριώνει πρώτης βασανίζουν. Ζητήσεις διάσημα έξι δουλεύει προσπαθήσεις. Περιεχόμενα στο κάνεις παίρνουν. Τέλειοι πιο τους άρα.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('324', '5d95499f-3625-4cf1-851f-51b7872b1315');
INSERT INTO media (media_id, path, description) VALUES ('325', '/media/images/image_quia.jpg', 'Εφαμοργής όταν εδώ ο. Την μιας βγήκε χρησιμοποιούσες χρησιμοποίησέ. Που εκτελέσεις το μπουν υπηρεσία χάος.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('325', '6f8076da-dbf0-4079-ba5d-9cbd2ca1d30d');
