INSERT INTO equipment_media (media_id, equipment_id) VALUES ('327', '34eae0a8-98eb-4c53-97cf-62c367d8887b');
INSERT INTO media (media_id, path, description) VALUES ('328', '/media/images/image_cumque.jpg', 'Απαράδεκτη προβληματική συνάδελφος συγγραφής εταιρείες μέρος επιδιορθώσεις φακέλους. Πάντα μη έλεγχος αγοράζοντας ήδη.
