INSERT INTO media (media_id, path, description) VALUES ('329', '/media/images/image_aperiam.jpeg', 'Θα πάρα ερωτήσεις διακοπή λίγο τα. Προσλάμβανες τη πάντα ημέρα. Διορθώσει όσο υπηρεσία έξι μέγιστη χρησιμοποιούσες.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('329', '60ee7f62-d141-4060-8e7f-0b49589fcd77');
INSERT INTO media (media_id, path, description) VALUES ('330', '/media/images/image_sequi.jpg', 'Αναγκάζονται εκτός δυστυχώς εταιρείες. Τύπους τη στο όταν αθόρυβες παίξουν επενδυτής.');
