INSERT INTO equipment_media (media_id, equipment_id) VALUES ('332', '081cb307-1be6-42be-82b8-9a1f5313bf40');
INSERT INTO media (media_id, path, description) VALUES ('333', '/media/images/image_deserunt.jpg', 'Επενδυτής εξοργιστικά τεσσαρών κι γραμμές. Σου πρώτοι κρατάει συγκεντρωμένοι σου. Επεξεργασία από διορθώσει ακούσει τρέξει δοκιμάσεις ποια. Προσπαθούν επιδιόρθωση σίγουρος έρθει για προσλάμβανες.');
