INSERT INTO media (media_id, path, description) VALUES ('334', '/media/images/image_saepe.png', 'Χώρου εξακολουθεί στα ναι σου εγώ τι. Κρατήσουν χαρακτηριστικό διευθυντές άρα νέα δεν.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('334', 'af38766f-d247-4de2-b5c4-3f699cfe9085');
