INSERT INTO media (media_id, path, description) VALUES ('339', '/media/images/image_quasi.png', 'Εφαμοργής απόλαυσε εντολές ένα σε το επί. Εκτός λαμβάνουν νέων παραγωγικής αλγόριθμου που. Πάντα δημιουργήσεις εκτός κάτι ωραίο πάρα μην.');
