INSERT INTO media (media_id, path, description) VALUES ('352', '/media/images/image_libero.jpeg', 'Όταν ρωτήσει άρα νέου απομόνωση δείξει. Μας τις μερικούς τεκμηριώνει. Απαρατήρητο όταν πετούν μέχρι άρα. Όχι ρωτάει αν.');
