INSERT INTO media (media_id, path, description) VALUES ('353', '/media/images/image_nemo.jpg', 'Πιο τεκμηριώνει έξι ορίστε πήρε χαρακτηριστικό ύψος. Περίπου ρωτήσει όταν κάτι διαχειριστής ανακλύψεις τι.');
