INSERT INTO media (media_id, path, description) VALUES ('355', '/media/images/image_odit.png', 'Πήρε πετάξαμε τοπικές την προγραμματιστές παίρνει στήλες. Περισσότερες περισσότερες αν πρώτο εδώ.');
