INSERT INTO media (media_id, path, description) VALUES ('358', '/media/images/image_iste.png', 'Τα κι ταξινομεί περισσότερες έτσι συγγραφής. Εργαζόμενοι πάντα κρατήσουν να κύκλο μάλλον σαν.');
