INSERT INTO media (media_id, path, description) VALUES ('364', '/media/images/image_recusandae.jpeg', 'Οι μάλλον στις έρθει διακόψουμε υψηλότερη ροή. Βασανίζουν πες πολύ έτοιμος κώδικα περίπου.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('364', '38d5d413-66af-4407-8b5a-91203d8995a1');
INSERT INTO media (media_id, path, description) VALUES ('365', '/media/images/image_animi.jpg', 'Αποθηκευτικού εκείνου κι. Ιδιαίτερα μέγιστη παραγωγικής του κλπ ακούσει επιδιορθώσεις.
