INSERT INTO media (media_id, path, description) VALUES ('448', '/media/images/image_voluptas.jpeg', 'Τα δεν εκτελέσει περιεχόμενα εξακολουθεί. Είχαμε μεταφραστής κανείς προσπαθούν ήδη ροή.
