INSERT INTO media (media_id, path, description) VALUES ('450', '/media/images/image_dicta.png', 'Εκδόσεις παραγωγικής στη σε επί καταλάθος για. Αναφέρονται μα συγγραφής αναφορά.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('450', 'a8208e5f-30b5-4f6b-b108-9698c4e9685b');
INSERT INTO media (media_id, path, description) VALUES ('451', '/media/images/image_ipsam.png', 'Κώδικα διολισθήσεις ο έρθει την επιχείριση έτσι. Ποια ύψος συγγραφείς πάντα εργοστασίου τους εκτός διάβασε.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('451', '26387535-b316-4fd1-a385-6cb9fdff80e9');
INSERT INTO media (media_id, path, description) VALUES ('452', '/media/images/image_alias.jpeg', 'Αποθηκευτικού πολύ συγχρόνως όσο. Θα μεταγλωτιστής τεκμηριώνει των περιεχόμενα ποια. Τους χρόνου ως υπηρεσία ίδιο προσλάμβανες τον.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('452', 'fff1230f-3409-495d-a616-38ca6eda7182');
