INSERT INTO equipment_media (media_id, equipment_id) VALUES ('453', '71dadff4-e11d-4866-b6d0-ff5f6639e05c');
INSERT INTO media (media_id, path, description) VALUES ('454', '/media/images/image_architecto.jpeg', 'Προγραμματιστής σε αρπάζεις εγώ κι διακόψουμε.
