INSERT INTO media (media_id, path, description) VALUES ('455', '/media/images/image_sint.png', 'Τέλειοι ναι προσλάμβανες μιας της. Πετάνε να προβληματική όσο. Δεν έγραψες προκαλείς μια ανεπιθύμητη.
