INSERT INTO media (media_id, path, description) VALUES ('456', '/media/images/image_alias.png', 'Όχι εργοστασίου κάτι τέλειοι. Πως μου δούλευε οι σας. Θέλεις φαινόμενο προβληματική από διάσημα.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('456', '0fe92c69-9dce-4630-bcdc-8aca8c04ab41');
INSERT INTO media (media_id, path, description) VALUES ('457', '/media/images/image_perspiciatis.png', 'Ως χρησιμοποιούσες δωροδοκηθούν περίπου χαρτιού μεταγλωτίσει γραμμή. Μπορούσες ήδη ας εκτός.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('457', 'd8f9ff59-bdd6-489e-93ec-cd78f876a3ca');
INSERT INTO media (media_id, path, description) VALUES ('458', '/media/images/image_sint.png', 'Σωστά των εργαλείων πρόσληψη ο συνέχεια γραμμές. Υπηρεσία κανένας έχω ιδιαίτερα ότι ένα. Να ας δείξει ναι χάος.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('458', '4f4d78f2-307e-4282-aac7-c00cd7554551');
INSERT INTO media (media_id, path, description) VALUES ('459', '/media/images/image_nesciunt.png', 'Βάζοντας εκείνου διευθυντές εγώ χρησιμοποιούνταν δημιουργήσεις δύο. Μας μπορούσες εσωτερικών γραφικά οι εφαρμογής.');
