INSERT INTO media (media_id, path, description) VALUES ('465', '/media/images/image_voluptatem.jpeg', 'Και στη έρθει παραπάνω αναγκάζονται δημιουργήσεις παραδώσεις εικόνες. Πρώτης πόρτες πιο παράδειγμα γραμμής.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('465', '60762cdf-1a24-41cc-9622-253bc9512941');
INSERT INTO media (media_id, path, description) VALUES ('466', '/media/images/image_vitae.png', 'Διαφήμιση προσλάμβανες μην προγραμματιστές δίνοντας. Αντιλήφθηκαν πάντα σου διοικητικό χαρακτηριστικό ναι γεύματος.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('466', '31b108b1-4662-4ce7-826a-51e3ac9c10d0');
INSERT INTO media (media_id, path, description) VALUES ('467', '/media/images/image_dicta.jpeg', 'Τον βαθμό πολύ γράψει στα.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('467', 'af397676-4448-4adf-813b-de544d04da0b');
INSERT INTO media (media_id, path, description) VALUES ('468', '/media/images/image_non.jpg', 'Ναι πως ρωτάει φίλος ένα πως υπηρεσία. Ας ανώδυνη πετάξαμε τύπου μέχρι πρώτοι κόλπα δε.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('468', '87923f3c-adbc-46b0-be2b-328d5c666077');
INSERT INTO media (media_id, path, description) VALUES ('469', '/media/images/image_molestiae.jpeg', 'Περιβάλλον προσπαθούν επιστρέφουν εγώ χρονοδιαγράμματος. Ανώδυνη προσπαθήσεις γραμμές εφαμοργής δε μέρος. Εκτός δεδομένων πολύ ανταγωνιστής ήδη. Διακοπή σταματάς χαρτιού.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('469', 'd7df1662-c6ab-43a9-8884-1f5cc8c0d0b3');
INSERT INTO media (media_id, path, description) VALUES ('470', '/media/images/image_nisi.jpeg', 'Νέου χρησιμοποιούνταν σκεφτείς αποδείξεις εκτός ημέρα στα. Παράγοντες μαγικά παίρνουν γραφικά.
