INSERT INTO media (media_id, path, description) VALUES ('471', '/media/images/image_itaque.png', 'Αρχεία κώδικάς πολύ χρησιμοποίησέ τρέξει προσθέσει. Εγώ διασφαλίζεται γραμμής τη κανόνα του.
