INSERT INTO media (media_id, path, description) VALUES ('472', '/media/images/image_saepe.png', 'Κι τρόποι κανένας πακέτων ατόμου παραγωγικής μας. Στραβά τους ήδη περίπου δε. Για κοιτάζοντας επί απαραίτητο παράδειγμα.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('472', 'ba3b8682-6d53-4ed8-9d45-49282a63a764');
INSERT INTO media (media_id, path, description) VALUES ('473', '/media/images/image_doloremque.jpg', 'Μέγιστη ζητήσεις κι δουλεύει μεταγλωτιστής σε αρχεία. Μην εργασίας τον για τον μέσης ρωτήσει. Ναι επιδιορθώσεις συνεντεύξεις. Γραφικά μπορούσες υποψήφιο.
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('473', 'a4953d43-1b23-4b71-9c7c-fbbf7566d4a9');
INSERT INTO media (media_id, path, description) VALUES ('474', '/media/images/image_asperiores.jpeg', 'Πιο προκαλείς έτοιμος πάντως μέγιστη. Προγραμματιστές από λετπά όταν σωστά διαπιστώνεις. Αντιλήφθηκαν ημέρα έστελνε συγχρόνως κι νόμιζες.');
