INSERT INTO media (media_id, path, description) VALUES ('477', '/media/images/image_vero.jpeg', 'Επιδιορθώσεις σου μεταγλωτίσει γιαυτό κανείς. Σαν φίλος μιας διοικητικό παίρνει τους.
