INSERT INTO media (media_id, path, description) VALUES ('637', '/media/images/image_amet.jpeg', 'Εκτός υόρκη κανόνα σταματάς αυτήν λοιπόν. Ένας έχω οι συνέχεια. Πάντα νέων απαράδεκτη.
INSERT INTO room_media (media_id, room_id) VALUES ('637', '133');
INSERT INTO media (media_id, path, description) VALUES ('638', '/media/images/image_eius.jpg', 'Ώρα ναι πρώτοι ευκολότερο σαν τρόποι σας μαγικά. Έχω τρόποι στραβά παραδοτέου βαθμό του αθόρυβες. Τι με απαράδεκτη.');
INSERT INTO room_media (media_id, room_id) VALUES ('638', '134');
INSERT INTO media (media_id, path, description) VALUES ('639', '/media/images/image_numquam.png', 'Ίδιο εκτός δημιουργείς για διολισθήσεις το διαχειριστής. Βιβλίο σπίτι διακόψουμε εξακολουθεί αν πετάνε. Αποστηθίσει κι μου κύκλο αθόρυβες πλέον.');
