INSERT INTO media (media_id, path, description) VALUES ('645', '/media/images/image_sapiente.png', 'Ερωτήσεις σταματάς μαγικά μια πρόσληψη με εκτός. Σε το πλέον ίδιο να πακέτων. Υπηρεσία μεταφραστής σπίτι προγραμματιστές εφαρμογής κώδικάς.');
