INSERT INTO media (media_id, path, description) VALUES ('647', '/media/images/image_aspernatur.jpeg', 'Γραφικά το χρησιμοποιούνταν γέλασαν. Μάλλον νέα συνεχώς. Περιεχόμενα εκθέσεις ανά επιδιόρθωση συγκεντρωμένοι σταματάς συγχρόνως.
