INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '95407', '2026-11-08 00:00:00', '2026-12-26 00:00:00', 'Νέων για το διασφαλίζεται. Ρωτάει συγγραφείς λίγο που πολύ του εργαζόμενων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '129490', '2026-03-07 00:00:00', '2026-03-09 00:00:00', 'Πακέτων σημαντικός συγχωνευτεί πάντα ποια προσοχή του εκδόσεις. Ναι νέο έτοιμος εικόνες αναφέρονται δημιουργείς. Ειδικά εκτός μη. Διασφαλίζεται τι προσπαθούν έλεγχος διοικητικό.', 'Μην πάντως αν ώρα ίδιο. Επεξεργασία απόλαυσε εντολές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '120476', '2025-02-14 00:00:00', '2025-03-26 00:00:00', 'Διασφαλίζεται τις αποκλειστικούς. Ας δε μιας αρπάζεις. Αντιλήφθηκαν μπορούσες κόλπα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '12923', '2025-11-09 00:00:00', '2026-01-08 00:00:00', 'Οι διευθυντές αυτός όταν δείξει δεν οι. Διαδίκτυο διακόψουμε τα ερωτήσεις. Λέει έξι μεταφραστής ας στη καταλάθος νέων λοιπόν. Διοικητικό στέλνοντάς περίπου αποστηθίσει γραμμές δούλευε γραμμές.', 'Θέλεις μιας αυτός γνωρίζουμε. Διορθώσει παραπάνω είχαμε απόλαυσε εγώ πιο όταν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '65962', '2022-11-26 00:00:00', '2022-12-01 00:00:00', 'Του ημέρα λέει ζητήσεις. Στήλες βγήκε μαγικά ζητήσεις αποκλειστικούς δημιουργια προβληματική των. Παίρνει διαδίκτυο σχεδιαστής διαφήμιση που τύπου. Ας αναφέρονται τα μιας εργαζόμενοι για το.', 'Σημαντικός ταξινομεί εταιρείες. Πετάξαμε μας επενδυτής το.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '121243', '2020-11-26 00:00:00', '2020-12-31 00:00:00', 'Υψηλότερη αποστηθίσει του σου νέα. Πιο να ανεπιθύμητη εδώ κάτι. Διοικητικό επιδιόρθωση δυστυχής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '130552', '2025-02-13 00:00:00', '2025-04-14 00:00:00', 'Ανεπιθύμητη ποσοστό πολύ συνέχεια απλό γέλασαν πόρτες. Έχω ταξινομεί άπειρα αποφάσισε. Νιρβάνα μετράει το πολύ. Τρόπο απίστευτα απόλαυσε.', 'Θυμάμαι πολύ δε προσπαθήσεις γραμμής. Το δείξει όσο εφαρμογή χάος δύο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '55773', '2021-05-18 00:00:00', '2021-06-30 00:00:00', 'Θυμάμαι εργαζόμενοι χρειάζονται υποψήφιο. Καλύτερο όχι πρώτο διασφαλίζεται. Αν ένα οι εδώ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '118181', '2020-02-22 00:00:00', '2020-04-21 00:00:00', 'Συνάδελφος απομόνωση στήλες οι μα ποσοστό σωστά. Κρατάει στα προσπαθούν απόλαυσε.', 'Εντολές όχι γραμμές γραμμές ένας εργαλείων ζητήσεις το.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('2', '2108896469', '0207552006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '122490', '2025-02-22 00:00:00', '2025-04-17 00:00:00', 'Συνηθίζουν τελειώσει επί μηχανής πως εφαμοργής έχω. Προκύπτουν κανένας σαν. Σου παραδώσεις τις του γιαυτό βγήκε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '132618', '2022-10-23 00:00:00', '2022-12-05 00:00:00', 'Δυστυχής τρέξει κι δύο θέματα έστειλε μια. Δημιουργια εσωτερικών σημαντικός διορθώσει τι και. Μια γνωστή ορίστε τα. Νόμιζες αν των.', 'Τα από εγώ εργοστασίου βασανίζουν πως μη προκύπτουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '65480', '2022-12-01 00:00:00', '2023-01-02 00:00:00', 'Ώρα μάτσο προσοχή σου χαρακτηριστικών κάνεις προβληματική. Εργάστηκε διαχειριστής μάτσο έτσι μπορούσες πλέον κλπ. Αποφάσισε ίδιο εταιρείες τελειώσει προκαλείς δωροδοκηθούν.', 'Χρειάζονται χρησιμοποιούσες θέλεις σου προσθέσει αντιλήφθηκαν νέου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '10153', '2022-07-24 00:00:00', '2022-07-31 00:00:00', 'Δουλεύει που όταν ίδιο μετράει. Νέων νέου που λες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '91437', '2025-12-08 00:00:00', '2025-12-21 00:00:00', 'Μάτσο σαν σου δεν ανακλύψεις νέων. Πάρεις φακέλους τελειώσει ναι. Πόρτες παίξουν κάτι από του. Χαρτιού εργαζόμενων βιβλίο σημεία εδώ ας δίνοντας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '91683', '2025-12-23 00:00:00', '2025-12-28 00:00:00', 'Κάτι εκθέσεις ορίστε πάντως λοιπόν άρα. Πως σε μη ως πρώτοι. Απίστευτα συνεντεύξεις έχω απίστευτα προσπαθούν ότι.', 'Γιαυτό ποια σας διάσημα να λοιπόν εικόνες. Παίξουν όσο καταλάθος δύο.');
