INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '29099', '2026-11-26 00:00:00', '2027-01-20 00:00:00', 'Τη το των εγώ μετράει του. Ας παίρνουν εκτελέσει νόμιζες κλπ επί ποια αναφέρονται.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '16148', '2023-02-07 00:00:00', '2023-03-05 00:00:00', 'Βρίσκονται ευκολότερο μιας αποφάσισε χαρτιού καλύτερο δουλεύει. Ορίστε διασφαλίζεται κάνε κάτι έξι. Ευκολότερο κόλπα εργάστηκε έξι παράδειγμα δύο.', 'Σαν προσπαθήσεις πάρεις μη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '9530', '2025-02-07 00:00:00', '2025-02-16 00:00:00', 'Ελέγχου μιας απαράδεκτη προγραμματιστής επενδυτής.', 'Πως σου λαμβάνουν παίρνει για εκτελέσει συνεντεύξεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '135858', '2026-05-22 00:00:00', '2026-07-16 00:00:00', 'Στις γνωρίζουμε περιβάλλον κόλπα γνωστή δεν. Ανά έχω εκτελέσει πεδία συνεχώς τις. Υποψήφιο δε που ο στα.', 'Μη φίλος περισσότερες. Συνεχώς γραμμές ημέρα μην εσωτερικών περιεχόμενα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '95476', '2026-02-03 00:00:00', '2026-04-03 00:00:00', 'Φαινόμενο ταξινομεί σου τις δημιουργήσεις ποσοστό. Εγώ περίπου απαράδεκτη έτσι μου χρησιμοποιούνταν.', 'Εδώ επενδυτής θέλεις. Απόλαυσε για συγχωνευτεί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('4', '2810769157', '0801614135');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '56725', '2021-05-31 00:00:00', '2021-06-27 00:00:00', 'Υόρκη ανά τα κανένας κανείς ευκολότερο χαρτιού. Πετάξαμε γνωρίζουμε περιβάλλοντος ως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '131063', '2021-01-15 00:00:00', '2021-02-27 00:00:00', 'Κανένας συνηθίζουν στα μας δημιουργείς ας ένας αν. Πολύ έρθει ποια λες που. Γειτονιάς των τρόποι κρατήσουν.', 'Θα τι πάντως. Εγώ προσθέσει άρθρων πιο έξι δημιουργείς. Υόρκη τον μη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '43839', '2022-02-07 00:00:00', '2022-02-09 00:00:00', 'Απίστευτα αν προσεκτικά εκτελέσεις εκτελέσει επιχείριση. Εταιρείες χρησιμοποιώντας παραγωγικής φράση εργαλείων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '109535', '2026-12-12 00:00:00', '2027-01-23 00:00:00', 'Μάθε και λίγο απόλαυσε λαμβάνουν. Τις γραφικά τέλειοι ναι δημιουργήσεις σαν εδώ.
