INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '73485', '2024-11-07 00:00:00', '2024-12-05 00:00:00', 'Αποστηθίσει αναφέρονται ρωτήσει συνάδελφος να. Μη σημεία ελέγχου γειτονιάς. Δημιουργήσεις προσπαθούν μετρήσεις τι κρατάει.', 'Επιχείριση πετάξαμε σταματάς.');
