INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '141425', '2020-05-13 00:00:00', '2020-05-31 00:00:00', 'Έτσι διολισθήσεις έτσι πλέον υψηλότερη. Που αποθηκευτικού ρουτίνα γραφικά μέχρι αθόρυβες κώδικάς. Έξι αν παίρνει περιμένουν σπίτι δυστυχής μια.', 'Ελέγχου δείξει δίνοντας περιβάλλον. Πάρα σωστά δημιουργείς ανά αρπάζεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('6', '2108896469', '0605788620');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '161440', '2020-02-04 00:00:00', '2020-02-23 00:00:00', 'Του εκτός μετράει άπειρα κανένας. Παίρνουν διοικητικό βγήκε ευκολότερο πολύ που έτσι. Έχω επενδυτής στη όταν εγώ απόλαυσε μάλλον.', 'Έστειλε εκτός πλέον ακούσει. Μέρος κρατάει αφήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '120013', '2026-09-27 00:00:00', '2026-10-04 00:00:00', 'Πλέον διορθώσει μαγικά νόμιζες. Από ρωτήσει μια. Σταματάς παραπάνω στραβά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '802', '2023-01-24 00:00:00', '2023-03-11 00:00:00', 'Κάτι προσλάμβανες όταν ποσοστό. Γεγονός βρίσκονται γραμμές. Προκαλείς μεταγλωτίσει τύπους παίρνουν στο έτοιμος μαγικά. Ρουτίνα θα τύπου εγώ σου εξοργιστικά λετπά ζητήσεις.', 'Κανένας γεύματος από των μα. Δε χρειάζονται δεν. Χρειάζονται ορίστε σε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('7', '2012726759', '0303070046');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '9663', '2020-06-30 00:00:00', '2020-08-21 00:00:00', 'Για γραμμής διακόψουμε ρουτίνα του πλέον ίδιο έρθει. Ίδιο σπίτι συνέχεια εκθέσεις μας χαρακτηριστικών. Εκείνου πάντα εσωτερικών υόρκη διολισθήσεις.', 'Εργαζόμενοι ύψος συγκεντρωμένοι δεν διακοπής λοιπόν πεδία δεδομένων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '26189', '2020-06-27 00:00:00', '2020-07-30 00:00:00', 'Τις ότι τις υψηλότερη. Ανεπιθύμητη το εξαρτάται. Γνωρίζουμε επιδιορθώσεις δωροδοκηθούν στη εντολές.', 'Λετπά σε δυστυχής έξι. Μου δωροδοκηθούν διακοπής. Πλέον μάθε μα γραφικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '111627', '2021-01-11 00:00:00', '2021-01-20 00:00:00', 'Πως λοιπόν τον. Γραμμές χρονοδιαγράμματος τέλειοι απίστευτα ύψος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '155272', '2020-07-29 00:00:00', '2020-09-17 00:00:00', 'Βουτήξουν που σημαντικό απαραίτητο στη παραγωγικής αφήσεις. Χώρου μα μεταγλωτίσει συνέχεια δεδομένων αντιλήφθηκαν έτσι αυτός.', 'Εργασίας βγήκε εκτελέσεις του για εσωτερικών και μου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '159462', '2025-08-12 00:00:00', '2025-10-01 00:00:00', 'Ένα ας υόρκη των των. Πλέον κώδικάς μην μας. Δε ρωτάει εκθέσεις χαμηλός σου επιδιόρθωση εκδόσεις. Μεταγλωτίσει πετάνε πολύ έλεγχος τη.', 'Φακέλους εγώ μεταφραστής αποθηκευτικού χαρακτηριστικών μάτσο πάρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '63851', '2020-07-06 00:00:00', '2020-07-25 00:00:00', 'Όταν από δεν έξι μέχρι φίλος μέχρι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '50105', '2022-08-13 00:00:00', '2022-10-03 00:00:00', 'Θέματα έξι διολισθήσεις κάτι. Μέρος όσο διάσημα προβληματική δυστυχώς. Επί νέα τι δύο δεδομένων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '99149', '2024-07-26 00:00:00', '2024-08-01 00:00:00', 'Ταξινομεί θέμα άρθρων περίπου πλέον.
