INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '56061', '2023-11-17 00:00:00', '2023-12-01 00:00:00', 'Ανταγωνιστής μιας των προσπαθήσεις εκείνου κι χρησιμοποιώντας. Διακόψουμε μάθε αγοράζοντας λετπά κάτι. Διαπιστώνεις βγήκε πλέον παραδοτέου.', 'Ερώτηση έτσι έξι σκεφτείς ο έχω εξοργιστικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '108945', '2024-01-20 00:00:00', '2024-02-26 00:00:00', 'Στις πρόσληψη διαχειριστής χρονοδιαγράμματα. Διακοπής απλό χάος πηγαίου διολισθήσεις το.', 'Ανταγωνιστής επιδιόρθωση παραπάνω ως θέλεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '134401', '2026-08-23 00:00:00', '2026-09-27 00:00:00', 'Αρέσει κι κλπ δυστυχής δε κοιτάζοντας τύπους. Συνέχεια ας ακούσει γραφικά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '125519', '2026-11-10 00:00:00', '2026-12-04 00:00:00', 'Χρησιμοποιούνταν προσλάμβανες χαρτιού μέχρι εκδόσεις χρησιμοποιούσες χαρακτηριστικών. Γραμμές του που παίξουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '14352', '2026-12-03 00:00:00', '2027-01-22 00:00:00', 'Υψηλότερη διορθώσεις να τι αποστηθίσει φράση απλό. Εργαλείων πάντα θα βρίσκονται ξέχασε όταν εκτός.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '124702', '2024-09-22 00:00:00', '2024-11-11 00:00:00', 'Ακούσει προσθέσει γειτονιάς αναγκάζονται περισσότερες. Επιστρέφουν επί αφήσεις εδώ ποια. Λες σας κάνεις πρώτο σας εφαμοργής.', 'Δείξει εσωτερικών λίγο διακοπής και έτσι κώδικα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '27290', '2026-08-22 00:00:00', '2026-08-29 00:00:00', 'Τρόποι ωραίο υπηρεσία επιδιόρθωση. Τεκμηριώνει παίρνουν εργαζόμενων αποστηθίσει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '142565', '2024-06-21 00:00:00', '2024-07-05 00:00:00', 'Ήδη εκδόσεις ερωτήσεις πολύ θέμα απλό δυστυχής. Ύψος μερικούς διορθώσεις ποσοστό βιαστικά επιστρέφουν με. Ότι νόμιζες κανείς πάρεις παίρνει μην περιβάλλοντος όταν.', 'Πιο περιεχόμενα μας που τις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '6648', '2020-07-09 00:00:00', '2020-08-10 00:00:00', 'Υπηρεσία νέου πρώτο. Ναι πως τρόπο θέμα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('9', '2103512690', '1411577444');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('9', '42988', '2026-01-06 00:00:00', '2026-02-26 00:00:00', 'Ένας περιμένουν μετρήσεις πρώτοι. Πεδία μάλλον μιας λετπά εξαρτάται παράδειγμα. Νέο επιστρέφουν αναφέρονται πολύ.', 'Έξι ένας πως προσθέσει αρχεία έρθει περισσότερες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('10', '0507856932', '1808698754');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '150305', '2024-06-17 00:00:00', '2024-06-26 00:00:00', 'Αυτός όταν σχεδιαστής. Τις σαν κώδικάς σταματάς πάντα κανόνα γράψει. Ήδη νιρβάνα διάσημα περισσότερη.', 'Πάντα επί την κανένας ρωτήσει κάτι περίπου. Χρησιμοποίησέ ίδιο γραμμές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '52848', '2026-04-29 00:00:00', '2026-05-24 00:00:00', 'Άρθρων για ίδιο αρχεία βαθμό έξι δε. Γραμμή τους διακόψουμε ήδη εκτελείται.', 'Νέου ένας μην. Το προσλάμβανες λοιπόν οι ως βουτήξουν στο μας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '51842', '2020-07-26 00:00:00', '2020-09-09 00:00:00', 'Είχαμε ρωτήσει σε λέει καλύτερο. Άλγεβρα αποφάσισε τύπου αποφάσισε ρωτήσει. Αναγκάζονται ένας ως ανακλύψεις.', 'Γιαυτό δωροδοκηθούν περιμένουν όταν σίγουρος όταν γνωστή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '142958', '2021-08-21 00:00:00', '2021-10-16 00:00:00', 'Όταν δωροδοκηθούν μην απαραίτητο. Νόμιζες έξι ρωτήσει ταξινομεί κώδικάς εκδόσεις λέει σημαντικό.', 'Γραμμής απίστευτα που εκδόσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '80088', '2020-04-25 00:00:00', '2020-04-28 00:00:00', 'Εικόνες αν που προϊόντα χρειάζονται μα έρθει. Χρονοδιαγράμματα και δεν μερικούς εξαρτάται ας ακούσει. Τύπους ημέρα έτοιμος μεταγλωτιστής.', 'Τεκμηριώνει λέει χρονοδιαγράμματα ας συγγραφής έχω που.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '143164', '2021-03-15 00:00:00', '2021-05-06 00:00:00', 'Έστειλε εντολές πετάξαμε ένας. Διαδίκτυο γραμμή ύψος ποια λίγο πάρεις.', 'Να συνεχώς που μεταγλωτίσει κύκλο την. Αυτήν προσθέσει γραμμή ένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('11', '1710622455', '2404740880');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '28939', '2026-05-25 00:00:00', '2026-07-11 00:00:00', 'Γέλασαν κάνεις χρονοδιαγράμματα εκτελέσει. Λετπά ποια προσπαθήσεις εδώ ποια σας. Νέου εξοργιστικά από ήδη όταν έστελνε ρουτίνα.', 'Καλύτερο από κόλπα συνηθίζουν μου διορθώσεις έχω. Άρα λέει αλγόριθμου εκθέσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '22675', '2021-12-05 00:00:00', '2021-12-09 00:00:00', 'Οι ρωτήσει κλπ αρέσει ίδιο δυστυχής. Γεύματος δεν εξακολουθεί της χρονοδιαγράμματα. Εξοργιστικά απομόνωση εκτός εργοστασίου εφαρμογής τα προϊόντα.', 'Εφαμοργής μα εκτός άλγεβρα διαφήμιση. Έτσι πεδία γεύματος αντιλήφθηκαν άτομο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '74104', '2026-04-20 00:00:00', '2026-05-28 00:00:00', 'Λες εργάστηκε πρώτο. Περιβάλλον πλέον τα αφήσεις υποψήφιο άρθρων όταν. Χαμηλός πηγαίου πρόσληψη ροή στη φακέλους αγοράζοντας απίστευτα.', 'Γειτονιάς πως ρωτήσει κάτι μάλλον παράδειγμα στέλνοντάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '116312', '2022-07-06 00:00:00', '2022-08-31 00:00:00', 'Προγραμματιστές μέρος την. Τα διορθώσεις κανόνα απαραίτητο το.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '31306', '2024-12-20 00:00:00', '2025-02-15 00:00:00', 'Δυστυχώς πάντως μου περιβάλλοντος χρησιμοποίησέ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '4941', '2025-08-31 00:00:00', '2025-09-04 00:00:00', 'Δεν ότι στέλνοντάς μάλλον σου. Εφαμοργής ημέρα απαράδεκτη αθόρυβες επιδιορθώσεις κρατήσουν υψηλότερη. Τις προγραμματιστής διαχειριστής έτοιμος διαφήμιση.', 'Άρα μάθε χαρτιού κάτι εκθέσεις παίρνουν θέλεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '105372', '2026-03-09 00:00:00', '2026-04-28 00:00:00', 'Ποια θέματα συγγραφείς όσο περίπου μέρος μας. Να να μιας όταν υόρκη δοκιμάσεις στήλες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '29927', '2026-10-31 00:00:00', '2026-12-05 00:00:00', 'Κι ένας έξι τρόπο. Διάβασε τα παίρνουν διαπιστώνεις λαμβάνουν παίξουν γνωρίζουμε. Εργαζόμενοι πάντως σε λοιπόν προβληματική διαδίκτυο ως.', 'Υψηλότερη χαμηλός επί βγήκε. Αποδείξεις είχαμε του εντολές πλέον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('12', '2608605682', '1610609390');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '107853', '2025-06-03 00:00:00', '2025-06-22 00:00:00', 'Άλγεβρα προβληματική μιας νέα ότι να έρθει επί. Πρόσληψη δύο για στραβά τρόποι ειδικά περίπου. Πάντα πλέον θέματα τι ροή άρα. Πολύ αλγόριθμου πλέον κάτι διαδίκτυο φράση.', 'Πλέον προκύπτουν αναγκάζονται πάρεις αντιλήφθηκαν τα κανένας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '108065', '2024-01-22 00:00:00', '2024-03-12 00:00:00', 'Με συνάδελφος πόρτες. Δεν σε σε όσο στήλες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('13', '0306759452', '0312710224');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '125419', '2024-08-06 00:00:00', '2024-09-03 00:00:00', 'Ήδη όχι πολύ έτοιμος ποια εκτελέσει της. Διακοπής δε ένας αγοράζοντας ειδικά εργαλείων πακέτων. Σκεφτείς λες έτσι που.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '159186', '2025-01-21 00:00:00', '2025-02-04 00:00:00', 'Δίνοντας τις της κάτι. Γιαυτό κύκλο συγγραφείς περιβάλλοντος σαν πετούν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '110568', '2022-05-24 00:00:00', '2022-06-07 00:00:00', 'Σκεφτείς τις στέλνοντάς εκδόσεις ανακλύψεις ημέρα προσοχή άρα. Θέματα ατόμου σου.', 'Μα πρώτης τον κανόνα για. Πιο ανά πετάξαμε και ορίστε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '151130', '2023-05-27 00:00:00', '2023-07-12 00:00:00', 'Δύο εγώ ερώτηση πες περιεχόμενα κειμένων. Επιστρέφουν χρησιμοποιώντας χειρότερα έξι όταν παραδώσεις. Αναφέρονται παίρνει χρησιμοποίησέ κρατήσουν.', 'Κανένας συνηθίζουν πάρεις εξακολουθεί νέου παραδώσεις κανένας όταν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('14', '1510425991', '1706634516');
