INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '81627', '2025-06-06 00:00:00', '2025-06-23 00:00:00', 'Δύο ναι αναφορά βάζοντας διοικητικό. Είχαμε μας χαρτιού περιβάλλον προσπαθήσεις υψηλότερη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '122001', '2022-04-12 00:00:00', '2022-06-11 00:00:00', 'Ακούσει ας μεταγλωτίσει αναφέρονται. Ανά εδώ ρουτίνα εδώ συνέχεια είχαμε του.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '43880', '2026-09-14 00:00:00', '2026-10-19 00:00:00', 'Μια υπηρεσία ύψος όσο ότι υψηλότερη. Στις παράδειγμα χαρακτηριστικό λες παίρνει κλπ ας. Πες σημεία έτσι ειδικά γειτονιάς δεν διακόψουμε. Γράψει αποδείξεις εδώ ατόμου κάνε χρησιμοποιώντας.', 'Διοικητικό μιας κόψεις διάβασε. Ήδη ότι πήρε νόμιζες στη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '110616', '2022-11-28 00:00:00', '2022-12-14 00:00:00', 'Χώρου χρησιμοποιούσες διορθώσει ναι αρχεία τύπους. Γεύματος χάος έτοιμος έτσι τεσσαρών φαινόμενο είχαμε.', 'Μεταγλωτίσει διαπιστώνεις εκτός ένας μιας διάσημα. Σκεφτείς μα τα κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('15', '2503001279', '1601850885');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '96045', '2024-12-13 00:00:00', '2025-01-05 00:00:00', 'Τέλειοι διακόψουμε ποσοστό συνεχώς. Μιας συγκεντρωμένοι μέσης απλό άρα έλεγχος. Λετπά στο γειτονιάς εργαλείων διαδίκτυο μπουν μέρος.', 'Ίδιο γεύματος λετπά φαινόμενο. Ποια στις κι τεκμηριώνει εκτελείται στη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '20331', '2026-09-24 00:00:00', '2026-11-23 00:00:00', 'Λίγο δύο απλό εργασίας αν προσπαθήσεις πετάξαμε. Τον στη από όταν μάλλον σε περιεχόμενα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '83091', '2024-01-25 00:00:00', '2024-02-02 00:00:00', 'Εφαρμογής γνωρίζουμε εργάστηκε κλπ εδώ εγώ των. Ειδικά εργαζόμενων κι δουλεύει συνεντεύξεις ίδιο.', 'Πολύ απλό τεσσαρών σημαντικός σου μη δεν ήδη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('16', '1001621875', '0107824374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '131863', '2023-08-28 00:00:00', '2023-09-20 00:00:00', 'Δοκιμάσεις δε ανακλύψεις ώρα χρονοδιαγράμματα τρόπο. Περισσότερη μην εργαζόμενων δεν δούλευε μέρος.', 'Σίγουρος για ναι μπουν σημαντικό. Νέα συνηθίζουν κάνε δουλεύει τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '24044', '2025-05-06 00:00:00', '2025-06-03 00:00:00', 'Που κάτι εκτός κύκλο προκύπτουν ακούσει εκτός. Ρουτίνα έχω ροή ως χρησιμοποιώντας.', 'Αρέσει σας προσθέσει διορθώσεις την δούλευε απίστευτα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '69556', '2022-09-03 00:00:00', '2022-10-10 00:00:00', 'Παραδοτέου συγγραφής περισσότερες ώρα συγγραφής ο έτσι τι.', 'Ανά περιβάλλον απλό πως περίπου τα όταν αν. Φαινόμενο θέμα κάτι από διακοπή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '4460', '2020-11-28 00:00:00', '2021-01-19 00:00:00', 'Απαρατήρητο στη μιας θέλεις θα. Στα εργαλείων και εγώ μεταφραστής βουτήξουν. Βιβλίο απομόνωση προβληματική προσπαθήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '72812', '2025-02-19 00:00:00', '2025-03-12 00:00:00', 'Σαν τον από περιεχόμενα ωραίο των εδώ. Μα που μην μαγικά αναφορά ειδικά προβληματική. Νέο απαραίτητο κώδικάς ανακλύψεις κανόνα πάντα.', 'Στο εργαζόμενοι κάνεις. Τις μας απαραίτητο εξακολουθεί δεν πεδία.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '139940', '2025-05-01 00:00:00', '2025-06-18 00:00:00', 'Της πολύ γεγονός γραφικά να μα μου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '52931', '2024-02-18 00:00:00', '2024-02-21 00:00:00', 'Ίδιο δύο κι αγοράζοντας μάτσο κάτι διάβασε. Θέματα προγραμματιστές χρόνου εικόνες τελειώσει χρόνου άρα υπηρεσία. Δυστυχής του έτσι τους συγκεντρωμένοι καλύτερο.', 'Είχαμε αθόρυβες επί θυμάμαι. Μπουν δίνοντας τον πάντα την κανένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('17', '1208984016', '2006028711');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '97086', '2021-09-28 00:00:00', '2021-10-24 00:00:00', 'Διαχειριστής προσπαθήσεις θα μπορούσες κλπ δεδομένων αγοράζοντας πρώτης. Όχι σταματάς μερικούς εταιρείες επεξεργασία δε πήρε.', 'Θέματα εξοργιστικά αντιλήφθηκαν έστελνε προγραμματιστής ήδη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '117349', '2022-04-21 00:00:00', '2022-05-23 00:00:00', 'Πάντως έλεγχος χαμηλός είχαμε οι. Σαν χαρακτηριστικών βρίσκονται απομόνωση έχω άρθρων χαρακτηριστικών ποια.', 'Εργαζόμενων θυμάμαι έτσι διακόψουμε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '143495', '2025-02-27 00:00:00', '2025-04-22 00:00:00', 'Χαμηλός μάθε εσωτερικών ως σκεφτείς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('18', '1606420374', '1309516787');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '47760', '2025-10-11 00:00:00', '2025-11-29 00:00:00', 'Συνάδελφος εκτελέσεις εκτελέσει γραμμές δουλεύει μιας διαδίκτυο. Μας χρησιμοποιώντας εργαζόμενοι νέων υψηλότερη εγώ. Μια τοπικές με τον που ήδη είχαμε.', 'Παραδοτέου παίρνει μας πιο σπίτι το καταλάθος. Παίξουν άρα πάντα ωραίο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '59654', '2024-12-10 00:00:00', '2025-01-01 00:00:00', 'Εδώ επεξεργασία μη έτοιμος. Το κειμένων προκύπτουν εικόνες ερωτήσεις όχι. Πάντα νέα άπειρα άρα συνάδελφος ένας.', 'Τοπικές ποια πιο. Να δεν χάος κανένας ένας προσλάμβανες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '96597', '2023-11-26 00:00:00', '2024-01-13 00:00:00', 'Ποσοστό δημιουργείς παραγωγικής χώρου χαρακτηριστικών πετάξαμε ακούσει. Που τα αρχεία εταιρείες ρωτήσει γνωρίζουμε. Απαραίτητο εδώ νέα χρησιμοποίησέ δωροδοκηθούν έστειλε.', 'Έρθει απομόνωση το χώρου λετπά όταν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '65435', '2025-09-28 00:00:00', '2025-10-02 00:00:00', 'Λοιπόν δωροδοκηθούν γνωρίζουμε γνωρίζουμε μας πολύ ήδη. Στις παραδώσεις εκτός πάντως διοικητικό εφαμοργής.
