INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '68343', '2024-11-16 00:00:00', '2024-12-26 00:00:00', 'Ως εικόνες δυστυχώς λαμβάνουν εσωτερικών σαν. Νέου μάλλον περισσότερη όσο. Ροή τεκμηριώνει χρησιμοποιώντας μέχρι στραβά έρθει.', 'Άπειρα ελέγχου χρησιμοποίησέ τύπου. Υποψήφιο που μέρος. Σου γνωστή ναι μην.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '79182', '2022-02-03 00:00:00', '2022-03-10 00:00:00', 'Εργοστασίου βιβλίο τεσσαρών πιο μέχρι δεν. Χειρότερα νόμιζες ότι έλεγχος συγχωνευτεί ευκολότερο. Επιστρέφουν που ότι πιο.
