INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '25256', '2023-07-29 00:00:00', '2023-09-20 00:00:00', 'Νέα έτοιμος χρόνου χάος εργασίας. Στις γεγονός άρθρων ένα τους αρχεία. Ημέρα με ευκολότερο πετούν υόρκη δεδομένων εγώ.', 'Χρονοδιαγράμματος τέλειοι άρα γράψει στέλνοντάς επί δυστυχώς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '9745', '2025-02-18 00:00:00', '2025-02-27 00:00:00', 'Συγγραφείς μεταγλωτιστής απαραίτητο περιβάλλον ειδικά βαθμό τρέξει.', 'Ένας εφαρμογής πετάξαμε πάντα ο ελέγχου ως χώρου.');
