INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '133974', '2021-03-15 00:00:00', '2021-04-11 00:00:00', 'Τελειώσει μη πρώτο αποθηκευτικού ας θα φράση πρόσληψη. Δωροδοκηθούν πλέον των ας κάτι σπίτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '135294', '2022-01-29 00:00:00', '2022-02-26 00:00:00', 'Δε συνεντεύξεις κάνε πάντως με εργοστασίου. Δημιουργείς διαδίκτυο πρώτο προϊόντα περιβάλλον βουτήξουν λίγο.', 'Κόψεις πως νέα έξι. Μπορούσες πάντα υποψήφιο. Ρωτάει θέμα διορθώσεις του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '128697', '2025-12-13 00:00:00', '2026-01-15 00:00:00', 'Βάζοντας σταματάς οι ποια έστελνε πάντα χάος. Γνωρίζουμε προγραμματιστής ξέχασε πόρτες τη τοπικές.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '73667', '2022-11-17 00:00:00', '2022-12-04 00:00:00', 'Μου ως απομόνωση μηχανής. Ένα περιεχόμενα βγήκε δημιουργήσεις διασφαλίζεται. Κρατήσουν ύψος έτοιμος διακόψουμε.', 'Σταματάς δε κρατάει αποκλειστικούς. Δε σου από αναφορά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '76384', '2023-09-24 00:00:00', '2023-10-23 00:00:00', 'Τύπους δείξει δύο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '143055', '2021-05-25 00:00:00', '2021-06-06 00:00:00', 'Μέχρι κόλπα μας τις τα στις του. Τι τις μετράει πόρτες. Τη διάβασε πρόσληψη όχι υψηλότερη έχω.', 'Έστειλε καλύτερο μέχρι ταξινομεί εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '4835', '2024-04-11 00:00:00', '2024-05-24 00:00:00', 'Ιδιαίτερα παραδοτέου πάρα τη εργάστηκε. Τεκμηριώνει βγήκε κάνεις εδώ γραφικά περιμένουν μη. Έρθει έχω μηχανής νέων.', 'Πιο πιο δύο μην ρωτήσει έχω προσπαθούν. Περιμένουν για δεδομένων βασανίζουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('29', '0909811886', '2406607772');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '35836', '2026-10-22 00:00:00', '2026-11-23 00:00:00', 'Θα μας τα εφαρμογή. Μάλλον συνεχώς σημαντικό απόλαυσε διαφήμιση.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '55624', '2024-06-30 00:00:00', '2024-08-17 00:00:00', 'Περιεχόμενα μας μάθε όταν κανένας. Θυμάμαι διακοπή βιβλίο γιαυτό ας τέλειοι. Έτοιμος παράδειγμα πόρτες λίγο.', 'Σας του έτοιμος ημέρα ότι με συνεχώς. Τρόποι αποφάσισε για κάνε μιας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '101636', '2020-02-05 00:00:00', '2020-02-18 00:00:00', 'Αρχεία περιμένουν μια προσεκτικά διακόψουμε. Αυτός σωστά σκεφτείς το. Μέχρι μετρήσεις αναγκάζονται σου ποια δύο απίστευτα παίρνει.', 'Προκαλείς εργαλείων νιρβάνα με.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '3391', '2020-09-11 00:00:00', '2020-10-29 00:00:00', 'Κύκλο από ερωτήσεις αφήσεις. Του όσο αρπάζεις εργάστηκε. Διαχειριστής τρόπο διάσημα βιβλίο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '138829', '2025-12-07 00:00:00', '2026-01-15 00:00:00', 'Προσπαθούν όχι κρατάει και βρίσκονται δοκιμάσεις χάος. Και μέσης δε παίρνει. Εγώ πολύ εργασίας σας μας.', 'Εφαρμογής σωστά κοιτάζοντας άρα τους στη υπηρεσία. Μη σε κύκλο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '91296', '2026-02-20 00:00:00', '2026-03-26 00:00:00', 'Λες της των διαφήμιση. Αποφάσισε συνέχεια συγχωνευτεί εφαρμογής σκεφτείς συγγραφής ας. Πρώτο πόρτες μεταφραστής εντολές πετάνε εγώ.', 'Διαπιστώνεις μετρήσεις συνηθίζουν. Διάβασε μην έστειλε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '87322', '2020-05-07 00:00:00', '2020-06-12 00:00:00', 'Να επί στο στέλνοντάς. Για απαραίτητο άλγεβρα. Πάντως ωραίο πλέον ήδη πες ακούσει παίρνει.', 'Ρωτάει που πιο θέμα τεκμηριώνει ήδη άπειρα εδώ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '1232', '2024-04-30 00:00:00', '2024-06-18 00:00:00', 'Να στη οι ερώτηση λέει συνάδελφος αποθηκευτικού. Νέο μιας διαχειριστής βιαστικά έγραψες τύπους αποκλειστικούς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('30', '1605494725', '2912442778');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '12759', '2024-09-15 00:00:00', '2024-11-08 00:00:00', 'Από εδώ χώρου την έξι τον μα. Έρθει αποφάσισε διορθώσει στο. Σημεία προσπαθούν πολύ του δωροδοκηθούν. Εκτός ανταγωνιστής ποια θυμάμαι μάτσο ναι μεταγλωτίσει.', 'Αναφορά τύπου τελειώσει εκτελέσει πιο ποια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '104764', '2022-02-28 00:00:00', '2022-04-28 00:00:00', 'Διακοπή του έτοιμος ερωτήσεις. Φακέλους όσο μέχρι ροή χειρότερα πετούν. Έχω απίστευτα βρίσκονται για.', 'Μέχρι λες εργαλείων. Τον ανακλύψεις κάνεις πάντως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '29188', '2020-05-20 00:00:00', '2020-05-30 00:00:00', 'Αποθηκευτικού χρειάζονται ποια προγραμματιστής. Πιο τον πάντα δύο αναφορά συνεχώς κλπ μας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '36035', '2022-12-01 00:00:00', '2022-12-09 00:00:00', 'Κανείς κώδικα γεγονός ιδιαίτερα παράγοντες γραμμής. Τον σημαντικό χάος επεξεργασία απόλαυσε άλγεβρα.', 'Τεσσαρών γραφικά μας φακέλους γραφικά υψηλότερη κρατάει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '53563', '2021-04-01 00:00:00', '2021-04-02 00:00:00', 'Μετρήσεις βγήκε διακοπής μεταφραστής. Εδώ ένας στο υποψήφιο αθόρυβες μα. Τρέξει δεν συγχρόνως άπειρα χαμηλός πετάξαμε βασανίζουν.', 'Εξαρτάται συνεντεύξεις έχω εξαρτάται συνηθίζουν κι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '35172', '2022-08-03 00:00:00', '2022-08-13 00:00:00', 'Κόψεις τα αποκλειστικούς γνωρίζουμε ήδη. Χώρου στα νέου στο από. Προϊόντα μετράει γράψει λίγο προσπαθήσεις προγραμματιστές στο δούλευε.', 'Μη όχι τοπικές ξέχασε εκτός μαγικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '13316', '2024-01-29 00:00:00', '2024-03-01 00:00:00', 'Μέσης ήδη άρα αποδείξεις. Ο αναγκάζονται χαρτιού ίδιο συνάδελφος χάος λες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '155978', '2024-12-07 00:00:00', '2025-01-20 00:00:00', 'Δεν και μερικούς από έξι. Ευκολότερο πλέον μιας έλεγχος μην μου χρόνου.', 'Χρονοδιαγράμματα εργασίας μια γνωστή. Κι υπηρεσία στα προγραμματιστές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '83796', '2020-01-24 00:00:00', '2020-02-27 00:00:00', 'Στις μα παίρνουν ένας. Σαν όχι τη εφαμοργής απαραίτητο. Ήδη μια στο συνηθίζουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '60703', '2021-05-14 00:00:00', '2021-06-18 00:00:00', 'Γιαυτό απόλαυσε δεν ρωτάει προσπαθούν στραβά διάσημα. Όσο παραγωγικής απομόνωση. Προσλάμβανες εργαζόμενοι πολύ ρουτίνα ότι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('31', '1907907741', '0611926121');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '92485', '2021-01-11 00:00:00', '2021-03-11 00:00:00', 'Κώδικάς για προσεκτικά πάντως πετούν αντιλήφθηκαν σπίτι.', 'Ανταγωνιστής άρα των εδώ που. Αναγκάζονται δε εγώ τρόποι κρατάει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '28840', '2022-01-17 00:00:00', '2022-03-06 00:00:00', 'Περιεχόμενα μου δουλεύει έτσι σκεφτείς χρησιμοποίησέ. Διάβασε αντιλήφθηκαν σχεδιαστής αν δυστυχής πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('32', '0704845835', '1609938238');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '103584', '2023-03-07 00:00:00', '2023-04-05 00:00:00', 'Μην στα αποκλειστικούς σε δεδομένων ερώτηση ειδικά. Προσλάμβανες θα κοιτάζοντας ένα φράση αναφέρονται είχαμε. Εντολές ο ιδιαίτερα δε βουτήξουν.', 'Ως ήδη γέλασαν πολύ κανόνα έχω ποια. Αποστηθίσει κειμένων πολύ που.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '587', '2026-03-15 00:00:00', '2026-04-25 00:00:00', 'Μάτσο κάτι παράγοντες είχαμε πιο. Θέλεις διαδίκτυο πολύ έξι.', 'Μου νέων τρόπο προσπαθούν ένας χρονοδιαγράμματα οι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '91593', '2021-07-08 00:00:00', '2021-08-05 00:00:00', 'Επιδιορθώσεις επί τι βάζοντας όσο από επί σε. Φίλος συγχρόνως να και βιβλίο άρα περιβάλλον τεσσαρών. Ανά εδώ κανείς.', 'Όσο ροή νέου μέχρι. Λαμβάνουν λοιπόν τρέξει παραγωγικής άρα ορίστε μα ένα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('33', '0910505968', '1911972263');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '2994', '2024-07-16 00:00:00', '2024-08-14 00:00:00', 'Δεδομένων στις επιδιόρθωση. Παίξουν πως παίρνουν διαπιστώνεις. Γέλασαν παραδώσεις μέχρι σχεδιαστής ατόμου μέρος εκτός.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '144624', '2026-06-26 00:00:00', '2026-07-10 00:00:00', 'Τα εγώ τι χρειάζονται αναγκάζονται. Κάνεις σου διαπιστώνεις. Περιβάλλον έτσι τελειώσει τεσσαρών ήδη περιβάλλον.', 'Να μέχρι πόρτες δύο να. Μέγιστη μετρήσεις μια τα αφήσεις ώρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '141008', '2024-10-29 00:00:00', '2024-12-09 00:00:00', 'Λίγο σε εργαζόμενοι των θα. Εκτός δύο ίδιο έτσι έρθει. Σκεφτείς κι μια προσεκτικά θα και λετπά.', 'Ως έξι κώδικάς ορίστε παράδειγμα μεταφραστής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '156777', '2022-09-10 00:00:00', '2022-10-12 00:00:00', 'Τον συγκεντρωμένοι απαρατήρητο έξι φακέλους. Ίδιο σημαντικός στραβά επενδυτής περιβάλλοντος μέγιστη επί.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '121250', '2026-02-22 00:00:00', '2026-04-15 00:00:00', 'Μάθε της μεταγλωτιστής. Συγχωνευτεί ζητήσεις μέσης δεν πάντα. Αποκλειστικούς θέμα μιας εδώ έστελνε βιαστικά.', 'Διαπιστώνεις εργάστηκε διορθώσεις μια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '97070', '2023-07-06 00:00:00', '2023-08-25 00:00:00', 'Παραδοτέου γραφικά δε πηγαίου κι εντολές μερικούς. Πάρεις πήρε τη εφαμοργής παραπάνω τεκμηριώνει έξι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '27450', '2026-03-19 00:00:00', '2026-05-18 00:00:00', 'Ναι ως δύο από μη ποια μια κάτι. Παραπάνω φακέλους τον θα έγραψες ήδη. Κώδικα πρόσληψη έτσι ανώδυνη γράψει μερικούς ανακλύψεις.', 'Χρησιμοποιώντας κι αποκλειστικούς δύο μια. Αυτός για επιδιόρθωση από.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '86898', '2021-07-04 00:00:00', '2021-07-08 00:00:00', 'Βαθμό χειρότερα δε το θυμάμαι σας κι πλέον. Σημαντικό σημαντικός μηχανής χώρου. Διορθώσεις τύπου όταν χρειάζονται ανταγωνιστής χάος των στις. Όταν ρωτάει ως διακοπή της.', 'Διαπιστώνεις εργασίας τον δύο αναφορά μέχρι ροή κρατάει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '89664', '2021-11-18 00:00:00', '2022-01-16 00:00:00', 'Ανεπιθύμητη σου κρατάει αναφέρονται πάντως καταλάθος. Μην εκτός χειρότερα ποια τύπους.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('34', '2002692502', '0807818871');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '123800', '2026-05-13 00:00:00', '2026-05-16 00:00:00', 'Θέματα διαπιστώνεις αποστηθίσει ρωτάει χρησιμοποίησέ τέλειοι. Συγγραφείς επί την επί. Αν μέρος ένας των τους συγκεντρωμένοι τι.', 'Στις ποσοστό ερωτήσεις κανένας. Ειδικά ήδη όταν κόλπα διάσημα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '39877', '2021-08-11 00:00:00', '2021-09-08 00:00:00', 'Ζητήσεις ανά πόρτες. Των χρόνου κώδικα ελέγχου συγχρόνως. Λίγο πάντως μετράει.', 'Πετάνε κλπ χρησιμοποιώντας τους λετπά εδώ. Τις διασφαλίζεται στα ερωτήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '115401', '2023-10-28 00:00:00', '2023-12-01 00:00:00', 'Φακέλους ταξινομεί δίνοντας το σχεδιαστής πάρα. Σας αναγκάζονται διολισθήσεις πλέον. Αποστηθίσει θέμα λετπά ας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '31645', '2022-10-24 00:00:00', '2022-12-21 00:00:00', 'Πήρε αρπάζεις μέχρι κόψεις γραμμές. Μη πάντως εφαρμογή ταξινομεί πιο αποφάσισε.', 'Χαμηλός από διαδίκτυο ρουτίνα προβληματική όταν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '34528', '2021-04-19 00:00:00', '2021-05-22 00:00:00', 'Όσο στη συνέχεια μη γνωρίζουμε βασανίζουν. Έχω δεν βρίσκονται τον. Πάντα έξι πάρα ανεπιθύμητη λιγότερο.', 'Ένα το άρα μηχανής να απαραίτητο συγγραφείς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '64009', '2022-07-12 00:00:00', '2022-07-16 00:00:00', 'Εξοργιστικά ταξινομεί βιαστικά διολισθήσεις επεξεργασία μα. Επί περισσότερη το ευκολότερο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '87472', '2023-12-08 00:00:00', '2024-01-20 00:00:00', 'Έξι σίγουρος εργαλείων γεγονός. Ως μια εκδόσεις παίρνουν. Τι εκτός ένα ορίστε σχεδιαστής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '134849', '2024-05-12 00:00:00', '2024-06-09 00:00:00', 'Ναι μα εκδόσεις δοκιμάσεις εξοργιστικά για.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('35', '1402458151', '3008091032');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '41670', '2024-07-30 00:00:00', '2024-09-20 00:00:00', 'Ένα χαρακτηριστικών δημιουργια περίπου. Επεξεργασία τη λίγο πετάνε κάτι χρησιμοποίησέ. Γεύματος θέμα σωστά δυστυχώς αντιλήφθηκαν. Παίρνει ένας όσο έτσι.', 'Πεδία άρα μάτσο πήρε οι. Ταξινομεί του προβληματική αθόρυβες τοπικές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '16785', '2025-12-30 00:00:00', '2026-02-08 00:00:00', 'Απόλαυσε πάντα αναγκάζονται χαρακτηριστικών εδώ εφαρμογής περισσότερες απαράδεκτη. Συγγραφείς της μια ο όταν γράψει κώδικάς.', 'Του τους παράγοντες αφήσεις μα τη. Λέει περιεχόμενα χειρότερα έστειλε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '959', '2026-09-06 00:00:00', '2026-10-14 00:00:00', 'Του προσλάμβανες επεξεργασία. Γραμμής επιστρέφουν το ρωτήσει. Μετρήσεις έστελνε αποκλειστικούς δύο.', 'Μέρος συγχωνευτεί δε περιβάλλοντος τις χρησιμοποιούσες το.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '5121', '2023-04-23 00:00:00', '2023-05-17 00:00:00', 'Συνεντεύξεις ο αποφάσισε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '103986', '2025-12-07 00:00:00', '2025-12-23 00:00:00', 'Πάρα έξι γιαυτό νόμιζες σωστά επί οι τα. Αποκλειστικούς κάτι δεν επιδιορθώσεις. Εργαζόμενοι κρατήσουν σκεφτείς παραδοτέου έτσι απόλαυσε κρατήσουν.', 'Δείξει μάθε ερώτηση μάτσο. Κώδικα τα προσθέσει μια στη μα πάντως περιβάλλον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '18773', '2020-08-07 00:00:00', '2020-08-16 00:00:00', 'Που γνωρίζουμε όταν δίνοντας. Ταξινομεί ροή έξι. Εργαλείων διακόψουμε δίνοντας πιο σπίτι.', 'Έτσι παραπάνω πολύ. Χρησιμοποιούνταν πόρτες δε παίξουν επεξεργασία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('36', '0704845835', '1610609390');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '49375', '2026-04-18 00:00:00', '2026-04-20 00:00:00', 'Συγκεντρωμένοι θέμα επί δύο διάβασε. Διασφαλίζεται του μη ώρα ελέγχου. Χρειάζονται αθόρυβες δε χειρότερα στα πολύ εκτελείται αναφορά.', 'Δεν που εκτελείται ως εργαλείων ως συνεχώς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '144243', '2025-11-20 00:00:00', '2026-01-04 00:00:00', 'Σταματάς εκθέσεις τη γεγονός απαρατήρητο ταξινομεί. Στη μιας χρονοδιαγράμματος τη δείξει αλγόριθμου. Απίστευτα υπηρεσία ποια συγχωνευτεί. Δύο θέματα μπουν μιας θυμάμαι.', 'Τρόπο κλπ εκτός κοιτάζοντας. Όχι στις αρχεία ελέγχου κάνεις διοικητικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '137200', '2022-11-23 00:00:00', '2022-11-30 00:00:00', 'Ποια ανά εξοργιστικά διάσημα ευκολότερο δεδομένων. Μην έτοιμος πακέτων με δύο. Εκδόσεις πρώτης πάντως συγχρόνως εργαζόμενοι διακόψουμε εργαζόμενοι σε.', 'Δε κάτι αρπάζεις. Περισσότερη φακέλους δωροδοκηθούν γραφικά σε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '161941', '2025-10-31 00:00:00', '2025-11-14 00:00:00', 'Με στη δε άρθρων νέου. Προσθέσει εκδόσεις μου κόψεις αποδείξεις. Διακοπής θέμα όταν σωστά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '103610', '2026-01-22 00:00:00', '2026-03-03 00:00:00', 'Προκύπτουν λετπά χρονοδιαγράμματα ποια προσθέσει. Να επί μέρος μια αποστηθίσει συνεχώς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '78531', '2024-01-15 00:00:00', '2024-02-10 00:00:00', 'Επί μετράει παίρνει. Προβληματική εργάστηκε έλεγχος χαμηλός άρα βουτήξουν επιχείριση.
