INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '99947', '2023-10-27 00:00:00', '2023-12-12 00:00:00', 'Πρώτο εργάστηκε ωραίο εγώ μια δεν πηγαίου. Πως χρησιμοποίησέ νιρβάνα προσοχή και.', 'Διολισθήσεις διορθώσει θέμα ζητήσεις όσο αναγκάζονται άτομο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '52558', '2024-12-08 00:00:00', '2025-02-04 00:00:00', 'Έξι έξι γραμμές περίπου συνεντεύξεις. Παραδοτέου για κι χρονοδιαγράμματος. Χρόνου προκαλείς περιμένουν σημαντικός τη γειτονιάς. Πάντα ως των κανόνα έρθει δημιουργήσεις.', 'Εργοστασίου ένας υψηλότερη κλπ. Περισσότερη δύο έρθει νέα ότι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '39103', '2021-02-01 00:00:00', '2021-03-06 00:00:00', 'Διάβασε πρώτο σημεία έξι ελέγχου για. Αρέσει στις απαρατήρητο πιο. Διακόψουμε μιας επιδιόρθωση πετάνε αρχεία.
