INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '117593', '2025-04-29 00:00:00', '2025-06-03 00:00:00', 'Προκαλείς περιμένουν τρέξει ήδη τεσσαρών μα πολύ.
