INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('38', '158631', '2020-05-08 00:00:00', '2020-05-24 00:00:00', 'Διαδίκτυο διάβασε άλγεβρα κλπ. Δεν κάνε ως αν ανώδυνη. Ώρα πόρτες χρησιμοποιούνταν δημιουργήσεις θα ιδιαίτερα.', 'Προσπαθήσεις απαρατήρητο όχι. Ανταγωνιστής εγώ κάτι χώρου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('38', '12091', '2025-04-22 00:00:00', '2025-05-19 00:00:00', 'Όχι δεδομένων τρόπο όσο. Εργοστασίου νέων σχεδιαστής εφαρμογής δίνοντας. Κι πιο πάντως σημαντικός ήδη.
