INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '128281', '2022-11-08 00:00:00', '2022-11-21 00:00:00', 'Εικόνες ρωτήσει ποια τα μεταγλωτίσει δε. Στραβά υόρκη κώδικα στήλες χάος με στήλες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '18072', '2025-11-10 00:00:00', '2026-01-03 00:00:00', 'Γεγονός χαμηλός δύο έχω πολύ επιδιόρθωση εξοργιστικά λετπά. Ύψος διασφαλίζεται περιβάλλοντος παραδοτέου. Κρατήσουν όχι μετράει νέων εκτελέσει έτσι μη.', 'Που πετούν φίλος κάνεις. Ας πετάνε από εργαζόμενοι μου.');
