INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '19595', '2024-12-06 00:00:00', '2025-01-18 00:00:00', 'Διορθώσεις εγώ άπειρα μέγιστη δούλευε όταν. Ερώτηση ανακλύψεις μα στις σημαντικό απόλαυσε εξακολουθεί σας.', 'Εφαρμογής σαν νέα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '68039', '2021-01-25 00:00:00', '2021-01-29 00:00:00', 'Τα στα ο στις γραμμής λες βάζοντας. Πάντως του χάος πάντα πιο στη ερώτηση. Μέρος με δείξει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '150377', '2020-08-31 00:00:00', '2020-10-26 00:00:00', 'Δημιουργείς ήδη ποια ακούσει χρονοδιαγράμματα πιο έξι. Χαρακτηριστικό του όσο αναγκάζονται που κάτι. Διολισθήσεις σωστά είχαμε επιδιορθώσεις αθόρυβες τι δωροδοκηθούν.', 'Διαφήμιση ποια μεταγλωτίσει ανά παράγοντες ανά πάντως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '79386', '2020-10-08 00:00:00', '2020-10-27 00:00:00', 'Απαράδεκτη εφαρμογή κρατάει τις ερώτηση.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('43', '1510425991', '1611432934');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '152763', '2026-07-12 00:00:00', '2026-07-19 00:00:00', 'Πάντα δεν χώρου δε περισσότερη κανένας ίδιο προκαλείς. Χρησιμοποιώντας δημιουργήσεις πολύ ατόμου βουτήξουν. Από παίξουν ας φακέλους. Σημαντικός νόμιζες του συνηθίζουν βιβλίο πρόσληψη.', 'Δεν πεδία εσωτερικών από ποια γιαυτό συγχρόνως. Εικόνες ίδιο αποφάσισε στο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '24556', '2024-02-26 00:00:00', '2024-03-03 00:00:00', 'Μια κάτι εκτελέσεις. Κάτι γραμμή ας εκθέσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '140061', '2022-12-29 00:00:00', '2023-01-31 00:00:00', 'Πιο της σπίτι απαραίτητο εδώ. Αναφέρονται τοπικές μας απλό περιμένουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '126412', '2026-04-18 00:00:00', '2026-05-20 00:00:00', 'Αγοράζοντας εκτός εκτελέσεις επί δεν βιαστικά. Σαν παράδειγμα άρα κειμένων έχω.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('44', '0501573361', '0807818871');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '62971', '2026-01-25 00:00:00', '2026-02-23 00:00:00', 'Με δυστυχώς κάτι συγκεντρωμένοι δε τρόποι. Εδώ κάνε ερωτήσεις απομόνωση ήδη ακούσει προσεκτικά.', 'Βασανίζουν προσπαθούν εγώ ένα. Πιο τι χώρου ως αρχεία έτοιμος εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '25235', '2024-03-08 00:00:00', '2024-03-24 00:00:00', 'Ύψος δεν παίξουν δυστυχής μέχρι μάλλον. Όσο σου χαρτιού εργαλείων μηχανής μάλλον.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '105519', '2022-06-17 00:00:00', '2022-08-01 00:00:00', 'Γνωρίζουμε κανείς εργαζόμενοι χρονοδιαγράμματος μέχρι συγχωνευτεί τις. Κώδικα πετάνε αλγόριθμου μέχρι στήλες. Σου διαπιστώνεις διορθώσει μια άλγεβρα κι δεν.', 'Δεν περισσότερη αν φακέλους ρουτίνα. Πετούν σωστά όχι δεν πιο τρόπο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '161612', '2023-10-29 00:00:00', '2023-11-23 00:00:00', 'Σχεδιαστής εγώ διολισθήσεις ένα στέλνοντάς αρχεία. Διαφήμιση κρατήσουν άρα διορθώσεις μα τους εξαρτάται. Σχεδιαστής ώρα απαραίτητο κανόνα πρώτο από. Και που απομόνωση ρωτήσει νέου ανώδυνη στις.', 'Με πακέτων τρόποι του απαρατήρητο βασανίζουν ρουτίνα πρόσληψη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '304', '2025-11-09 00:00:00', '2025-11-22 00:00:00', 'Από συνέχεια πηγαίου θα για τέλειοι δυστυχώς άπειρα. Κόλπα τρέξει χρησιμοποιούνταν. Βγήκε κανένας κάτι κι προκαλείς μετράει πάντα.', 'Τέλειοι ίδιο έχω γεγονός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '45644', '2026-01-07 00:00:00', '2026-01-12 00:00:00', 'Έγραψες έστειλε ανά αρχεία. Πάρα παραπάνω έστειλε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '118475', '2021-12-22 00:00:00', '2022-02-04 00:00:00', 'Νιρβάνα παραπάνω διαχειριστής απαράδεκτη τρέξει. Μην γεύματος γέλασαν πλέον ανά.', 'Προσεκτικά χρόνου εργοστασίου εκείνου διαπιστώνεις. Σε δύο δε άρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('45', '1307652974', '2607821289');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '32263', '2025-04-28 00:00:00', '2025-06-19 00:00:00', 'Απομόνωση πετούν χαρακτηριστικό υόρκη διαφήμιση. Απίστευτα τύπους φακέλους σε. Με άρα ανακλύψεις μερικούς από ατόμου νέων προγραμματιστής. Πάντως της άρα παράδειγμα άπειρα.', 'Σημαντικός μια πάντως διαπιστώνεις. Ποια τεκμηριώνει στο διαδίκτυο ίδιο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '59153', '2020-09-26 00:00:00', '2020-11-07 00:00:00', 'Κι ίδιο μέχρι ευκολότερο τελειώσει πετάνε σε αθόρυβες. Γειτονιάς τύπου κάνε βρίσκονται.', 'Μη κανένας πρώτοι γράψει εκτελέσει σταματάς απόλαυσε. Εκτός να δημιουργείς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '27465', '2024-06-12 00:00:00', '2024-07-25 00:00:00', 'Ώρα μηχανής πλέον εργάστηκε θέμα ας. Μετράει τα μα σχεδιαστής δε το έλεγχος.', 'Επεξεργασία εφαρμογής σταματάς σας τα εγώ ελέγχου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '119989', '2022-08-20 00:00:00', '2022-09-08 00:00:00', 'Έτοιμος ώρα εγώ υποψήφιο στο. Παραδώσεις έγραψες γραμμές διαφήμιση.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '104595', '2021-01-09 00:00:00', '2021-02-21 00:00:00', 'Νέων εικόνες μηχανής περίπου αφήσεις μη άρα συγκεντρωμένοι. Εντολές έρθει χρησιμοποιώντας των υποψήφιο.', 'Πιο δεν χαμηλός για διακοπής. Γέλασαν χαμηλός ποια ερώτηση μεταγλωτιστής έξι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '24842', '2023-05-07 00:00:00', '2023-05-21 00:00:00', 'Για βουτήξουν που πλέον αυτήν. Διακοπή νόμιζες μαγικά έχω έτοιμος μιας.
