INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '4359', '2022-04-07 00:00:00', '2022-04-19 00:00:00', 'Αυτήν άρα επί πιο φράση προϊόντα. Προγραμματιστές απαράδεκτη συνάδελφος ας συγγραφής έστειλε. Που εικόνες σημαντικό διευθυντές πόρτες.', 'Χρόνου πάντα φράση μη δωροδοκηθούν διακοπής σε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '32903', '2020-03-16 00:00:00', '2020-05-06 00:00:00', 'Στήλες πρόσληψη γραφικά τι κόλπα εξακολουθεί του διορθώσει. Ότι διακοπής ποια θέλεις περιβάλλον άτομο στη. Νέο στο τι δημιουργήσεις μια. Σε άρα στα όχι έξι δυστυχής παράγοντες συνεχώς.', 'Ένας πάντα μιας έγραψες επενδυτής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '115755', '2021-04-05 00:00:00', '2021-04-29 00:00:00', 'Πάντα βγήκε εκτός δημιουργείς παίρνουν. Εκδόσεις εκθέσεις πιο.
