INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '94392', '2024-11-20 00:00:00', '2024-12-19 00:00:00', 'Εδώ υποψήφιο φαινόμενο θα πρώτης. Όσο στα ποια στέλνοντάς ποια.
