INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('47', '5308', '2026-12-12 00:00:00', '2027-01-13 00:00:00', 'Μεταγλωτιστής μου παράδειγμα πάντα απόλαυσε εγώ. Ύψος τη υπηρεσία.', 'Τεσσαρών το δημιουργήσεις τρόποι στραβά νέων από.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('47', '112554', '2020-08-17 00:00:00', '2020-09-19 00:00:00', 'Μέρος όχι όταν στραβά δε τεσσαρών. Γεύματος ημέρα και γνωστή το γεγονός.', 'Τύπους παίρνουν μετράει βουτήξουν. Τρόποι επί κόλπα διαπιστώνεις διάβασε σου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('48', '1606420374', '0701029250');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '132589', '2020-09-11 00:00:00', '2020-10-12 00:00:00', 'Χαρτιού βιβλίο θέλεις τα τον σωστά μη. Διάσημα ναι εγώ σας. Απλό πρόσληψη φράση έγραψες.', 'Επενδυτής πρώτοι βγήκε βάζοντας χρησιμοποιούσες. Δουλεύει σίγουρος μην.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '7519', '2024-09-07 00:00:00', '2024-10-24 00:00:00', 'Υψηλότερη υπηρεσία μηχανής δωροδοκηθούν κοιτάζοντας υποψήφιο. Ναι βάζοντας σπίτι προσοχή γεύματος απομόνωση παίξουν τρέξει.', 'Εφαρμογής του κανένας άρα. Μπορούσες παίρνουν ρωτάει όταν διολισθήσεις πιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('49', '0709484565', '1207212405');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '23449', '2024-06-29 00:00:00', '2024-07-25 00:00:00', 'Δωροδοκηθούν γράψει χρησιμοποιούνταν διαπιστώνεις λέει. Προσπαθήσεις ρωτήσει πολύ ότι μιας αναγκάζονται. Βασανίζουν σημαντικό και προσλάμβανες την.', 'Περίπου το εδώ δύο παραπάνω.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '104023', '2021-02-09 00:00:00', '2021-02-28 00:00:00', 'Κώδικα τι τις φίλος εξακολουθεί. Επιχείριση τους όσο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '19595', '2021-03-21 00:00:00', '2021-04-22 00:00:00', 'Απαράδεκτη με μην δε γεύματος. Της προσπαθούν χρονοδιαγράμματος χρησιμοποιούνταν διακόψουμε. Λέει κάνεις από πετάνε διοικητικό.', 'Τελειώσει κανένας δύο έρθει νόμιζες εδώ θυμάμαι καταλάθος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '87559', '2023-09-03 00:00:00', '2023-10-01 00:00:00', 'Νόμιζες απαραίτητο όσο εκτός ορίστε. Δοκιμάσεις δύο αποκλειστικούς ένα απόλαυσε τέλειοι. Επεξεργασία σημαντικό περισσότερες κρατήσουν.', 'Στραβά τον ήδη συγγραφής. Κάτι ταξινομεί νόμιζες βαθμό δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('50', '0111720422', '2208902248');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('50', '114436', '2026-05-15 00:00:00', '2026-05-16 00:00:00', 'Νέο μάθε ανταγωνιστής. Βιαστικά διακοπής κάτι ίδιο μια αποφάσισε όχι χρονοδιαγράμματα. Αν πηγαίου προβληματική χάος ποια μια.', 'Προσπαθούν άπειρα παίξουν φαινόμενο ώρα ρουτίνα από όσο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('51', '0704845835', '1308581648');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '73756', '2022-09-13 00:00:00', '2022-09-25 00:00:00', 'Έξι ένας απαρατήρητο παίρνουν κάνεις δε ζητήσεις. Εδώ αποδείξεις ανά των του τους. Αθόρυβες των λιγότερο να στα χάος. Παραδώσεις έχω εκδόσεις του εντολές άτομο ότι από.', 'Όσο ποσοστό χάος τι. Ροή των νέα χαρτιού.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '99190', '2025-11-29 00:00:00', '2026-01-18 00:00:00', 'Νέα κάνεις μέσης γραμμές με δεν θα. Ατόμου ο τον διαφήμιση.', 'Διασφαλίζεται διακοπή περισσότερες άτομο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '12256', '2022-02-26 00:00:00', '2022-03-11 00:00:00', 'Χρησιμοποίησέ μεταγλωτίσει πολύ ευκολότερο χρησιμοποίησέ. Πως μη δυστυχής εγώ σχεδιαστής το πολύ.', 'Σπίτι χρησιμοποιώντας στα πάντα πάντα χρησιμοποιώντας δυστυχής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '133824', '2025-10-15 00:00:00', '2025-12-12 00:00:00', 'Γεύματος κι προσπαθούν στα δημιουργια νέου. Πόρτες ένας εκτελέσει ήδη πακέτων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('52', '0709484565', '2212052479');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('52', '110458', '2020-09-14 00:00:00', '2020-09-27 00:00:00', 'Από σου συνηθίζουν. Τα πλέον εργασίας άρθρων συγκεντρωμένοι μετράει το δυστυχής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('52', '30471', '2026-11-23 00:00:00', '2026-12-29 00:00:00', 'Επί εκτελέσει χρησιμοποίησέ κλπ άτομο στη. Αντιλήφθηκαν χρόνου οι νέων στραβά κόψεις. Ανά πως ανώδυνη.
