INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('54', '1605494725', '1611033036');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '43137', '2026-09-14 00:00:00', '2026-10-04 00:00:00', 'Αποστηθίσει μετράει οι τη. Μπουν περιβάλλοντος δυστυχώς των μέχρι. Άρθρων νέου μέσης διασφαλίζεται πάντως κάτι.', 'Σταματάς τους δείξει και επί για άρθρων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '140291', '2025-11-19 00:00:00', '2025-12-22 00:00:00', 'Κανένας επιδιόρθωση ημέρα. Επιδιόρθωση δωροδοκηθούν τις όταν πρόσληψη. Παραδώσεις γειτονιάς συγχρόνως επιστρέφουν τα απόλαυσε.', 'Πιο διάβασε χαρακτηριστικό σπίτι ιδιαίτερα. Μετράει θυμάμαι ποσοστό τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '80747', '2021-03-07 00:00:00', '2021-03-30 00:00:00', 'Ανακλύψεις τύπου ότι εκτελείται τι τις μέσης. Εγώ στις πετάνε κάτι φαινόμενο έχω.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '68750', '2026-10-02 00:00:00', '2026-11-24 00:00:00', 'Έξι μου πες στέλνοντάς μας στα αναφέρονται. Τι προσθέσει πετάξαμε πάντα εσωτερικών παίρνει μέχρι.', 'Αποδείξεις ρωτάει σημαντικός ώρα τοπικές λαμβάνουν τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '110386', '2021-01-09 00:00:00', '2021-01-15 00:00:00', 'Παίξουν επιδιορθώσεις υπηρεσία απαρατήρητο δείξει κανόνα. Νέο μιας περιμένουν υπηρεσία όσο.', 'Παραπάνω μεταφραστής περιβάλλον συνάδελφος. Ναι σου πρόσληψη μέχρι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('55', '2810810239', '1509104877');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '21067', '2022-03-04 00:00:00', '2022-03-17 00:00:00', 'Βουτήξουν εκείνου σχεδιαστής. Πλέον ήδη εδώ μπουν εργαζόμενων νέων αποδείξεις. Παίρνουν ότι στα αποστηθίσει τον εκτελείται.', 'Άρθρων ένα τύπους επεξεργασία κειμένων. Πιο χρονοδιαγράμματος φίλος τι με τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '90761', '2025-04-09 00:00:00', '2025-04-20 00:00:00', 'Για βρίσκονται συγκεντρωμένοι αποστηθίσει άρθρων. Κλπ κύκλο έστελνε όσο μη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '96113', '2024-08-24 00:00:00', '2024-09-19 00:00:00', 'Πάντα ποσοστό δωροδοκηθούν κειμένων. Πως συνηθίζουν να ειδικά. Δοκιμάσεις διακοπή σημεία άρα πάντως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '131022', '2020-04-05 00:00:00', '2020-04-12 00:00:00', 'Κώδικάς κρατάει με λαμβάνουν έτοιμος έχω. Ορίστε εγώ περιβάλλοντος μη εκτός κανόνα προσπαθούν. Έστελνε άτομο πες.
