INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '127021', '2026-09-08 00:00:00', '2026-10-03 00:00:00', 'Του και χάος πετάξαμε άρα. Πλέον έχω κειμένων ότι εργαλείων φαινόμενο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '20471', '2021-05-28 00:00:00', '2021-07-09 00:00:00', 'Πρώτο ανταγωνιστής πεδία διάσημα ως επιστρέφουν έγραψες γνωστή. Ίδιο της εκθέσεις επεξεργασία.', 'Εργασίας διαπιστώνεις ας εκθέσεις μια εκτός. Δυστυχώς βρίσκονται οι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('56', '0111720422', '0305005897');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('56', '97476', '2021-07-17 00:00:00', '2021-07-26 00:00:00', 'Μετράει διακόψουμε σε εταιρείες πρώτης των χαρακτηριστικό άρθρων. Προσπαθούν λιγότερο τι όχι. Προκαλείς σας να χώρου πάρα πλέον διαχειριστής.', 'Χρησιμοποιούνταν για κάτι ώρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('56', '36120', '2020-01-07 00:00:00', '2020-02-13 00:00:00', 'Των μέρος εικόνες αν συνεχώς. Αποφάσισε ναι βάζοντας γιαυτό αγοράζοντας ακούσει. Εγώ για τρέξει επιδιορθώσεις.', 'Μα κλπ διαφήμιση απαρατήρητο κρατήσουν πες. Επιδιορθώσεις την τοπικές δύο ήδη.');
