INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('57', '99348', '2023-12-20 00:00:00', '2023-12-23 00:00:00', 'Ανώδυνη δύο διακοπή στο. Κώδικάς δείξει ώρα προγραμματιστής εντολές συνέχεια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('58', '1806613730', '1808698754');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '93403', '2026-11-12 00:00:00', '2026-12-20 00:00:00', 'Αντιλήφθηκαν ως ίδιο πάντως παίρνουν κύκλο τους. Ρωτάει χρόνου ημέρα εφαρμογής είχαμε στις συνέχεια. Προκαλείς έστειλε γνωρίζουμε πλέον παραδοτέου αποκλειστικούς.', 'Δύο σου δείξει.');
