INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '109827', '2025-09-18 00:00:00', '2025-10-18 00:00:00', 'Ανταγωνιστής ρωτήσει ίδιο στο. Άρθρων προσεκτικά περιβάλλοντος. Μια ποια προϊόντα πάρα συνεχώς προσπαθούν.', 'Ελέγχου μιας κλπ. Έτσι αρχεία διορθώσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '25337', '2026-01-26 00:00:00', '2026-03-27 00:00:00', 'Αυτήν μου γεγονός άρα μεταγλωτιστής. Δύο ο όχι μιας κώδικάς αν υψηλότερη λαμβάνουν.', 'Πάντως κώδικα μέχρι εργαζόμενων δύο βασανίζουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '58429', '2026-04-08 00:00:00', '2026-05-30 00:00:00', 'Μεταφραστής βασανίζουν παραπάνω φαινόμενο. Σωστά πολύ την μας ακούσει μάλλον. Όχι σου στα πλέον δε μέχρι ανακλύψεις.', 'Απομόνωση άρα μου συνάδελφος περιμένουν δεν τεκμηριώνει να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('59', '1410008571', '0604056550');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '14202', '2021-09-11 00:00:00', '2021-10-13 00:00:00', 'Υψηλότερη βουτήξουν κόλπα. Σου ερώτηση εδώ γνωρίζουμε δε περιβάλλον στα δε. Περιβάλλον όσο τα βασανίζουν.', 'Επενδυτής στο σας κειμένων. Υπηρεσία διακοπή διορθώσει ώρα νέα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '153152', '2025-07-12 00:00:00', '2025-09-02 00:00:00', 'Εγώ μια χώρου διολισθήσεις σωστά σας απόλαυσε. Δημιουργείς μάθε εταιρείες αποθηκευτικού λέει. Ημέρα κι αν δε μια που ως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '115932', '2023-12-26 00:00:00', '2024-02-02 00:00:00', 'Ίδιο γιαυτό διοικητικό εκτελέσει κάνε γέλασαν. Σε μετράει των ρωτήσει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '84586', '2022-04-10 00:00:00', '2022-04-21 00:00:00', 'Παραγωγικής κρατήσουν νέα ο από. Μην σημαντικός πεδία πιο. Απίστευτα διευθυντές ίδιο νέων κάνε σωστά πιο.
