INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '149862', '2022-03-21 00:00:00', '2022-05-08 00:00:00', 'Το διευθυντές κύκλο σημαντικό δίνοντας εταιρείες ήδη πάντα. Αφήσεις σαν κάτι παραγωγικής. Άρα καλύτερο μετράει σε χρησιμοποίησέ.', 'Πετάνε αναγκάζονται και γνωρίζουμε περιβάλλοντος συγγραφείς πεδία νέων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '115899', '2020-11-18 00:00:00', '2020-11-27 00:00:00', 'Στραβά έτσι παραπάνω χρονοδιαγράμματα μέγιστη τους εργαλείων ως. Λες πολύ ημέρα μας ειδικά βουτήξουν.', 'Φράση γραμμή μέχρι. Έστελνε χειρότερα μια σου θυμάμαι σου χώρου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '155684', '2021-04-25 00:00:00', '2021-06-19 00:00:00', 'Εξαρτάται την ο ανά. Προϊόντα αποστηθίσει ημέρα ανεπιθύμητη χαρακτηριστικών μερικούς νέων μέσης.', 'Τύπου μάτσο εκτελέσει που εκδόσεις για. Εγώ μου έτσι μα διακοπής ίδιο.');
