INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '63154', '2021-09-09 00:00:00', '2021-09-11 00:00:00', 'Έξι ίδιο έχω λέει φίλος επιδιορθώσεις υποψήφιο. Προσπαθούν έχω έχω. Άρθρων ποσοστό βγήκε θέλεις πετάνε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '7896', '2024-03-07 00:00:00', '2024-03-20 00:00:00', 'Ταξινομεί μπορούσες γέλασαν πακέτων παράγοντες νόμιζες. Έχω στραβά όχι έχω.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '30298', '2020-12-13 00:00:00', '2021-02-08 00:00:00', 'Πάντα έχω ξέχασε υποψήφιο τύπου πολύ. Σχεδιαστής δημιουργήσεις διορθώσει πάντα όχι του διοικητικό.', 'Κανείς πάντα κόλπα και έτσι. Πάντως σας ξέχασε όσο διακοπής εφαρμογής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '38010', '2020-03-12 00:00:00', '2020-03-27 00:00:00', 'Προσθέσει ήδη στις σίγουρος πρόσληψη. Εντολές ανακλύψεις δυστυχώς επιδιορθώσεις.', 'Διασφαλίζεται πάντα ειδικά δύο αφήσεις θέμα στα δοκιμάσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '30035', '2021-09-19 00:00:00', '2021-11-10 00:00:00', 'Μη ταξινομεί έλεγχος φράση πιο. Άρθρων ίδιο τα παραδώσεις των ημέρα κι ευκολότερο. Νέα πλέον έτσι ίδιο εκτός.', 'Αρέσει που λέει μπουν. Δύο μαγικά παίρνει κλπ συγγραφείς εξαρτάται δεν σου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '105469', '2021-02-12 00:00:00', '2021-04-13 00:00:00', 'Οι προσθέσει των μάθε συνεχώς. Έξι ροή μα ήδη το μπορούσες χαρακτηριστικό επενδυτής. Τον ρωτήσει εργάστηκε χώρου κόλπα κόλπα. Φαινόμενο τύπου πρώτοι φίλος μαγικά.', 'Τη μου στα πάντα εταιρείες. Συνηθίζουν κλπ κώδικα μην απαρατήρητο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '83515', '2024-05-10 00:00:00', '2024-06-28 00:00:00', 'Γεγονός έτοιμος δημιουργήσεις με νέα διορθώσει γραφικά. Χρησιμοποιώντας διασφαλίζεται πιο αναγκάζονται φαινόμενο εφαρμογή.', 'Συγγραφής νέων δεν τη προσεκτικά. Τύπου φαινόμενο μας άπειρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '143226', '2025-05-08 00:00:00', '2025-05-10 00:00:00', 'Κώδικάς σας τρόποι κανόνα σκεφτείς προϊόντα κι. Τα έρθει στο έτοιμος.
