INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '129197', '2024-09-20 00:00:00', '2024-10-29 00:00:00', 'Έχω τεκμηριώνει απαρατήρητο περισσότερη θα. Ότι προκύπτουν μερικούς ανταγωνιστής μιας δουλεύει ακούσει. Ύψος ανά πάρεις γράψει.', 'Άπειρα ανακλύψεις ανταγωνιστής εκθέσεις αθόρυβες επεξεργασία μας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '158484', '2024-07-29 00:00:00', '2024-09-03 00:00:00', 'Τέλειοι λοιπόν ναι ένας πάντως τους στις. Σταματάς αποθηκευτικού μάτσο για. Δύο θέμα δεν φίλος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '82344', '2026-10-09 00:00:00', '2026-12-06 00:00:00', 'Μην μας ίδιο χρησιμοποιώντας στα πηγαίου. Για ναι ειδικά μέχρι τους βασανίζουν. Ο απίστευτα διορθώσει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '140566', '2025-10-10 00:00:00', '2025-10-14 00:00:00', 'Αλγόριθμου δωροδοκηθούν ο σκεφτείς αντιλήφθηκαν όσο μια. Για διάσημα λέει αποθηκευτικού υπηρεσία πετάνε πλέον αλγόριθμου.', 'Οι πλέον διαφήμιση ημέρα ως μα γραμμής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '66679', '2021-01-11 00:00:00', '2021-01-20 00:00:00', 'Αποστηθίσει ανταγωνιστής δε παίρνει ένα που. Προγραμματιστής δοκιμάσεις χαμηλός ύψος συνέχεια κλπ.', 'Μέχρι πακέτων κειμένων κι προσοχή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '28739', '2026-05-11 00:00:00', '2026-06-20 00:00:00', 'Υόρκη του θα. Επί ξέχασε πάντως βγήκε ποια παράγοντες κλπ. Διαφήμιση τρόπο τους. Ρωτάει ποια προσοχή κάτι χρειάζονται.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '148935', '2020-04-28 00:00:00', '2020-05-17 00:00:00', 'Κάνεις με εξοργιστικά διοικητικό ποια ίδιο. Πρώτο αποφάσισε μα τεκμηριώνει πρόσληψη πετάξαμε. Τις εκτός έτοιμος ορίστε μάλλον γραφικά.', 'Δύο δεν εξαρτάται ανώδυνη ανακλύψεις στις χρησιμοποιούσες μια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '43538', '2026-10-20 00:00:00', '2026-10-31 00:00:00', 'Εικόνες εφαμοργής γράψει χρόνου. Πόρτες χειρότερα όχι το μην δωροδοκηθούν τρέξει. Χάος ένας τρόπο πρόσληψη έστελνε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '132216', '2025-09-30 00:00:00', '2025-10-14 00:00:00', 'Ποσοστό σας μάθε στις εγώ δύο. Σε κι εφαρμογή περισσότερη δύο θα συνηθίζουν. Μου οι έχω κι.', 'Ανεπιθύμητη έχω δυστυχώς χώρου. Τις κάτι ίδιο πάντως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '84458', '2020-06-26 00:00:00', '2020-07-16 00:00:00', 'Συγχωνευτεί ο βαθμό που απλό πάντα ίδιο. Αναφέρονται ο ώρα ίδιο.', 'Παραγωγικής πάντα τρόποι ως πεδία ναι συγγραφής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('63', '2510976713', '0307997994');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('63', '104141', '2024-04-09 00:00:00', '2024-05-29 00:00:00', 'Σε πάντως κοιτάζοντας αποστηθίσει ρωτάει. Αφήσεις σε χειρότερα μέρος δημιουργήσεις έστειλε δείξει. Χρησιμοποίησέ τοπικές τρέξει ώρα ας απομόνωση. Τεσσαρών ρωτάει να άτομο κάνεις.', 'Ποσοστό έξι σου όταν πάρα. Έτοιμος νέου μην δεδομένων προσοχή παίρνει μπουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('63', '129996', '2021-05-02 00:00:00', '2021-06-15 00:00:00', 'Μέγιστη προκύπτουν περισσότερες πλέον σου θα εκτός δωροδοκηθούν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('64', '1208984016', '2801400141');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('64', '94641', '2026-09-12 00:00:00', '2026-11-10 00:00:00', 'Μέχρι άρα σημαντικό διοικητικό ζητήσεις μέχρι άπειρα το. Δεν στήλες μην σαν τύπους του δεν. Αφήσεις εξαρτάται δεδομένων εργάστηκε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('65', '2706990667', '1808698754');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '141705', '2022-10-28 00:00:00', '2022-11-21 00:00:00', 'Και όταν εξαρτάται άτομο διοικητικό. Χαρτιού εργάστηκε σε επί μετρήσεις δημιουργια εκθέσεις εργαλείων.', 'Σημεία πάρεις μη πηγαίου πλέον μετράει βάζοντας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '8343', '2025-12-06 00:00:00', '2026-01-03 00:00:00', 'Τελειώσει συγγραφείς εταιρείες άλγεβρα χάος νέο πακέτων. Έτοιμος το διευθυντές θέλεις κανόνα κρατάει ανώδυνη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '93567', '2023-12-24 00:00:00', '2024-02-06 00:00:00', 'Μεταγλωτίσει νέων λοιπόν ώρα φαινόμενο από κανείς. Όσο σας δεν πάντως προκαλείς σημαντικός.', 'Επενδυτής συνεντεύξεις κλπ παραπάνω παραπάνω κι νόμιζες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '88785', '2024-04-21 00:00:00', '2024-06-20 00:00:00', 'Περιμένουν εγώ τα. Βρίσκονται τι θα επενδυτής προσλάμβανες μέχρι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '28659', '2022-09-15 00:00:00', '2022-11-03 00:00:00', 'Κειμένων με μηχανής φράση δε περισσότερες χρονοδιαγράμματα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '35657', '2022-05-14 00:00:00', '2022-06-03 00:00:00', 'Κανόνα λίγο πλέον προβληματική ροή. Έστελνε βιβλίο συγγραφείς ανά έστελνε. Μπορούσες θέματα μάλλον πρώτοι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '106166', '2025-02-20 00:00:00', '2025-04-19 00:00:00', 'Όσο αναγκάζονται λίγο κύκλο νέο σου ήδη. Κόλπα προσοχή δεν διοικητικό την εδώ των. Περιεχόμενα τι συγγραφείς.', 'Στις θα εφαμοργής αλγόριθμου συνεντεύξεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('66', '2701818499', '1309192053');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '30504', '2022-01-05 00:00:00', '2022-01-24 00:00:00', 'Της κώδικα εφαμοργής όχι περιβάλλον περιμένουν. Περιβάλλον έτσι έρθει κάτι περιεχόμενα δε προσοχή. Μέχρι διαχειριστής διαφήμιση εταιρείες καταλάθος.', 'Επιστρέφουν μην πολύ αποθηκευτικού. Έτοιμος αντιλήφθηκαν σας πάρα γειτονιάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '159839', '2023-07-06 00:00:00', '2023-07-27 00:00:00', 'Πάντα οι στις έξι δε πετάξαμε. Πλέον στέλνοντάς κάτι μερικούς πηγαίου εφαρμογής. Διοικητικό βασανίζουν διάσημα τις στο με.', 'Διακοπής ανώδυνη υποψήφιο τρόπο αρπάζεις πως στο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '70877', '2020-09-25 00:00:00', '2020-11-04 00:00:00', 'Ένας πάντως άλγεβρα αποκλειστικούς δωροδοκηθούν.', 'Προσπαθήσεις νέο εξοργιστικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '157605', '2023-12-08 00:00:00', '2024-01-21 00:00:00', 'Εγώ διαφήμιση δίνοντας προσεκτικά διοικητικό εργαζόμενοι αυτός διακοπή. Μας φίλος εφαμοργής τα. Πρόσληψη εργοστασίου πάντως.', 'Ποια παίρνουν πρόσληψη βγήκε απομόνωση έχω. Κάτι κάνεις ίδιο επιχείριση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '47846', '2025-11-24 00:00:00', '2025-12-19 00:00:00', 'Το βαθμό είχαμε ανεπιθύμητη. Πλέον εκτός παίρνει σημεία συνηθίζουν τι. Ο κώδικάς πεδία διαφήμιση εκτός κι μηχανής νέων.', 'Λοιπόν την μάτσο πηγαίου. Βιαστικά ένα ότι ερώτηση δύο μέρος εκτελέσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '66183', '2020-12-16 00:00:00', '2021-01-13 00:00:00', 'Λιγότερο μεταφραστής διάσημα. Ήδη νέων με θέματα μάτσο. Τον πρόσληψη μέχρι. Πάντως κώδικα σε μέχρι τοπικές.', 'Σωστά ελέγχου πρώτης μιας πετούν. Ρωτήσει μέχρι παίρνουν επί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '98797', '2023-05-19 00:00:00', '2023-05-24 00:00:00', 'Ένας εφαμοργής προσπαθούν αναφέρονται νέων προσπαθούν. Έτοιμος προβληματική μεταγλωτιστής παραδοτέου σταματάς. Δεν δημιουργείς επεξεργασία στέλνοντάς γνωστή υπηρεσία.', 'Σίγουρος ανώδυνη χάος περισσότερες. Αποθηκευτικού πιο συνεντεύξεις την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('67', '2310644379', '2610022908');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '118593', '2022-02-01 00:00:00', '2022-03-28 00:00:00', 'Διαχειριστής πες άλγεβρα γνωστή. Στέλνοντάς κανένας γραμμή όταν πως της.', 'Μιας των πες πολύ γραμμές κι του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '4789', '2024-10-02 00:00:00', '2024-11-11 00:00:00', 'Δίνοντας έξι κρατήσουν φακέλους διολισθήσεις νέα αρπάζεις. Θυμάμαι δημιουργείς συνεντεύξεις. Αποκλειστικούς πάντως διακοπή νέα χρονοδιαγράμματα έστειλε εκθέσεις ευκολότερο.', 'Μου ένας χαμηλός μάτσο εξαρτάται πόρτες. Όταν προσλάμβανες ερώτηση τα κανόνα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '113700', '2022-06-16 00:00:00', '2022-06-20 00:00:00', 'Σημαντικό επιδιορθώσεις παραδώσεις τον δωροδοκηθούν επιχείριση. Μερικούς ένα όσο τεκμηριώνει αρχεία εργάστηκε σου. Ίδιο μην νιρβάνα γιαυτό μέχρι.', 'Υποψήφιο ζητήσεις εδώ συνεντεύξεις που έχω χαρακτηριστικών.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '47488', '2021-04-02 00:00:00', '2021-04-04 00:00:00', 'Διολισθήσεις μέσης πλέον το. Χρησιμοποιούνταν το δοκιμάσεις ίδιο απομόνωση.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '78126', '2024-10-12 00:00:00', '2024-11-16 00:00:00', 'Εφαρμογής ένας αναγκάζονται δε εδώ χρησιμοποιούσες ένα. Παίξουν τέλειοι εγώ προϊόντα μου μάθε προκαλείς. Μπουν θα περιμένουν κύκλο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '128757', '2025-09-30 00:00:00', '2025-11-26 00:00:00', 'Μην σχεδιαστής σου γραφικά κώδικάς σας μάλλον πρώτης. Θέματα μέσης χρησιμοποιούνταν εξακολουθεί. Πεδία ειδικά νιρβάνα κόψεις πεδία χαρακτηριστικών.', 'Έλεγχος μαγικά μου αποστηθίσει δεν αυτήν μιας. Του ειδικά σε έστελνε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('68', '0405687081', '0406811293');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '89452', '2021-01-16 00:00:00', '2021-02-26 00:00:00', 'Δε μα δεν σκεφτείς απόλαυσε γραμμής στη. Κι σαν προκαλείς μέχρι λοιπόν και βγήκε λαμβάνουν.', 'Στις περιβάλλον στη λοιπόν πιο ώρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '129574', '2023-07-11 00:00:00', '2023-07-12 00:00:00', 'Όταν ως έξι σίγουρος. Αγοράζοντας σωστά θυμάμαι προσοχή θυμάμαι μέγιστη. Πιο που διακοπής εδώ.', 'Έτσι για συγγραφής στα εργαζόμενων. Οι ναι δωροδοκηθούν νέο πως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '98917', '2025-01-27 00:00:00', '2025-03-27 00:00:00', 'Ρωτάει απαραίτητο χρησιμοποιούσες γνωστή. Περιβάλλοντος διολισθήσεις εκτελέσει προσπαθούν χρόνου στο. Μην εικόνες εργαλείων χαρακτηριστικών.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '99874', '2022-05-30 00:00:00', '2022-06-16 00:00:00', 'Λοιπόν ήδη μάτσο χαρτιού σκεφτείς. Στήλες περίπου μέγιστη έτσι κάτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '79775', '2020-05-02 00:00:00', '2020-06-04 00:00:00', 'Ωραίο δυστυχώς απομόνωση σημεία χρονοδιαγράμματα ύψος. Για κανόνα εργοστασίου από απίστευτα κοιτάζοντας.', 'Ότι αφήσεις κάτι. Συνεντεύξεις έχω βασανίζουν ώρα εργάστηκε στραβά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '12915', '2025-05-22 00:00:00', '2025-07-10 00:00:00', 'Μην για λέει ότι βιαστικά έστελνε μια. Το έτοιμος εφαρμογής τέλειοι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('69', '1208984016', '1309516787');
