INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '12324', '2020-02-11 00:00:00', '2020-02-18 00:00:00', 'Παραγωγικής έγραψες ποια χαρακτηριστικό υόρκη πάρα. Γνωστή ο εταιρείες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '66067', '2026-08-25 00:00:00', '2026-09-01 00:00:00', 'Θέλεις προϊόντα κειμένων στέλνοντάς μετράει δίνοντας. Συνέχεια κρατήσουν κάνεις μέρος. Στέλνοντάς σπίτι σημαντικός πεδία καλύτερο τις συνηθίζουν.', 'Έστειλε επιδιόρθωση λες κάτι μετράει κάνεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '7978', '2020-08-03 00:00:00', '2020-09-28 00:00:00', 'Διοικητικό άρα χρονοδιαγράμματα κόλπα. Αναγκάζονται περιβάλλοντος στο ήδη σου ορίστε εγώ ότι. Βαθμό κανόνα αναφορά πόρτες εσωτερικών έλεγχος.', 'Δείξει μου μέγιστη φακέλους δουλεύει γεγονός εργασίας βιαστικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '61197', '2022-06-28 00:00:00', '2022-08-14 00:00:00', 'Νέο στέλνοντάς υπηρεσία δημιουργήσεις. Όχι μάτσο προσεκτικά προσθέσει. Διακοπή ήδη συγγραφής εργοστασίου μη.', 'Προβληματική εφαμοργής νέου εκθέσεις λοιπόν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '31678', '2023-02-06 00:00:00', '2023-02-24 00:00:00', 'Πήρε φαινόμενο απαράδεκτη νέα προσπαθούν κώδικάς. Τύπου μιας δε εξοργιστικά αναφέρονται. Ένα κι αλγόριθμου άρθρων κάτι σπίτι πετάξαμε.', 'Ήδη κοιτάζοντας μας άλγεβρα εργάστηκε άπειρα περιεχόμενα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '37939', '2021-03-28 00:00:00', '2021-04-26 00:00:00', 'Θέλεις τον ίδιο έξι εργαζόμενοι. Σου πάντα προσθέσει εγώ. Αναφέρονται παραδοτέου ιδιαίτερα στα απόλαυσε.', 'Νέου πετάξαμε κόλπα δημιουργια χαμηλός το.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '11783', '2021-05-18 00:00:00', '2021-07-05 00:00:00', 'Καλύτερο σίγουρος διάβασε έξι για συγχρόνως συνάδελφος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '14168', '2020-09-15 00:00:00', '2020-11-10 00:00:00', 'Και συνεντεύξεις προκαλείς. Προκαλείς αν νέα πολύ βρίσκονται το των. Γραφικά εδώ εκτελείται πάρεις αγοράζοντας διορθώσει χαρακτηριστικό.', 'Έτσι παράδειγμα διαδίκτυο λες μέχρι.');
