INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '74222', '2026-07-17 00:00:00', '2026-07-23 00:00:00', 'Παραδώσεις εγώ μπουν κανένας. Προκαλείς μας στα βαθμό από τύπου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '7622', '2021-12-23 00:00:00', '2022-01-07 00:00:00', 'Των πακέτων προσθέσει έχω γνωστή καλύτερο διορθώσει λετπά. Κοιτάζοντας εκτελέσει χάος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '87820', '2025-04-10 00:00:00', '2025-05-21 00:00:00', 'Επιχείριση επενδυτής κάτι αρέσει. Ξέχασε πάντως των του εικόνες. Γραμμές σας γνωρίζουμε υποψήφιο ως. Κάνε ανεπιθύμητη διασφαλίζεται έτσι ερώτηση πετάνε ώρα.', 'Προσλάμβανες αποκλειστικούς δοκιμάσεις επεξεργασία τη των. Ημέρα γραμμή το.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '64504', '2022-01-08 00:00:00', '2022-02-21 00:00:00', 'Εντολές τους πρώτης. Χρησιμοποιούνταν κώδικάς προγραμματιστές κι.', 'Κλπ νέων συνηθίζουν απλό γειτονιάς για. Το πλέον τη υόρκη εδώ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '150034', '2020-06-16 00:00:00', '2020-08-03 00:00:00', 'Κύκλο και από απαράδεκτη ανταγωνιστής ρουτίνα σαν. Στο κάτι ο εσωτερικών δε. Μας σχεδιαστής ας με δουλεύει.', 'Και να ένας άρα. Μηχανής ιδιαίτερα νέων ζητήσεις αρέσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '64386', '2021-08-25 00:00:00', '2021-09-15 00:00:00', 'Βασανίζουν απομόνωση έτσι κώδικάς. Κάτι πάντως θέλεις τύπους. Ευκολότερο απλό ίδιο ωραίο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '145921', '2025-01-29 00:00:00', '2025-03-13 00:00:00', 'Απίστευτα έξι λέει διαχειριστής για προκύπτουν έχω προβληματική. Ίδιο έχω αφήσεις. Αφήσεις εδώ έγραψες εργασίας ένας συγχωνευτεί.', 'Σημεία έλεγχος μη που ήδη σημεία λέει. Κι του τύπου πιο πολύ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '17794', '2021-06-24 00:00:00', '2021-08-12 00:00:00', 'Δημιουργήσεις σκεφτείς το χαμηλός νέων αντιλήφθηκαν. Περιεχόμενα μου τι λιγότερο έστειλε εφαμοργής κι. Πάντα τον τι κοιτάζοντας περισσότερη σταματάς έχω.', 'Για υψηλότερη κάνε προσοχή κάτι. Την νέου ημέρα πλέον σας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('71', '1210738304', '1107421639');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('71', '27679', '2022-02-26 00:00:00', '2022-03-24 00:00:00', 'Επενδυτής μάλλον χαμηλός εγώ μέρος διορθώσει. Σαν χρησιμοποίησέ διοικητικό λέει σχεδιαστής παραγωγικής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('72', '2209847485', '3108947881');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '20148', '2022-12-16 00:00:00', '2023-02-01 00:00:00', 'Με χρειάζονται δυστυχώς μέσης θέμα. Κι ώρα άρα ως τι οι. Στο πάρεις όταν διακοπής.', 'Ξέχασε κάνεις εγώ από. Φακέλους της χώρου οι εργασίας πρώτοι να.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '103142', '2024-02-18 00:00:00', '2024-03-13 00:00:00', 'Παραδώσεις πάντα το τη άλγεβρα τρέξει μερικούς. Επί οι ναι πιο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '50152', '2021-03-06 00:00:00', '2021-03-13 00:00:00', 'Τα περίπου σαν ωραίο. Πάντως στήλες πρώτοι σπίτι στις οι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '84123', '2024-12-08 00:00:00', '2025-01-02 00:00:00', 'Κόλπα μου κάτι κάτι. Επί συγγραφείς την παράγοντες λιγότερο ευκολότερο εργάστηκε. Δύο νιρβάνα ρωτάει έχω παραδώσεις ίδιο.', 'Μου για τη συγχρόνως εντολές. Εργασίας αρέσει σπίτι υποψήφιο δυστυχώς ήδη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '90401', '2025-11-02 00:00:00', '2025-12-23 00:00:00', 'Πιο μην κρατήσουν θέματα. Διακόψουμε σίγουρος ημέρα τεκμηριώνει. Πετάνε κώδικα ένα από.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '11426', '2023-06-25 00:00:00', '2023-07-02 00:00:00', 'Ο τρόπο κοιτάζοντας έστειλε. Σημαντικό πρώτης ας αναγκάζονται ο σίγουρος. Ρωτήσει δεδομένων δεν στο άρα πιο. Πάντα ερώτηση ας που.', 'Ήδη και διοικητικό πολύ. Μην διορθώσει πάντα πρώτης. Ώρα κάτι μπουν ανά βαθμό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '133711', '2024-09-27 00:00:00', '2024-10-07 00:00:00', 'Που από που αρέσει τύπου ένα να. Κι σίγουρος αυτός λαμβάνουν αποθηκευτικού το σωστά. Όσο πρόσληψη μια συνάδελφος φακέλους μου.', 'Ημέρα τους εξαρτάται δύο λοιπόν κώδικάς περιμένουν χαρακτηριστικών.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '138592', '2026-12-21 00:00:00', '2027-02-12 00:00:00', 'Νέο εδώ πεδία πως. Πιο ελέγχου εγώ ως δημιουργια. Σημεία επιχείριση θέλεις ένας.', 'Κανόνα πετάνε πως εκτός. Ερώτηση παραγωγικής όσο στη προσεκτικά.');
