INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('78', '51577', '2020-02-10 00:00:00', '2020-02-27 00:00:00', 'Αθόρυβες γραφικά δύο απλό να χρησιμοποιούνταν χρονοδιαγράμματος. Στη προκύπτουν μέγιστη. Παράγοντες γεγονός πρώτο τρέξει ροή χάος κάτι.', 'Αποθηκευτικού και επί καταλάθος διοικητικό δουλεύει.');
