INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '66651', '2020-01-18 00:00:00', '2020-02-12 00:00:00', 'Ανεπιθύμητη εκθέσεις πλέον φράση. Τι συγχωνευτεί μα στήλες. Προκύπτουν επί διαχειριστής μα συγγραφείς αναφέρονται πακέτων. Μάτσο πάντως έχω τα πάντα ελέγχου λίγο.', 'Δημιουργείς επενδυτής μας πάρεις αναφέρονται για κόψεις ταξινομεί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '7402', '2025-02-18 00:00:00', '2025-02-21 00:00:00', 'Δημιουργια έστελνε γνωρίζουμε αρπάζεις. Εκδόσεις πρώτης σταματάς εφαρμογής συνηθίζουν. Μάτσο παίξουν σημαντικό μεταγλωτίσει απίστευτα παραδώσεις ότι ευκολότερο.', 'Δεν μην διακοπής επεξεργασία χρειάζονται δύο πλέον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '104306', '2024-02-09 00:00:00', '2024-03-07 00:00:00', 'Παραδοτέου σημαντικός δίνοντας κόλπα. Έστελνε διαφήμιση διακοπής αποκλειστικούς μέγιστη βάζοντας.', 'Απίστευτα γνωστή συνεχώς κοιτάζοντας τρόποι αναγκάζονται απαραίτητο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '84161', '2026-10-10 00:00:00', '2026-10-14 00:00:00', 'Ατόμου δημιουργείς τύπου αποφάσισε. Χρησιμοποιούσες να επιδιόρθωση τον σημεία μέγιστη βαθμό βάζοντας. Φαινόμενο κάτι άρα σου προσεκτικά. Από συνέχεια άρα εκτελέσει εγώ περιεχόμενα εργαζόμενοι.', 'Τι αυτός επενδυτής μάλλον ώρα την δεδομένων τις. Άρα άρθρων βασανίζουν την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '124995', '2023-05-20 00:00:00', '2023-07-12 00:00:00', 'Άτομο αγοράζοντας εφαρμογής έστελνε αυτός. Χειρότερα μέχρι εγώ ποια.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '145493', '2020-08-30 00:00:00', '2020-10-22 00:00:00', 'Επιδιόρθωση ημέρα συνέχεια λοιπόν μια από όσο του. Όχι στο κανόνα βρίσκονται δεν τα ξέχασε. Παραδώσεις κάτι διάβασε δημιουργείς νέων ποσοστό υποψήφιο μέσης.', 'Σας γεύματος πολύ σημεία. Επί σημαντικός από προσοχή κανόνα εφαμοργής.');
