INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('81', '117768', '2022-09-07 00:00:00', '2022-09-27 00:00:00', 'Υψηλότερη σκεφτείς πρώτοι ερωτήσεις. Σε επιδιορθώσεις ειδικά νιρβάνα γραφικά σταματάς δείξει. Έξι αγοράζοντας κλπ υπηρεσία αρχεία και τα.', 'Ζητήσεις παίξουν απόλαυσε στη. Έχω μου στη κι απλό.');
