INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '64272', '2022-11-13 00:00:00', '2022-11-19 00:00:00', 'Πλέον στραβά χαμηλός άπειρα διακόψουμε από. Ας εκθέσεις χρησιμοποίησέ παραδοτέου λέει εικόνες. Βασανίζουν για τοπικές εφαμοργής.', 'Διαπιστώνεις λιγότερο απομόνωση όταν διολισθήσεις ταξινομεί χρονοδιαγράμματος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '88226', '2022-06-29 00:00:00', '2022-07-11 00:00:00', 'Άρα εκτός απίστευτα σου επιχείριση παίρνει. Με συγκεντρωμένοι προσπαθήσεις αποφάσισε δεν εταιρείες πολύ. Εργάστηκε έτσι μα ξέχασε μην σκεφτείς κρατάει.', 'Διάσημα προκύπτουν κύκλο παραπάνω μάθε εργοστασίου βάζοντας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '50101', '2025-08-05 00:00:00', '2025-09-26 00:00:00', 'Μια ανεπιθύμητη υπηρεσία τοπικές κάτι τρόπο. Ατόμου τρόπο συνεντεύξεις μην ειδικά υψηλότερη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '95187', '2020-06-08 00:00:00', '2020-07-19 00:00:00', 'Τη ποια χρησιμοποιώντας. Ανά έξι διοικητικό εξακολουθεί. Διαδίκτυο θέλεις ζητήσεις απλό απομόνωση δε.', 'Εκθέσεις όταν αρχεία περιβάλλοντος χρονοδιαγράμματα άλγεβρα ζητήσεις σας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '77550', '2020-09-04 00:00:00', '2020-10-15 00:00:00', 'Τη μέχρι έστειλε μεταγλωτίσει παίξουν. Δημιουργείς απίστευτα γραμμές χώρου μην το έξι ήδη. Συγχρόνως σκεφτείς μας ότι θα.', 'Χρησιμοποιούσες και εκτελέσει σημαντικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '26973', '2020-04-13 00:00:00', '2020-05-20 00:00:00', 'Σαν τα τις διακόψουμε φράση. Χρονοδιαγράμματος κειμένων κοιτάζοντας επεξεργασία. Ένας ποια εκτελέσει από διαχειριστής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '110966', '2022-07-29 00:00:00', '2022-08-29 00:00:00', 'Ροή χρησιμοποιούσες κι τεκμηριώνει κειμένων τις πόρτες. Προσεκτικά να ρωτήσει από να ακούσει του. Γραμμή περιεχόμενα την ίδιο στις χώρου. Της επιστρέφουν εταιρείες συνέχεια που δύο.', 'Κλπ μάτσο χαρακτηριστικό απαρατήρητο ευκολότερο σαν παίρνει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('83', '1710921659', '0106802516');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '75916', '2020-06-12 00:00:00', '2020-06-19 00:00:00', 'Αναφορά για εργαλείων διαχειριστής κλπ. Παίρνουν κλπ πιο παίξουν αποστηθίσει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '150163', '2023-02-05 00:00:00', '2023-02-16 00:00:00', 'Διορθώσει προκύπτουν επιστρέφουν όχι γεγονός. Βγήκε ημέρα του δυστυχής. Ώρα θέμα σημαντικό κάτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '96395', '2024-05-07 00:00:00', '2024-05-24 00:00:00', 'Κάτι ήδη εγώ έχω. Πρώτοι εφαρμογής μερικούς προσπαθούν ποια. Συγγραφείς ο προσλάμβανες σαν επενδυτής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '16857', '2022-01-08 00:00:00', '2022-01-31 00:00:00', 'Μας μας καλύτερο προγραμματιστής. Απαρατήρητο ελέγχου δε δε συνεντεύξεις. Προσπαθούν σας δυστυχής ας διάσημα.', 'Με συνεντεύξεις προϊόντα πακέτων κι χρονοδιαγράμματος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('84', '2810769157', '0312710224');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('84', '147429', '2021-02-06 00:00:00', '2021-04-07 00:00:00', 'Σχεδιαστής ας σκεφτείς θα μα πρώτης πάντως πάντα. Συγχωνευτεί νόμιζες προσλάμβανες σπίτι έστειλε παίρνουν. Παίξουν προσπαθήσεις σου δουλεύει τον. Μα για ζητήσεις τα επί βιβλίο στο.', 'Έχω ερώτηση ύψος. Πάντως πηγαίου ποια μέχρι εκτελέσει βασανίζουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('84', '29677', '2022-08-23 00:00:00', '2022-10-18 00:00:00', 'Μα έχω σας φράση κειμένων. Μας πήρε έτσι μετράει προβληματική παίξουν ως μη. Σε λες στα αφήσεις εργασίας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('85', '1510425991', '1008642589');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('85', '27621', '2022-03-13 00:00:00', '2022-04-17 00:00:00', 'Τοπικές εγώ μιας πακέτων βγήκε. Δουλεύει κλπ μη όσο εκείνου θέλεις. Μέχρι πετούν όχι εκτός. Από κάτι παραπάνω εκδόσεις επιδιόρθωση περίπου γράψει.', 'Μην πάρεις διορθώσει σε. Εκδόσεις μην να εργαζόμενων ειδικά μάλλον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('85', '37550', '2023-06-25 00:00:00', '2023-06-27 00:00:00', 'Μεταφραστής βρίσκονται βάζοντας δεν τι εργαζόμενοι λιγότερο. Έτσι που πολύ αρχεία. Μη μεταγλωτίσει τις πάρεις στο.', 'Εργαζόμενων την τα εργάστηκε γνωστή ότι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('86', '2108896469', '2206071697');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '45138', '2024-11-18 00:00:00', '2025-01-07 00:00:00', 'Στέλνοντάς διασφαλίζεται αποστηθίσει εκδόσεις δύο εδώ ανώδυνη τους. Εργαζόμενων σημαντικό έστελνε όταν περιμένουν αθόρυβες διάσημα. Κανείς μηχανής ρουτίνα εξακολουθεί. Ποσοστό τύπου ωραίο έξι.', 'Διαφήμιση δεν να χαμηλός αποφάσισε. Σου αποδείξεις σημεία στήλες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '33197', '2022-06-30 00:00:00', '2022-08-07 00:00:00', 'Τύπους ότι στη χρησιμοποιούσες μάλλον δεδομένων. Φαινόμενο προκύπτουν πρώτης εκτελείται γραμμές τον διορθώσεις. Μας αντιλήφθηκαν πάρεις ρωτάει υόρκη για πιο.', 'Ήδη ανακλύψεις έχω καταλάθος χρησιμοποίησέ μάλλον να ξέχασε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '14804', '2022-11-30 00:00:00', '2023-01-01 00:00:00', 'Μεταγλωτίσει συνεντεύξεις κοιτάζοντας απλό φακέλους βάζοντας. Να λαμβάνουν όσο εδώ σε. Μάθε σπίτι επιδιορθώσεις βάζοντας διαδίκτυο απλό εκτός.', 'Άρα μου πολύ διευθυντές μου μου. Έχω εργαζόμενων λετπά προκαλείς θα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '89873', '2020-02-23 00:00:00', '2020-04-09 00:00:00', 'Ωραίο ημέρα βγήκε το εκτός. Ίδιο πρώτοι ένας. Μέσης στη γραφικά σπίτι να τα πλέον.', 'Μα τύπους έστελνε εφαρμογή εκτελέσεις υποψήφιο. Συνέχεια πολύ πιο ύψος θέματα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '17071', '2020-08-09 00:00:00', '2020-08-16 00:00:00', 'Εργαζόμενοι ορίστε προβληματική γνωστή παίρνουν ώρα θα. Του υποψήφιο θέλεις ξέχασε καλύτερο κι τις χαρακτηριστικό. Αναγκάζονται περίπου εξοργιστικά δημιουργήσεις μη έξι.', 'Διακόψουμε εγώ πλέον επί εκτελέσει στο πάντα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '129534', '2022-06-21 00:00:00', '2022-08-04 00:00:00', 'Σε ο επί προσπαθούν εργαζόμενων επί. Ήδη μέχρι σημαντικός απόλαυσε κλπ συγχωνευτεί. Ήδη σε κλπ σου κάνεις μετρήσεις.', 'Δεδομένων σχεδιαστής της οι πάρα αποκλειστικούς μάθε εργασίας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '70583', '2026-01-19 00:00:00', '2026-01-28 00:00:00', 'Μα απαραίτητο της άρα θυμάμαι επί πεδία. Χαρακτηριστικό λετπά δύο οι άρθρων ωραίο. Αφήσεις να πιο μαγικά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '6322', '2025-06-11 00:00:00', '2025-08-08 00:00:00', 'Τεσσαρών κοιτάζοντας άτομο πιο ίδιο αλγόριθμου τη τα. Παραδοτέου και εσωτερικών μην νέου.', 'Ήδη μας ρουτίνα των του πιο. Παράγοντες μην ωραίο εκδόσεις ποια δύο την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '29190', '2021-09-08 00:00:00', '2021-10-05 00:00:00', 'Χάος εδώ ποσοστό λίγο. Ώρα το αν αυτός έχω. Ήδη ακούσει όσο στραβά.', 'Πάρεις διορθώσει χαρακτηριστικών μεταγλωτιστής διολισθήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '38615', '2024-10-16 00:00:00', '2024-12-01 00:00:00', 'Μην συνεχώς δημιουργήσεις τι πάντα με πάντα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('87', '1307652974', '2712002031');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('87', '96157', '2021-11-12 00:00:00', '2021-12-07 00:00:00', 'Ο σίγουρος αυτός εκτός ως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('88', '2810810239', '2908412577');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '137318', '2023-01-26 00:00:00', '2023-03-26 00:00:00', 'Διολισθήσεις χρειάζονται πρόσληψη νέο. Δεν επί ακούσει κώδικάς κι. Εφαρμογής συγκεντρωμένοι περιβάλλον εργάστηκε συνηθίζουν. Έγραψες αρπάζεις παίρνουν ναι σε σαν.', 'Τι εκδόσεις έχω λες. Μέχρι αρχεία δούλευε ρουτίνα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '117111', '2022-09-13 00:00:00', '2022-10-18 00:00:00', 'Προβληματική κάνε καταλάθος κανείς τρόποι θέμα εγώ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '38356', '2024-03-17 00:00:00', '2024-05-09 00:00:00', 'Χρησιμοποίησέ εκτελέσει εγώ γραφικά. Τους δουλεύει πάρεις γέλασαν πολύ βρίσκονται τοπικές χρησιμοποιούσες. Ήδη πως εκείνου ποια των πηγαίου. Στέλνοντάς κάτι έτσι ποια δυστυχής σχεδιαστής παραπάνω.', 'Της σαν κύκλο. Στήλες θέμα πολύ λίγο παραδώσεις γραμμής βασανίζουν φακέλους.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '34515', '2024-09-18 00:00:00', '2024-09-22 00:00:00', 'Μην ορίστε αυτός σε θα στήλες. Που απαρατήρητο βγήκε αρχεία έχω άρα ώρα. Είχαμε διακοπή άρθρων ίδιο. Ορίστε έξι διαδίκτυο εκείνου ατόμου.', 'Αποστηθίσει μιας και θέμα δούλευε. Χαρακτηριστικών όσο ρωτήσει βαθμό πάρεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('89', '1403699638', '0103870003');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('89', '70504', '2023-11-28 00:00:00', '2023-12-27 00:00:00', 'Πρόσληψη νέο χαρακτηριστικό αποδείξεις τις κύκλο έστελνε. Περισσότερη ελέγχου προσθέσει κώδικα σταματάς δημιουργείς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('89', '89284', '2021-04-04 00:00:00', '2021-05-16 00:00:00', 'Εξοργιστικά ζητήσεις μετρήσεις έτσι γραμμές σωστά ένα τρόποι. Λίγο ευκολότερο πηγαίου και έστελνε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('90', '2108896469', '1709431072');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '112960', '2020-09-26 00:00:00', '2020-10-17 00:00:00', 'Κανόνα σε αυτός. Χώρου κανόνα τι περιμένουν ότι.', 'Έρθει διαδίκτυο προϊόντα. Κι πόρτες διορθώσεις που λες ταξινομεί κι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '55642', '2025-09-19 00:00:00', '2025-11-04 00:00:00', 'Βρίσκονται τις κι πως. Προγραμματιστές ορίστε δείξει γεγονός ωραίο υψηλότερη χειρότερα. Τύπου προσεκτικά καταλάθος μάτσο κόψεις για.', 'Την βουτήξουν ατόμου περιεχόμενα λαμβάνουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '37333', '2023-02-15 00:00:00', '2023-02-23 00:00:00', 'Το τύπους δίνοντας δείξει πιο προγραμματιστές.', 'Θέλεις άτομο ένας ναι μια κρατάει πάντα. Ακούσει τη γραμμή έτσι λίγο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '155336', '2025-12-15 00:00:00', '2026-01-03 00:00:00', 'Το θα βρίσκονται θα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '100053', '2025-03-19 00:00:00', '2025-05-14 00:00:00', 'Νέο τη δυστυχής αρχεία εργάστηκε ποια έχω τεκμηριώνει. Ύψος χρησιμοποιούσες εγώ δεν ροή ναι. Συγχωνευτεί τύπου της να μας ότι.', 'Παράδειγμα χρησιμοποιούνταν το χρονοδιαγράμματα πάρεις εργαζόμενων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '96099', '2024-09-26 00:00:00', '2024-10-12 00:00:00', 'Στήλες πες στο. Κάνεις εγώ ως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('91', '1308819353', '2209496415');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('91', '119645', '2024-06-25 00:00:00', '2024-08-18 00:00:00', 'Χρειάζονται ναι καλύτερο πρώτοι μη νέο παραδώσεις. Μαγικά εργάστηκε σαν διαδίκτυο κόλπα μα δυστυχής. Σε το πετάνε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('91', '148477', '2024-04-26 00:00:00', '2024-05-08 00:00:00', 'Μου δούλευε τρέξει πρώτοι. Δωροδοκηθούν τεσσαρών από.', 'Εγώ εγώ με εντολές την μετράει. Επιδιόρθωση επιστρέφουν μετρήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('91', '7864', '2025-04-19 00:00:00', '2025-04-20 00:00:00', 'Εργάστηκε και δουλεύει έτοιμος πλέον σας. Εδώ διαδίκτυο πάντως μην σκεφτείς συνέχεια φακέλους.', 'Στέλνοντάς μην άλγεβρα εκδόσεις προκύπτουν εκτελέσει εγώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('92', '2901598111', '1606751646');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '1798', '2025-10-05 00:00:00', '2025-11-08 00:00:00', 'Έτσι νέου πάντως πως αναφορά διακοπή εργασίας. Τι έξι πάντως διαχειριστής. Λετπά ευκολότερο εδώ τρέξει ιδιαίτερα πολύ κρατήσουν.', 'Συνάδελφος πηγαίου τέλειοι βιαστικά ανεπιθύμητη. Κώδικάς προσεκτικά αν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '73573', '2022-09-18 00:00:00', '2022-09-30 00:00:00', 'Πρώτο έχω βάζοντας ποια από χαρακτηριστικών. Επί λοιπόν κάνε. Βάζοντας του στη βάζοντας ευκολότερο άπειρα πρώτης. Έτσι τα ναι πιο προκύπτουν πάντα όχι.', 'Αν σκεφτείς εκτός έτσι εγώ νέα μιας. Που ένα απαράδεκτη έχω από κάτι τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '34624', '2023-10-28 00:00:00', '2023-12-16 00:00:00', 'Χρονοδιαγράμματα συνηθίζουν δημιουργήσεις τι το απόλαυσε τον. Εκδόσεις μην των αρέσει.', 'Δεν εικόνες των παράδειγμα κόψεις από χρησιμοποιώντας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '78051', '2022-07-22 00:00:00', '2022-09-02 00:00:00', 'Εκτελέσεις γειτονιάς και πάντα αλγόριθμου κάνεις. Ταξινομεί πολύ δείξει σας. Μην τύπου δωροδοκηθούν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '152071', '2023-03-30 00:00:00', '2023-04-03 00:00:00', 'Όταν άπειρα αν έρθει ήδη λέει. Τρόποι κώδικάς παίρνουν καταλάθος. Κανείς δεδομένων το τέλειοι διάβασε περίπου. Λίγο σαν πλέον ο παίρνει περιεχόμενα.', 'Σου περιεχόμενα χαρτιού νέα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '70942', '2023-09-21 00:00:00', '2023-11-14 00:00:00', 'Κοιτάζοντας πεδία διαδίκτυο άρθρων συγχωνευτεί διοικητικό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '21233', '2026-10-02 00:00:00', '2026-11-30 00:00:00', 'Προβληματική πήρε έστειλε από. Εκτός όχι διάσημα εργασίας ο τύπους. Ταξινομεί ώρα γειτονιάς πρώτο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('93', '1606420374', '2007741978');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '152432', '2021-10-15 00:00:00', '2021-12-01 00:00:00', 'Στη μέσης θέμα χρησιμοποίησέ. Εκτός περιβάλλοντος γράψει διαδίκτυο κλπ μέχρι.', 'Σου συγχρόνως εργάστηκε σωστά την μην δεν θα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '128903', '2023-10-22 00:00:00', '2023-11-08 00:00:00', 'Εταιρείες για ήδη πάρεις μέχρι σαν. Ήδη άρθρων τι τον. Κύκλο έτοιμος έστειλε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '97267', '2025-04-03 00:00:00', '2025-05-19 00:00:00', 'Απίστευτα νέο στραβά εφαμοργής ωραίο κώδικάς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '148266', '2024-07-13 00:00:00', '2024-07-22 00:00:00', 'Ένας δημιουργια συνεχώς γέλασαν δεν. Αποδείξεις έξι της αθόρυβες ως.', 'Ανώδυνη διάβασε βουτήξουν. Μέχρι μιας δε όσο. Πρόσληψη πρώτο κάτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '55762', '2024-10-29 00:00:00', '2024-12-23 00:00:00', 'Τις αθόρυβες περιεχόμενα γραμμές μερικούς σκεφτείς. Σημεία συνεχώς κανένας παίρνει. Πακέτων δωροδοκηθούν κάτι αναφορά με ανταγωνιστής.', 'Κάνεις δε άρθρων. Θέλεις λέει πετάνε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '82040', '2024-03-22 00:00:00', '2024-05-08 00:00:00', 'Σχεδιαστής όχι άτομο ένας ο. Εικόνες επιχείριση δυστυχής προσλάμβανες δωροδοκηθούν. Ρωτάει την εφαρμογή εργαζόμενοι μιας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '130968', '2021-08-29 00:00:00', '2021-09-11 00:00:00', 'Ημέρα φίλος εφαμοργής έξι. Χρόνου τον ρουτίνα μου μηχανής. Κι δε επιστρέφουν στα τη των.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '130506', '2020-05-18 00:00:00', '2020-05-28 00:00:00', 'Χάος χρονοδιαγράμματα διασφαλίζεται χρησιμοποιώντας. Χρόνου όχι τοπικές εφαμοργής διευθυντές ίδιο. Απομόνωση δεν εκτελέσεις τεσσαρών διακοπής είχαμε μα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '8723', '2026-10-05 00:00:00', '2026-11-21 00:00:00', 'Θυμάμαι επί απόλαυσε μπορούσες μπορούσες βάζοντας. Πες προκαλείς προκύπτουν συγκεντρωμένοι. Επιδιόρθωση στις αποθηκευτικού απαραίτητο ο δείξει αποφάσισε.', 'Πρώτοι νόμιζες πρώτο χρησιμοποιούσες. Διορθώσεις εδώ χρονοδιαγράμματος έστελνε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '87763', '2021-06-26 00:00:00', '2021-07-12 00:00:00', 'Κάνε κλπ πολύ εδώ επί στήλες έξι προσπαθούν. Μας έλεγχος αποστηθίσει μέχρι τρέξει χρησιμοποιούνταν. Μηχανής μιας κάτι και κύκλο συγγραφής τις. Τι νέων υψηλότερη της.', 'Ως δύο τον διακοπής βιαστικά εργάστηκε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('94', '2002692502', '0102465455');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('94', '81452', '2020-06-30 00:00:00', '2020-07-22 00:00:00', 'Λίγο ταξινομεί ήδη εικόνες όχι συνεντεύξεις. Βουτήξουν αλγόριθμου το τις συνεντεύξεις εκτελέσει μα.', 'Ότι συγχωνευτεί συνεντεύξεις γραφικά λαμβάνουν χρόνου κλπ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('94', '121462', '2022-09-23 00:00:00', '2022-10-05 00:00:00', 'Χρησιμοποιώντας παράδειγμα νέων πάντως κάτι πάρα. Ανακλύψεις πάντα μέχρι στήλες δε θέλεις. Γνωρίζουμε τεκμηριώνει χάος ποια μάθε. Αν εκδόσεις όταν προσπαθούν υψηλότερη ποια δυστυχώς αναγκάζονται.', 'Χρησιμοποιούνταν βάζοντας ένα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('95', '1605494725', '0107824374');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '25786', '2022-06-24 00:00:00', '2022-07-14 00:00:00', 'Στήλες συνέχεια υψηλότερη στήλες έχω. Ωραίο συνηθίζουν να. Κι κύκλο προγραμματιστής ναι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '89899', '2021-07-25 00:00:00', '2021-07-27 00:00:00', 'Να αγοράζοντας τύπου έχω μέχρι βγήκε εγώ. Σταματάς ρωτάει πετάνε εντολές τις. Μεταγλωτιστής δεν εγώ της ανεπιθύμητη.', 'Προκύπτουν νέα στέλνοντάς πετούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '114896', '2024-05-15 00:00:00', '2024-05-22 00:00:00', 'Μηχανής θυμάμαι κάνε προσεκτικά απαράδεκτη. Ελέγχου ποια προκύπτουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '21960', '2026-04-23 00:00:00', '2026-05-05 00:00:00', 'Ημέρα τη εργαζόμενοι κανένας μην κάτι αναφορά περιμένουν. Διοικητικό αυτός και τύπους ένα οι κανένας όταν. Χαρτιού παίρνει δημιουργια συγκεντρωμένοι πιο νέων.', 'Ότι προβληματική ελέγχου θέμα χρόνου βάζοντας χάος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('96', '1710921659', '3005654782');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('96', '111323', '2026-11-02 00:00:00', '2026-12-26 00:00:00', 'Μεταγλωτιστής κάνεις δημιουργείς σημαντικός σαν λίγο. Μέχρι ιδιαίτερα γέλασαν στο ποια εργαζόμενοι μέρος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('97', '1710622455', '0303070046');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('97', '64771', '2024-03-16 00:00:00', '2024-05-13 00:00:00', 'Από παράγοντες σου περισσότερες. Έχω μέχρι μέχρι ύψος λέει των και. Εταιρείες πλέον κοιτάζοντας δεδομένων κι έτοιμος θα θέλεις.', 'Μα τα παράγοντες. Ανά αρέσει ημέρα άπειρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('98', '1806613730', '0303070046');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '104429', '2020-02-27 00:00:00', '2020-04-20 00:00:00', 'Έστειλε πιο σου πετάξαμε ποια απαραίτητο κι. Νιρβάνα αρπάζεις απλό κλπ κώδικα τρόποι εκτός. Σπίτι ωραίο τον λαμβάνουν με εφαμοργής επιχείριση.', 'Μέχρι όταν αποδείξεις πόρτες αποφάσισε εικόνες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '25018', '2024-03-31 00:00:00', '2024-04-01 00:00:00', 'Συγχωνευτεί τεκμηριώνει ήδη φίλος χρησιμοποίησέ διαδίκτυο ας. Αναγκάζονται αφήσεις κώδικάς γέλασαν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '43435', '2021-07-13 00:00:00', '2021-07-26 00:00:00', 'Εικόνες προκαλείς μεταγλωτιστής. Υόρκη εργαζόμενοι μπουν λες. Διαφήμιση ερώτηση παράδειγμα στο προκαλείς προσοχή άλγεβρα.', 'Δε σε χειρότερα συνάδελφος. Λοιπόν τι παίξουν θέματα βάζοντας λαμβάνουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '103426', '2026-12-16 00:00:00', '2027-01-17 00:00:00', 'Πεδία σίγουρος στραβά εγώ. Τις πως επί στη προβληματική παίρνουν κειμένων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '101906', '2025-07-01 00:00:00', '2025-08-06 00:00:00', 'Τι πάντως θέλεις πολύ. Ανά εκτός σε γραφικά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '53295', '2021-04-15 00:00:00', '2021-05-01 00:00:00', 'Ναι καλύτερο όσο δύο. Διαπιστώνεις γεγονός προσπαθήσεις κώδικα εκτελέσει παραδοτέου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('99', '1104876855', '2910240766');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('99', '105828', '2025-07-20 00:00:00', '2025-08-05 00:00:00', 'Επί ωραίο απαρατήρητο δημιουργια μπορούσες μου θέλεις. Προσοχή κόλπα παίξουν από τους τύπους. Πετάξαμε διακοπής ανεπιθύμητη χρόνου εκθέσεις έχω.', 'Τα διολισθήσεις όταν. Γιαυτό τις πάρεις διαδίκτυο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('99', '45826', '2026-08-30 00:00:00', '2026-10-21 00:00:00', 'Γεγονός ημέρα μια άρα. Χρησιμοποιούσες προγραμματιστής πολύ γράψει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('100', '0709484565', '2812772376');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '160309', '2020-02-28 00:00:00', '2020-03-17 00:00:00', 'Φαινόμενο εκείνου χαρακτηριστικών πολύ εξοργιστικά. Την κώδικα σου λίγο παίξουν πόρτες εκτελέσει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '145951', '2024-02-05 00:00:00', '2024-04-03 00:00:00', 'Φίλος πακέτων διοικητικό εντολές συνέχεια εδώ μετρήσεις για. Επιδιορθώσεις κόψεις λιγότερο δεδομένων άρα νιρβάνα χρειάζονται νέων. Για συγχωνευτεί εσωτερικών σου έχω.', 'Γραφικά του ποια και προσλάμβανες ένας την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '51550', '2021-06-24 00:00:00', '2021-06-28 00:00:00', 'Αφήσεις χρονοδιαγράμματα έγραψες περισσότερες δυστυχώς απίστευτα. Ένα πρόσληψη παίξουν τελειώσει.', 'Σημαντικός πάντως εργαλείων χρησιμοποιούνταν για φράση αποστηθίσει βγήκε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '55121', '2025-05-28 00:00:00', '2025-06-04 00:00:00', 'Πρώτοι χαρακτηριστικών διάβασε βιβλίο προκαλείς που ποσοστό επιδιορθώσεις. Του τι απομόνωση μας εσωτερικών πρώτο παίρνει.', 'Απλό από πάρα μα γραμμές για προσθέσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '143501', '2020-09-26 00:00:00', '2020-11-05 00:00:00', 'Δυστυχής γιαυτό νόμιζες δυστυχώς. Και διοικητικό και χρησιμοποιώντας παράδειγμα και πρώτοι.', 'Λίγο ύψος παράγοντες μέσης σπίτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('101', '0204747049', '2410539174');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('101', '22676', '2022-10-20 00:00:00', '2022-11-22 00:00:00', 'Υψηλότερη διοικητικό σε εκτελέσει. Βάζοντας μέρος διορθώσεις πάντα προκύπτουν ότι. Πηγαίου κρατάει αναφορά μια ας.', 'Μέγιστη σε στη σαν. Τεκμηριώνει επενδυτής θέλεις ρωτήσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('102', '0609734534', '1906481868');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '147428', '2025-11-30 00:00:00', '2025-12-31 00:00:00', 'Μέχρι τελειώσει της δεν. Ποια στα μέσης δεδομένων που.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '159703', '2023-04-16 00:00:00', '2023-05-29 00:00:00', 'Γνωστή τέλειοι χειρότερα μη. Φαινόμενο γνωρίζουμε κλπ θέλεις δεν. Δοκιμάσεις πιο κάνε.', 'Περιεχόμενα συνάδελφος βιαστικά χαρτιού σαν λαμβάνουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '133661', '2025-08-23 00:00:00', '2025-10-02 00:00:00', 'Έχω επιστρέφουν χρησιμοποίησέ μάλλον δείξει έστελνε απομόνωση. Εκτός αποκλειστικούς εκείνου πάντως βγήκε λετπά έξι τα.', 'Επενδυτής τον κρατήσουν συγγραφείς συγκεντρωμένοι εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '32868', '2024-03-17 00:00:00', '2024-03-26 00:00:00', 'Διαφήμιση τι αν παραπάνω. Προσλάμβανες τρόποι τις δοκιμάσεις έτσι. Κοιτάζοντας προκύπτουν αρχεία προσεκτικά ναι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '75300', '2026-10-01 00:00:00', '2026-11-13 00:00:00', 'Εγώ βιαστικά έτσι ελέγχου όσο. Θέλεις παίξουν έτσι δυστυχώς πλέον ως. Ταξινομεί γραφικά άρα για συνάδελφος.', 'Μεταφραστής κώδικα παραδοτέου τι άρα θυμάμαι φράση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '23771', '2022-06-01 00:00:00', '2022-06-28 00:00:00', 'Πήρε σου ταξινομεί διακοπή τεσσαρών εκθέσεις. Όσο εργαλείων από της. Το μιας ας δυστυχώς γραφικά κύκλο βγήκε εκτελείται.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '84439', '2024-08-12 00:00:00', '2024-09-07 00:00:00', 'Προσλάμβανες τι συγκεντρωμένοι προγραμματιστής. Με κρατάει περίπου που. Αποστηθίσει συγγραφής στα πακέτων ένα προσπαθήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '132723', '2022-02-10 00:00:00', '2022-02-23 00:00:00', 'Γνωρίζουμε τεσσαρών εργάστηκε ιδιαίτερα πλέον δεν. Λίγο χρησιμοποιώντας είχαμε. Επί αν χρησιμοποιούσες αλγόριθμου θα αυτός σημαντικός.', 'Ο τι μέσης τις. Όχι κρατήσουν παράγοντες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('103', '1811456363', '3107761925');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '145940', '2020-11-04 00:00:00', '2020-11-07 00:00:00', 'Θέματα δύο μη της κλπ σημεία εφαμοργής. Μέχρι διαφήμιση δούλευε και μα σαν μην.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '59326', '2023-04-29 00:00:00', '2023-06-13 00:00:00', 'Νέα στη απαραίτητο γιαυτό μαγικά διαφήμιση από. Έστελνε των το πηγαίου λιγότερο συνεντεύξεις πήρε μαγικά.', 'Στη χρησιμοποιώντας και γέλασαν στα. Δωροδοκηθούν κάτι νέα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '132607', '2021-09-09 00:00:00', '2021-10-12 00:00:00', 'Δούλευε σπίτι σημαντικός του. Αθόρυβες κι απόλαυσε τοπικές χαρακτηριστικών. Πάντως χρησιμοποιούσες κάτι νόμιζες επιδιορθώσεις διορθώσει πάρα.', 'Αναγκάζονται βιαστικά ερώτηση μη εγώ εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '58038', '2023-07-05 00:00:00', '2023-08-08 00:00:00', 'Μέσης χρονοδιαγράμματος επενδυτής πως χρειάζονται. Των στις πηγαίου τύπου αθόρυβες. Στήλες για έξι ίδιο διασφαλίζεται για.', 'Πάντως μηχανής πάρα κρατάει αντιλήφθηκαν περίπου τα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '36462', '2024-07-09 00:00:00', '2024-08-18 00:00:00', 'Τι ως εργοστασίου πάντως από σκεφτείς επεξεργασία.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '31904', '2025-09-19 00:00:00', '2025-10-29 00:00:00', 'Για σημαντικό μεταγλωτίσει χρόνου λες. Παίξουν εκτελέσεις χρησιμοποιούσες τεκμηριώνει.', 'Προσλάμβανες στη τρόπο μια μα φακέλους εκδόσεις στέλνοντάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '121235', '2023-08-28 00:00:00', '2023-10-05 00:00:00', 'Αγοράζοντας μεταφραστής ποια. Εκτός δε κανένας δημιουργήσεις μερικούς. Χρειάζονται ξέχασε ανταγωνιστής πάρεις. Ιδιαίτερα όσο εντολές ρωτάει.', 'Εκθέσεις που χαμηλός πλέον ένας σου και.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '89702', '2024-09-11 00:00:00', '2024-10-27 00:00:00', 'Δεν δεδομένων διολισθήσεις διάσημα διαφήμιση νέων γειτονιάς. Αναφέρονται χάος θέμα επιδιορθώσεις παραπάνω.', 'Συγκεντρωμένοι όχι προκύπτουν πλέον. Δε ο αφήσεις ναι ύψος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '87062', '2022-03-23 00:00:00', '2022-03-27 00:00:00', 'Σίγουρος αγοράζοντας διακόψουμε φακέλους. Γέλασαν επί και βουτήξουν μπουν οι σε παραδώσεις. Όχι αρπάζεις των παίξουν άρα χρησιμοποιούσες χαμηλός.', 'Δούλευε θέμα κι σημαντικό ανά τον κοιτάζοντας φράση.');
