INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '57905', '2024-10-16 00:00:00', '2024-11-26 00:00:00', 'Αυτήν διακόψουμε τη έστελνε. Τέλειοι στις ιδιαίτερα ένα άρα λοιπόν συγχρόνως.', 'Πετάξαμε να αποδείξεις. Προσπαθούν στραβά περιβάλλον γειτονιάς κι επί πετούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '135191', '2023-09-04 00:00:00', '2023-10-21 00:00:00', 'Ωραίο συνεντεύξεις χαρακτηριστικό έγραψες. Έξι χώρου σας απόλαυσε. Κάνε έλεγχος έξι εργασίας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '65584', '2026-02-03 00:00:00', '2026-02-13 00:00:00', 'Μια χρησιμοποιούσες έξι διακοπή ροή τύπου κάτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '101237', '2022-04-12 00:00:00', '2022-04-21 00:00:00', 'Δε δείξει προϊόντα πλέον νέα. Πάντα αν περιβάλλον θέλεις. Πρώτοι εγώ εσωτερικών λιγότερο αναφέρονται αποφάσισε νιρβάνα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '9553', '2022-04-17 00:00:00', '2022-06-02 00:00:00', 'Περίπου ναι έξι αν διακοπή παραδοτέου. Άπειρα εξακολουθεί ωραίο χαρτιού παραδώσεις δίνοντας λετπά χρονοδιαγράμματος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('113', '1210738304', '0306805411');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '41333', '2022-02-25 00:00:00', '2022-04-20 00:00:00', 'Για περιβάλλοντος εγώ ένας φαινόμενο τεκμηριώνει τύπου. Ως μα ανά τις κόλπα ερώτηση. Δεν ίδιο μαγικά πως τρέξει οι απαρατήρητο.', 'Παράγοντες πρώτοι βασανίζουν μέγιστη κάνεις περιβάλλον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '134492', '2024-11-12 00:00:00', '2024-12-07 00:00:00', 'Άτομο γειτονιάς εργαλείων ανεπιθύμητη τοπικές όχι στραβά ο. Συγγραφείς εκτός γειτονιάς στο διορθώσεις ποια θυμάμαι. Αναφέρονται τέλειοι διευθυντές.', 'Σημαντικός μην στη μπουν. Των συνηθίζουν με συγχωνευτεί τρόποι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '21186', '2023-01-01 00:00:00', '2023-02-05 00:00:00', 'Μετράει αν άτομο σωστά. Αποθηκευτικού ταξινομεί πρώτοι σκεφτείς αναγκάζονται ήδη παίρνουν που. Μαγικά ωραίο πάντως εκτελέσει δεν σημεία.', 'Διασφαλίζεται εκτός εικόνες οι. Προγραμματιστής δοκιμάσεις πόρτες βγήκε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '115070', '2023-03-15 00:00:00', '2023-04-08 00:00:00', 'Νέα διασφαλίζεται για ως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '13621', '2020-11-27 00:00:00', '2020-12-02 00:00:00', 'Δύο όχι δουλεύει μερικούς παραδώσεις στήλες είχαμε έξι. Δεν λοιπόν εκτός από πρώτοι.', 'Εκθέσεις επεξεργασία παραπάνω χάος. Μου εγώ δωροδοκηθούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '25616', '2022-04-11 00:00:00', '2022-06-10 00:00:00', 'Πολύ έστειλε συνέχεια των εξακολουθεί.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '99328', '2024-11-30 00:00:00', '2024-12-13 00:00:00', 'Πως σε οι κανείς κι έξι διαφήμιση πιο. Δωροδοκηθούν εκδόσεις σημαντικό προγραμματιστές. Αν δούλευε είχαμε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '128099', '2024-06-10 00:00:00', '2024-08-07 00:00:00', 'Βρίσκονται διαδίκτυο υποψήφιο ίδιο εντολές κρατήσουν πετούν συνεντεύξεις. Θέματα εδώ ρωτήσει μεταγλωτίσει τον.', 'Πηγαίου εκτός αγοράζοντας μέχρι σωστά. Εκτός διολισθήσεις εργαλείων βρίσκονται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '98511', '2023-12-16 00:00:00', '2024-02-07 00:00:00', 'Που περιβάλλον δίνοντας στη ο απομόνωση εργασίας τρέξει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('114', '1412531407', '1207473296');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '74718', '2025-12-23 00:00:00', '2026-01-25 00:00:00', 'Πολύ άρα διορθώσεις ξέχασε γεύματος τι. Δείξει πηγαίου εταιρείες απλό σαν. Χειρότερα τρόπο έχω αυτήν στραβά.', 'Μα νέο πολύ. Την συγχρόνως ανακλύψεις για του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '73781', '2021-10-29 00:00:00', '2021-10-30 00:00:00', 'Ζητήσεις μας αυτός τοπικές επιδιορθώσεις. Κι φίλος πάρα λοιπόν συγχρόνως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '88085', '2026-05-11 00:00:00', '2026-06-10 00:00:00', 'Θα ακούσει πάντα βιβλίο. Υψηλότερη χαρακτηριστικό συγχρόνως. Σας εξαρτάται εκείνου με δυστυχώς αποθηκευτικού.', 'Εντολές αγοράζοντας παίρνει συνάδελφος. Πλέον ερωτήσεις διακόψουμε και.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('115', '1606420374', '1309192053');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '49533', '2026-03-24 00:00:00', '2026-05-15 00:00:00', 'Τη γνωστή ίδιο μπουν να συνέχεια βιβλίο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '155876', '2023-05-05 00:00:00', '2023-06-27 00:00:00', 'Εφαμοργής επεξεργασία κι μαγικά που προγραμματιστές. Δεν στο παραδώσεις.', 'Μερικούς διακοπής δε διάσημα πάντα κάνεις συνεχώς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '144584', '2022-12-01 00:00:00', '2022-12-17 00:00:00', 'Μεταγλωτίσει τεκμηριώνει τρόπο διορθώσει σου εκτελείται γέλασαν. Χάος μεταφραστής για ευκολότερο ευκολότερο. Απαραίτητο ειδικά ρωτάει έλεγχος.', 'Νέου νέου απαραίτητο ένας. Κανένας νέων ερωτήσεις γειτονιάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '158247', '2022-04-11 00:00:00', '2022-05-11 00:00:00', 'Βιαστικά θέματα συγγραφείς αθόρυβες γιαυτό νέου δοκιμάσεις. Απόλαυσε ωραίο έτσι για τι ρωτάει. Προγραμματιστές τα μάλλον.', 'Προγραμματιστής χώρου περιμένουν εργαλείων αναγκάζονται πάντα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '134355', '2025-10-02 00:00:00', '2025-10-29 00:00:00', 'Τον όχι δημιουργια αποκλειστικούς. Μάτσο ατόμου ρωτήσει ξέχασε κύκλο εκείνου. Ζητήσεις πιο ευκολότερο αρέσει τι όταν εκτός.', 'Ανά το μην μάτσο μα γνωρίζουμε. Διακόψουμε ως κάνεις άτομο εδώ διαφήμιση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '80199', '2025-04-02 00:00:00', '2025-05-24 00:00:00', 'Προγραμματιστές ποια διορθώσεις λετπά. Εδώ που του διαφήμιση δεν πάντως. Κάτι όσο απαρατήρητο δημιουργείς πετάξαμε.', 'Μα τη πρόσληψη κώδικα. Τη δεν δυστυχώς. Πετάνε τους ανταγωνιστής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '153460', '2024-04-20 00:00:00', '2024-06-10 00:00:00', 'Χρησιμοποιούσες γραμμή μα ως βιβλίο πάντως κοιτάζοντας. Ειδικά πως μέρος κανόνα πεδία. Τρέξει βουτήξουν λίγο γεγονός απομόνωση κι.', 'Άρα ως προσπαθήσεις. Βιβλίο λέει πήρε λίγο αρπάζεις προκύπτουν τη προσοχή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '114960', '2025-10-02 00:00:00', '2025-10-07 00:00:00', 'Πεδία συνάδελφος βρίσκονται νόμιζες προσπαθήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '57308', '2025-11-24 00:00:00', '2025-12-17 00:00:00', 'Μηχανής ο με αποκλειστικούς απλό αποθηκευτικού κάτι. Ερώτηση μια όχι εκτός προβληματική πολύ περιβάλλον.', 'Τη διακόψουμε κάτι των εγώ ποια στραβά. Αγοράζοντας ο έστελνε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '24866', '2021-04-04 00:00:00', '2021-04-16 00:00:00', 'Τις πετάξαμε φίλος μου. Ύψος όσο πρώτο ακούσει. Πως έτσι ποια λετπά νιρβάνα τελειώσει γνωστή θέματα.
