INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '80144', '2025-04-23 00:00:00', '2025-05-17 00:00:00', 'Διαδίκτυο το υπηρεσία. Προσοχή γεγονός εργάστηκε χρησιμοποιούνταν κάτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '159116', '2026-08-04 00:00:00', '2026-09-28 00:00:00', 'Ένα με διάσημα απαραίτητο στα εκτός αφήσεις ελέγχου. Παράγοντες προβληματική δύο ποσοστό για με νέου. Έξι κι επί ζητήσεις πρώτο.', 'Με θέματα το διορθώσεις αγοράζοντας. Ένας σου τα αν εκείνου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '149752', '2023-03-01 00:00:00', '2023-03-11 00:00:00', 'Ανακλύψεις διάσημα διευθυντές σαν. Στη πως ορίστε στη στη κι πως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('117', '1611426076', '2806235869');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '42808', '2023-01-08 00:00:00', '2023-02-18 00:00:00', 'Μα πολύ επί αποδείξεις ο από ποια. Ζητήσεις γράψει διακόψουμε βρίσκονται πακέτων άλγεβρα.', 'Αρπάζεις διακόψουμε έτσι τα που για στέλνοντάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '27379', '2021-10-30 00:00:00', '2021-12-22 00:00:00', 'Παίρνει στήλες μπουν. Βασανίζουν φράση να χώρου περιβάλλοντος ένα. Διορθώσεις ναι πακέτων τοπικές κάνε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '125404', '2023-04-07 00:00:00', '2023-05-01 00:00:00', 'Ποια ανεπιθύμητη γεγονός πάντα σας. Όταν ο τις διαφήμιση παραδοτέου όταν ανά. Άρα δεν αν το σκεφτείς. Διαπιστώνεις τρόπο επιδιόρθωση σου αυτός στις.', 'Ένα εργαλείων μέσης πετούν θέλεις. Πετάξαμε λίγο με όσο διακόψουμε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('118', '2812755366', '1810120984');
