INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('118', '54810', '2023-09-08 00:00:00', '2023-11-03 00:00:00', 'Παράδειγμα ροή αρπάζεις ίδιο μπουν. Ζητήσεις γέλασαν θέλεις έξι κάτι. Παραδοτέου όσο έτσι.', 'Βαθμό επί ανώδυνη παραδώσεις γράψει παράδειγμα χαρακτηριστικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('118', '155559', '2020-05-08 00:00:00', '2020-06-16 00:00:00', 'Από στα παραδοτέου δείξει περιβάλλον. Γνωστή ναι εκτελέσεις εκτελέσεις τρόπο επιδιορθώσεις άρθρων. Εκτός τι ερώτηση μεταφραστής μπουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('119', '1611426076', '1611033036');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '30982', '2022-12-28 00:00:00', '2023-02-11 00:00:00', 'Μια ήδη τη συγγραφής. Σίγουρος τον υποψήφιο εταιρείες μέγιστη ίδιο. Χρησιμοποιώντας περιβάλλοντος σπίτι ας σας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '40060', '2023-01-30 00:00:00', '2023-02-03 00:00:00', 'Βιβλίο κάτι πήρε και ναι. Δύο γέλασαν μέγιστη δεν σου λαμβάνουν του. Ένας μέχρι γέλασαν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '116385', '2020-01-07 00:00:00', '2020-01-30 00:00:00', 'Μη προσπαθούν δίνοντας οι ρουτίνα υόρκη. Κάτι υπηρεσία αποφάσισε κάνε γειτονιάς δωροδοκηθούν. Μέχρι παραγωγικής πεδία ο θα χώρου χρονοδιαγράμματος πήρε. Κάτι επί μεταγλωτίσει πάντα.', 'Ίδιο αθόρυβες τα. Πως έξι επιδιορθώσεις δημιουργήσεις αποκλειστικούς αναφορά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '65609', '2022-01-11 00:00:00', '2022-01-26 00:00:00', 'Κάτι έγραψες τις σου πάντα. Χρησιμοποιούνταν χρονοδιαγράμματος πάντα βουτήξουν πάντως εντολές πρώτο. Πεδία αρπάζεις στραβά προϊόντα εγώ ορίστε ποσοστό.', 'Υψηλότερη απαρατήρητο κλπ. Δεν πρόσληψη ότι λιγότερο τρέξει πιο στα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '75472', '2022-07-18 00:00:00', '2022-08-16 00:00:00', 'Ως τεκμηριώνει μεταφραστής προγραμματιστής. Δυστυχώς περισσότερες ερώτηση εντολές. Επεξεργασία πάντα κόψεις προγραμματιστής παίρνουν μια δύο διορθώσεις.', 'Διάσημα εργαζόμενων σου εγώ. Εφαρμογής συνηθίζουν έξι δεν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '130865', '2026-04-17 00:00:00', '2026-06-02 00:00:00', 'Χαρακτηριστικών συγκεντρωμένοι προγραμματιστές κάτι περιμένουν εργαλείων ειδικά πρώτοι. Διάσημα μετράει κύκλο δοκιμάσεις ημέρα μαγικά εφαμοργής συγχρόνως. Περιβάλλον εργαζόμενοι πρώτο πακέτων ένα.', 'Εκθέσεις κρατήσουν εφαρμογής περιβάλλοντος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '108494', '2023-09-02 00:00:00', '2023-09-13 00:00:00', 'Του για χρησιμοποιώντας στο χρονοδιαγράμματα μας. Πάντα πλέον πάντα όσο.', 'Όσο επί πάντως γραμμής έτσι σίγουρος του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '23759', '2021-01-15 00:00:00', '2021-03-09 00:00:00', 'Σίγουρος χειρότερα γεγονός επενδυτής έτσι. Γεγονός απίστευτα ένα ότι μια στραβά πιο δημιουργήσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('120', '2810810239', '0705073574');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '16851', '2025-11-05 00:00:00', '2025-12-30 00:00:00', 'Χρησιμοποιούσες του εκτελέσει. Κώδικάς μη προγραμματιστές. Εργάστηκε στήλες διάβασε κανείς εσωτερικών. Διαχειριστής πλέον λίγο εξοργιστικά τρόπο είχαμε.', 'Επιστρέφουν πάντα συγχωνευτεί λιγότερο δύο ότι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '48993', '2026-03-04 00:00:00', '2026-04-13 00:00:00', 'Συγγραφής μάλλον προσθέσει ανακλύψεις δείξει. Διαδίκτυο χρονοδιαγράμματα δύο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '68482', '2023-07-15 00:00:00', '2023-07-18 00:00:00', 'Βιβλίο εκτελέσει πρώτης προσοχή σημαντικός μα. Δύο τις αυτήν βιαστικά πετάξαμε μάλλον. Αποθηκευτικού δε στις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '42484', '2021-06-26 00:00:00', '2021-07-22 00:00:00', 'Ημέρα γραμμής περιβάλλοντος βρίσκονται δίνοντας ρωτάει πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('121', '2701818499', '1509104877');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '68705', '2023-12-22 00:00:00', '2024-01-26 00:00:00', 'Κόλπα εταιρείες ποια στο εκδόσεις εκδόσεις μην. Μέχρι δεν ήδη γέλασαν.', 'Πάρα ροή ότι γραμμή. Για έχω κρατάει βουτήξουν επεξεργασία μερικούς εφαρμογή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '140749', '2026-05-08 00:00:00', '2026-06-18 00:00:00', 'Κι έξι διαπιστώνεις που ορίστε κάτι δούλευε επί. Υποψήφιο κάτι αν μερικούς σημαντικός προκύπτουν διορθώσεις. Εφαρμογή άτομο συνέχεια κύκλο γραμμή έστελνε τελειώσει.', 'Εγώ σαν έξι. Εκτελέσει κανένας αν εκτελέσει εργασίας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '25089', '2023-04-27 00:00:00', '2023-06-07 00:00:00', 'Κάτι εφαρμογής παραδώσεις παράδειγμα συγγραφής. Πρόσληψη όταν προσπαθούν γειτονιάς ίδιο σας πλέον.', 'Γράψει διάβασε κειμένων εκθέσεις μέχρι βουτήξουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '9541', '2020-07-03 00:00:00', '2020-08-01 00:00:00', 'Υποψήφιο τρέξει όχι λιγότερο έχω θα. Μη μεταφραστής αν μετράει δεν διακοπής. Χώρου μάλλον χρησιμοποίησέ ατόμου έλεγχος. Ήδη χαμηλός πετούν όταν κύκλο.', 'Ορίστε άρα τους πετάξαμε τοπικές εργάστηκε πρώτοι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '80293', '2023-02-03 00:00:00', '2023-02-04 00:00:00', 'Σίγουρος όχι κανόνα να όταν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '90396', '2025-09-10 00:00:00', '2025-09-15 00:00:00', 'Και δοκιμάσεις ποσοστό κάτι. Υποψήφιο δύο με γειτονιάς. Θα αρέσει εξοργιστικά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '76756', '2021-11-17 00:00:00', '2021-11-30 00:00:00', 'Αν δεν διάβασε πως περισσότερες γραμμής κρατήσουν εκθέσεις. Αναγκάζονται προσθέσει όσο μέχρι διορθώσει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('122', '0910505968', '0307997994');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '50005', '2022-04-10 00:00:00', '2022-05-29 00:00:00', 'Δημιουργια υπηρεσία εγώ δύο συνεντεύξεις φίλος κειμένων. Κειμένων ήδη μέρος ανεπιθύμητη κώδικα ανώδυνη κλπ.', 'Ρωτήσει προκύπτουν χαμηλός ένας επεξεργασία ένα εφαμοργής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '68253', '2025-12-13 00:00:00', '2026-01-31 00:00:00', 'Μάλλον βασανίζουν εργοστασίου μιας έστελνε εκτελείται. Μα παράγοντες ο πάντα. Επεξεργασία εκδόσεις λαμβάνουν εδώ των.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '98652', '2023-05-15 00:00:00', '2023-06-15 00:00:00', 'Έρθει λετπά προσπαθούν προγραμματιστής εικόνες ως συγγραφείς. Σε χαρτιού το στα βάζοντας γραμμή. Τεκμηριώνει τύπου τους χρόνου αναγκάζονται ποσοστό.', 'Ανώδυνη πιο ως λίγο νέα δημιουργείς πιο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '38928', '2022-10-31 00:00:00', '2022-12-10 00:00:00', 'Δεν όσο υψηλότερη χαρακτηριστικό και έξι μπορούσες πολύ. Γράψει λοιπόν για κύκλο πως τη τη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '9003', '2026-10-04 00:00:00', '2026-10-10 00:00:00', 'Ότι για χρόνου. Επεξεργασία βγήκε δεν μέγιστη σημαντικό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '97566', '2021-07-08 00:00:00', '2021-07-22 00:00:00', 'Πετάξαμε ναι διάβασε ανά νέου μέγιστη. Πολύ πρώτο δημιουργια μηχανής του όταν. Του γεύματος κύκλο σε δεδομένων.', 'Δούλευε αντιλήφθηκαν πρώτοι που σταματάς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '88495', '2021-11-19 00:00:00', '2021-12-23 00:00:00', 'Παίρνει χρησιμοποιούνταν μεταγλωτιστής με μα μετρήσεις εντολές. Μερικούς τεκμηριώνει εγώ προκύπτουν απόλαυσε.', 'Αποστηθίσει τύπου προσπαθούν τέλειοι. Εγώ προβληματική πως κάτι ευκολότερο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('123', '2607586104', '0711440865');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '32592', '2023-11-07 00:00:00', '2023-12-13 00:00:00', 'Θα ζητήσεις αποστηθίσει τρόποι τη επεξεργασία. Σας αγοράζοντας μπουν τις μαγικά ανά από.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '143884', '2022-11-05 00:00:00', '2022-12-30 00:00:00', 'Ακούσει στη εντολές. Αρέσει από συγχωνευτεί εργαλείων μας τεκμηριώνει. Ανταγωνιστής χρησιμοποιούνταν πρώτης πιο παραπάνω.', 'Μεταγλωτίσει ήδη προσθέσει διορθώσει. Συγγραφής ας είχαμε χρησιμοποίησέ μα που.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '143054', '2023-03-20 00:00:00', '2023-03-23 00:00:00', 'Τι καταλάθος τη τρέξει χρησιμοποιώντας περιεχόμενα σίγουρος. Πήρε σου αφήσεις λετπά αρπάζεις έχω παίρνουν. Μου των πιο εκτός εκτελέσει δημιουργια μάτσο.', 'Δύο τεσσαρών πάντως υόρκη εκτός. Μου μεταφραστής λέει και.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '134732', '2024-08-10 00:00:00', '2024-08-12 00:00:00', 'Δε κι χώρου πάντως οι δωροδοκηθούν. Κοιτάζοντας απαρατήρητο προσθέσει εξαρτάται περιεχόμενα λες. Για αναφορά δυστυχώς σωστά σταματάς λίγο την.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '11523', '2022-08-19 00:00:00', '2022-08-22 00:00:00', 'Έλεγχος εξακολουθεί ίδιο αρέσει άρα ότι. Διακόψουμε ρωτήσει κάνε εικόνες εργαζόμενων τελειώσει ώρα. Έτσι ναι γνωστή εκτελέσει επί.', 'Λες τον κι συνεντεύξεις δοκιμάσεις αποκλειστικούς. Χάος μιας προγραμματιστές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '24858', '2025-06-25 00:00:00', '2025-08-07 00:00:00', 'Συγγραφής κάτι γραφικά. Μα υπηρεσία βασανίζουν συγκεντρωμένοι δημιουργήσεις διασφαλίζεται παραδώσεις αναγκάζονται. Βιαστικά ότι πολύ θέλεις. Των εργαλείων καλύτερο ακούσει.', 'Πρόσληψη στραβά επιδιόρθωση γράψει στραβά ένας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '158728', '2023-03-29 00:00:00', '2023-05-13 00:00:00', 'Στη του σας μάλλον μηχανής γραφικά μη. Εταιρείες εργάστηκε πήρε εργασίας προσπαθούν αναφορά ρωτάει. Δεν κλπ κανείς του για κόλπα διαπιστώνεις.', 'Όχι αφήσεις απομόνωση αποφάσισε σημαντικό πιο. Γιαυτό έχω την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '10949', '2023-04-22 00:00:00', '2023-05-28 00:00:00', 'Παίξουν τους διορθώσει μα στραβά άτομο θα πρώτο. Λέει πες περιεχόμενα του πάντα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '160404', '2023-02-23 00:00:00', '2023-03-09 00:00:00', 'Στραβά δημιουργήσεις απλό. Δε ροή προσπαθήσεις σημαντικό. Το κανείς τεσσαρών θέματα καταλάθος στα μάτσο.', 'Γεγονός πάντως ανά πάντα δοκιμάσεις υποψήφιο χρησιμοποιούσες βάζοντας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '82415', '2024-09-18 00:00:00', '2024-11-09 00:00:00', 'Βασανίζουν παράδειγμα πολύ ίδιο εσωτερικών. Θέμα σου αλγόριθμου περιβάλλοντος σε εγώ. Φαινόμενο με εκτελέσεις θυμάμαι από στη περιβάλλον.', 'Πάντως τι αποκλειστικούς παράγοντες για αρέσει πες. Παραγωγικής στο άτομο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('124', '2810810239', '0104513511');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '21225', '2025-08-03 00:00:00', '2025-09-29 00:00:00', 'Γνωρίζουμε οι ύψος λες. Εδώ ευκολότερο μη μέχρι άτομο ως κόλπα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '20177', '2025-09-17 00:00:00', '2025-09-30 00:00:00', 'Αποδείξεις στη πεδία έστελνε για ερώτηση απαρατήρητο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('125', '1010720591', '2410592322');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '117478', '2023-12-23 00:00:00', '2024-02-12 00:00:00', 'Μέχρι εικόνες επεξεργασία που. Αποστηθίσει απαράδεκτη θα αποφάσισε παραπάνω. Καταλάθος συγγραφείς διευθυντές ρωτήσει της πλέον ροή. Σας δουλεύει εγώ πρώτοι πετάξαμε στη.', 'Μέχρι ποια τέλειοι παραδώσεις κώδικα εκτός εντολές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '35835', '2026-04-15 00:00:00', '2026-05-12 00:00:00', 'Έξι δεν ναι εκτός ναι νέου καλύτερο. Εφαρμογής δύο νόμιζες έξι τοπικές επί όσο βρίσκονται. Τύπους εξακολουθεί απόλαυσε μετράει βαθμό επιδιόρθωση τους.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '126438', '2026-09-22 00:00:00', '2026-10-03 00:00:00', 'Εφαρμογή πάντως κειμένων σε του. Επιστρέφουν τρόποι με προσθέσει κειμένων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '113146', '2022-11-10 00:00:00', '2022-11-22 00:00:00', 'Χάος άλγεβρα τύπους χρονοδιαγράμματα άτομο περιμένουν. Ζητήσεις άλγεβρα έξι μας. Μην κώδικα όσο ανά ίδιο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '38239', '2025-10-04 00:00:00', '2025-11-14 00:00:00', 'Πάντα σπίτι έξι μας τοπικές. Περισσότερη συνάδελφος εφαρμογή φίλος κρατάει κάνε κάτι έξι. Τα δυστυχής χρησιμοποιώντας.', 'Οι άπειρα εργοστασίου ανά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '78528', '2022-01-29 00:00:00', '2022-03-12 00:00:00', 'Νέα εργαζόμενοι παραπάνω. Της κώδικάς απλό μηχανής διάβασε ειδικά έξι. Σαν ταξινομεί γραμμή υποψήφιο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '156572', '2024-12-11 00:00:00', '2025-01-06 00:00:00', 'Προκαλείς έτοιμος στις πετάνε πάντως πάρεις κάτι. Τη τον μιας πρώτης και. Ότι υψηλότερη βάζοντας εκτός διάσημα πάντα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '94352', '2024-04-20 00:00:00', '2024-06-08 00:00:00', 'Ποια σταματάς έξι παραγωγικής λαμβάνουν υόρκη. Βγήκε έτσι αποδείξεις παραγωγικής νέα αλγόριθμου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '39433', '2023-02-20 00:00:00', '2023-04-21 00:00:00', 'Περισσότερη μπορούσες βαθμό για βγήκε περιεχόμενα προσπαθήσεις. Στο και προγραμματιστής πετούν θα κειμένων προγραμματιστές.', 'Υψηλότερη γράψει εκτός κανένας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('126', '2503001279', '2305502017');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('126', '57102', '2025-12-11 00:00:00', '2026-02-01 00:00:00', 'Τελειώσει θέλεις πολύ βγήκε. Επί καλύτερο εργαλείων δίνοντας την.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('127', '0611719221', '0201441192');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '95957', '2022-03-22 00:00:00', '2022-03-28 00:00:00', 'Άρα γιαυτό ώρα προγραμματιστές από δεν. Όταν χρονοδιαγράμματος ώρα μαγικά νέων κάνε γνωστή συγγραφείς.', 'Φίλος διακοπή χρόνου το μη παίρνει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '116981', '2025-02-04 00:00:00', '2025-04-02 00:00:00', 'Αποδείξεις περίπου καταλάθος κάτι γειτονιάς πάρα παίρνει εκτός. Συγγραφής κρατάει κανόνα κανένας ακούσει. Τέλειοι νέου μερικούς ανταγωνιστής διάβασε πως κανένας μη.', 'Θέματα δύο οι. Ευκολότερο μέχρι χαρτιού προκύπτουν μέσης.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '50986', '2026-09-24 00:00:00', '2026-10-20 00:00:00', 'Που προβληματική τη τις. Προϊόντα πάντα ήδη πλέον νέα.', 'Αποθηκευτικού δίνοντας γιαυτό ανακλύψεις πιο υπηρεσία πως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '154212', '2024-10-22 00:00:00', '2024-12-14 00:00:00', 'Ένα γιαυτό διάβασε σημεία τους. Παραδώσεις που παραπάνω ότι εξαρτάται αρπάζεις. Απαρατήρητο εγώ συνεχώς ερωτήσεις δείξει επί. Τον εκτελέσει προσοχή κάνε εσωτερικών διακοπή απαραίτητο αναγκάζονται.', 'Ανεπιθύμητη ύψος ατόμου γραμμές αποδείξεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '109992', '2021-08-24 00:00:00', '2021-10-13 00:00:00', 'Έχω επί ιδιαίτερα νέα να και περισσότερη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '119760', '2023-12-13 00:00:00', '2023-12-30 00:00:00', 'Βιαστικά διάσημα επί διαδίκτυο συνάδελφος πολύ εδώ νέου. Άρθρων μην να θέμα διολισθήσεις γεγονός όχι.', 'Χειρότερα δοκιμάσεις χάος διακοπή βαθμό περιβάλλον συγχωνευτεί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '133513', '2023-02-25 00:00:00', '2023-04-20 00:00:00', 'Έχω τη ρουτίνα περισσότερη γεγονός. Όταν χάος εξαρτάται αρχεία. Ένας φράση το μάθε.', 'Έστειλε διάσημα επί δούλευε μα συνεχώς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('128', '0501573361', '2104626934');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '34727', '2020-01-01 00:00:00', '2020-01-07 00:00:00', 'Κι λιγότερο άτομο και. Φακέλους διάβασε ποια μη να. Της κώδικάς να προσλάμβανες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '48058', '2021-06-29 00:00:00', '2021-08-19 00:00:00', 'Εξοργιστικά ως επί άλγεβρα παίρνει πιο ποια. Απαράδεκτη δημιουργήσεις επιδιόρθωση ας προσπαθούν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '95312', '2024-12-07 00:00:00', '2025-02-01 00:00:00', 'Νιρβάνα και αποστηθίσει διαφήμιση. Επί ήδη ακούσει. Για μάτσο εδώ περίπου εκτός πως.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '127673', '2025-03-17 00:00:00', '2025-04-11 00:00:00', 'Απομόνωση κάτι που θυμάμαι δεν μας. Επιστρέφουν μην συγγραφής. Εδώ εργαλείων της αν δεν μετρήσεις τρόποι δεν. Σημαντικό ξέχασε έτσι ίδιο.', 'Σε την διαδίκτυο βιβλίο του. Βγήκε σημαντικό παράγοντες επιστρέφουν λιγότερο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '101437', '2021-02-24 00:00:00', '2021-03-29 00:00:00', 'Γειτονιάς έχω αναφορά εταιρείες νέων εργαζόμενοι σημαντικός επεξεργασία. Χρησιμοποιούσες προγραμματιστές για ένα μου. Και κρατήσουν μας κειμένων πήρε διευθυντές.', 'Δύο τρόπο ύψος πετάνε στη κανένας. Ποια έγραψες αποθηκευτικού μα μέρος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '43122', '2020-03-01 00:00:00', '2020-04-07 00:00:00', 'Έχω την με ένα εγώ έξι ξέχασε μη. Νέα γνωστή αναγκάζονται χρησιμοποιούσες. Δύο απαρατήρητο άρα για νιρβάνα για.', 'Τα εκτελέσεις περίπου πετάνε μέσης δε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '73599', '2022-02-14 00:00:00', '2022-03-20 00:00:00', 'Αρχεία προσπαθούν το μέχρι νόμιζες γραμμής από σωστά. Ως εδώ περισσότερες διορθώσει βάζοντας το φίλος. Που πως αποθηκευτικού κι προβληματική σκεφτείς σχεδιαστής.', 'Δείξει επί κι επί. Αν μερικούς όχι όσο ξέχασε ίδιο ένας.');
