INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('129', '94650', '2021-03-16 00:00:00', '2021-04-28 00:00:00', 'Γεύματος παραγωγικής γραμμές εδώ μη αντιλήφθηκαν περισσότερη. Μη αφήσεις κόψεις υποψήφιο μπορούσες βάζοντας υποψήφιο.', 'Εξακολουθεί έξι λαμβάνουν τις έστειλε νιρβάνα.');
