INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('132', '35412', '2024-06-06 00:00:00', '2024-06-22 00:00:00', 'Χρονοδιαγράμματος κρατάει κάνε δημιουργια άπειρα ως. Ότι μετρήσεις εκτός κειμένων. Συγγραφής κανόνα κοιτάζοντας δύο αποστηθίσει πολύ γέλασαν.', 'Μάτσο ιδιαίτερα έστειλε δοκιμάσεις τα φακέλους επιστρέφουν.');
