INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('134', '101321', '2023-05-02 00:00:00', '2023-05-19 00:00:00', 'Επιχείριση έχω έλεγχος περισσότερες δε νέου. Διασφαλίζεται ο που απαράδεκτη καταλάθος διοικητικό.', 'Τρόποι ορίστε διορθώσεις που χρησιμοποιώντας. Έτοιμος σίγουρος όσο εκείνου.');
