INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '154547', '2026-05-04 00:00:00', '2026-05-22 00:00:00', 'Μπουν πακέτων γέλασαν βαθμό άρα τι. Υπηρεσία απίστευτα τοπικές μην περίπου στις. Φράση φράση που εκτελέσεις εργάστηκε πιο διορθώσεις. Που παραγωγικής τελειώσει μην φαινόμενο.', 'Οι σωστά τοπικές τρόπο συνεντεύξεις. Το εγώ κάτι όχι.');
