INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '53852', '2025-01-24 00:00:00', '2025-02-15 00:00:00', 'Προβληματική μέχρι χρησιμοποιούσες. Καλύτερο ελέγχου σου πάρα μη. Ύψος περίπου λιγότερο σας παίξουν έξι.
