INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '30121', '2022-09-30 00:00:00', '2022-11-17 00:00:00', 'Εκτελείται πάρα πετάξαμε την σκεφτείς εκδόσεις. Την κρατάει επενδυτής μη νέο χρησιμοποιούσες ένας. Την μπορούσες πρώτοι την από.', 'Γνωρίζουμε όταν θέμα έτσι. Σημαντικός αρέσει διακοπής μέχρι.');
