INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('136', '2205543692', '1204760829');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('136', '7502', '2023-02-06 00:00:00', '2023-03-08 00:00:00', 'Εγώ ώρα διασφαλίζεται ποσοστό πάντα κι διακοπής μάτσο. Προϊόντα απόλαυσε λετπά υόρκη σημαντικός κειμένων.', 'Σίγουρος παίρνει ως αποδείξεις συνέχεια. Εκτελείται νέα απόλαυσε άπειρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('137', '0405687081', '0601589402');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '104480', '2024-09-25 00:00:00', '2024-11-01 00:00:00', 'Πρώτοι κώδικα χρειάζονται μπουν απίστευτα έτοιμος. Διευθυντές προσοχή χαρτιού παράδειγμα. Και νέων ποσοστό δημιουργια κρατήσουν διαπιστώνεις.', 'Προγραμματιστές μηχανής έλεγχος ερώτηση με περιβάλλοντος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '22711', '2022-09-22 00:00:00', '2022-11-06 00:00:00', 'Ακούσει παράδειγμα μετράει περίπου. Προσθέσει νέο στήλες κρατάει τα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '34039', '2020-04-28 00:00:00', '2020-05-29 00:00:00', 'Μου ότι που σπίτι. Εργοστασίου συνηθίζουν επί τις ημέρα. Βιαστικά ως εκτελέσει καλύτερο πεδία τους προσεκτικά.', 'Απίστευτα εργασίας γεύματος δύο κλπ μας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '22160', '2026-06-12 00:00:00', '2026-06-30 00:00:00', 'Γεγονός μη κανόνα πάρα περίπου εξοργιστικά. Οι έχω ξέχασε πόρτες. Εκτός πάντως διάσημα εδώ γραμμής έτσι.', 'Έξι το εκτελείται εκτός περίπου τη. Ορίστε στο δημιουργια υψηλότερη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '124421', '2021-07-16 00:00:00', '2021-07-31 00:00:00', 'Υόρκη προσοχή σημεία κάνε σε επεξεργασία. Νιρβάνα ίδιο μάτσο διορθώσει δημιουργείς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '123808', '2026-11-16 00:00:00', '2026-11-23 00:00:00', 'Σκεφτείς έγραψες τύπους θέμα εφαρμογής σημεία προσεκτικά ήδη. Ατόμου τέλειοι μη δεδομένων επιστρέφουν μερικούς καλύτερο. Των κι μου. Εξαρτάται συγχωνευτεί πάντως ένας βάζοντας τρέξει όταν ποσοστό.', 'Τι δημιουργείς έγραψες εκδόσεις εκδόσεις γραμμές νέα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '27059', '2026-10-10 00:00:00', '2026-12-01 00:00:00', 'Τρέξει δημιουργήσεις μάτσο σε έχω γραφικά παίξουν. Οι αρχεία συνεντεύξεις άπειρα πολύ αυτήν άρα. Τύπους τι διαφήμιση απαράδεκτη χώρου.', 'Απλό κύκλο ροή πως μετράει. Πόρτες έξι γραμμής δυστυχής τα έξι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '124444', '2026-06-19 00:00:00', '2026-07-16 00:00:00', 'Στέλνοντάς στις πρόσληψη αρέσει απαράδεκτη διάβασε. Μα συνεχώς κρατήσουν τα αποκλειστικούς. Παραπάνω κανόνα κάνε αναφέρονται διακόψουμε.', 'Πως εδώ περισσότερη το τις. Παίξουν δίνοντας ότι. Ημέρα σας βρίσκονται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '123228', '2021-07-05 00:00:00', '2021-08-15 00:00:00', 'Χαρακτηριστικό περιεχόμενα επί. Πρώτοι νέα από λαμβάνουν φακέλους παράγοντες έχω. Δύο παραδοτέου πρόσληψη όταν.', 'Κώδικα στήλες λίγο άρα εντολές.');
