INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '154307', '2022-06-04 00:00:00', '2022-07-24 00:00:00', 'Δε χαρτιού ρουτίνα σημαντικός των από ρωτήσει είχαμε. Κώδικάς τρέξει προβληματική ίδιο έτσι δημιουργήσεις.
