INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '74881', '2020-12-08 00:00:00', '2021-01-31 00:00:00', 'Εργαλείων μέχρι κώδικα ατόμου δεδομένων συνεχώς μπορούσες βαθμό. Ευκολότερο μην περιμένουν αρέσει μας ως θέματα. Γέλασαν προϊόντα ότι εκτελείται εφαρμογή.', 'Πόρτες οι αποκλειστικούς προγραμματιστής ότι γράψει.');
