INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '120289', '2020-03-18 00:00:00', '2020-05-11 00:00:00', 'Εγώ νόμιζες έστελνε ανακλύψεις επί ποια μπορούσες. Πολύ κύκλο κι πάντως κάτι μέχρι χαρακτηριστικό. Εφαρμογή χρονοδιαγράμματα θέματα πεδία.', 'Των πολύ σημαντικό τύπου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '160946', '2021-10-07 00:00:00', '2021-12-05 00:00:00', 'Πάντως σταματάς αυτήν εξακολουθεί εκτός διαφήμιση κι. Χαρακτηριστικό ροή διακοπή δημιουργια.', 'Εκθέσεις αν μέχρι τρέξει κόψεις μην σημαντικό. Χρησιμοποιούσες δυστυχής τρόποι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '6598', '2020-07-26 00:00:00', '2020-08-28 00:00:00', 'Κάτι βγήκε ήδη μιας προσθέσει του. Μας επιστρέφουν πετάνε έχω απαραίτητο τα. Έξι έλεγχος τρόπο δύο ανά διευθυντές.', 'Εφαρμογή διορθώσει κάνε γειτονιάς αναφέρονται ήδη ναι.');
