INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '118260', '2023-01-17 00:00:00', '2023-01-27 00:00:00', 'Ροή πολύ προκύπτουν ερωτήσεις αποφάσισε όσο. Ως εσωτερικών ο πετάνε πλέον. Γράψει δύο εργάστηκε χρειάζονται πλέον γραφικά και.', 'Βιβλίο μιας πες πολύ. Πιο ναι ρωτήσει πλέον. Ότι πόρτες θέμα τρόπο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '55523', '2024-01-10 00:00:00', '2024-02-24 00:00:00', 'Αυτήν πρώτοι το εκτελέσεις άρθρων μα στις. Γειτονιάς ως εξοργιστικά. Ρωτάει προκαλείς κόψεις και πρώτο.', 'Απαράδεκτη γειτονιάς το λέει. Ένα υόρκη πρώτης δύο προσθέσει ο.');
