INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '138610', '2023-05-08 00:00:00', '2023-05-19 00:00:00', 'Τρέξει στέλνοντάς παράδειγμα λοιπόν ποια γραμμή. Προσοχή ημέρα παραπάνω αποθηκευτικού εργαλείων.', 'Σας όσο εικόνες παράδειγμα συνεντεύξεις.');
