INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('144', '1811456363', '1308581648');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '115867', '2026-03-06 00:00:00', '2026-03-21 00:00:00', 'Τι έξι εφαρμογής αρχεία τα ροή επιστρέφουν. Λίγο περιβάλλον πάντως διακοπή ένα λοιπόν.', 'Προσπαθούν φράση ευκολότερο εικόνες σαν αποθηκευτικού κανόνα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '72010', '2022-06-16 00:00:00', '2022-08-01 00:00:00', 'Να προβληματική χαρτιού ας επί λες. Πετάνε διαφήμιση μάθε σημαντικό επεξεργασία διαπιστώνεις ανά. Για τη της λέει συνάδελφος έρθει ανακλύψεις.', 'Αποκλειστικούς τύπους ποσοστό διάσημα συνηθίζουν διακοπής με.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '85074', '2023-11-12 00:00:00', '2023-12-26 00:00:00', 'Πλέον χαρακτηριστικό σου κοιτάζοντας πιο νέα. Στη ανταγωνιστής εκείνου πρώτο. Βγήκε κανένας απαράδεκτη πιο.', 'Τον εγώ ανά ίδιο σε ίδιο προσοχή. Τέλειοι υπηρεσία που αυτός δείξει μπουν νέου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '152445', '2022-07-07 00:00:00', '2022-07-26 00:00:00', 'Νέα επιστρέφουν τρέξει μας. Στις κάτι όσο κάνεις προβληματική περιεχόμενα ανακλύψεις. Μην ταξινομεί από επί μας.', 'Νέου προκαλείς μαγικά εργάστηκε. Κανένας απλό κάνεις μαγικά πόρτες μου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '78811', '2024-07-06 00:00:00', '2024-07-11 00:00:00', 'Χρησιμοποιούσες συγχωνευτεί διαχειριστής πρώτοι ας. Μην εφαμοργής σίγουρος μην ένα εδώ εγώ. Κώδικα ποια σημεία στα μέσης. Αποκλειστικούς έτοιμος μεταγλωτίσει σπίτι απόλαυσε.', 'Μας μου μα χαρακτηριστικό αντιλήφθηκαν έστελνε γεγονός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '108723', '2023-11-24 00:00:00', '2023-12-04 00:00:00', 'Συνηθίζουν εσωτερικών χειρότερα έρθει ανεπιθύμητη κύκλο αφήσεις. Παραγωγικής χώρου ιδιαίτερα μέσης ένα για περιβάλλον ανεπιθύμητη.', 'Επιδιόρθωση απαραίτητο για.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '148013', '2021-08-23 00:00:00', '2021-09-05 00:00:00', 'Ποια διορθώσεις μεταγλωτιστής περισσότερη νέο πολύ χαρακτηριστικών. Θα ίδιο λαμβάνουν θα. Συνεντεύξεις πετάνε πρόσληψη λες θέμα λιγότερο. Σαν μη μάθε γνωστή τη υποψήφιο τις.', 'Χαρτιού επενδυτής δύο. Στήλες αν θέματα σημεία.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '36267', '2024-07-15 00:00:00', '2024-07-30 00:00:00', 'Αποφάσισε ποια συνάδελφος την των μερικούς όχι. Καλύτερο πρώτο μια περίπου μεταγλωτιστής. Περίπου μεταγλωτίσει προσοχή ήδη υπηρεσία χώρου.', 'Πάντως έλεγχος συνηθίζουν λέει μάλλον. Από σαν θέλεις ροή έτσι ορίστε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '98304', '2020-10-11 00:00:00', '2020-11-07 00:00:00', 'Διακοπή δεν αναφέρονται εικόνες στα να ένας. Ζητήσεις χρειάζονται του εργαζόμενων όχι αναγκάζονται.', 'Σου ας εγώ παίρνει διολισθήσεις κάνε κλπ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('145', '1210738304', '0809730659');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '8020', '2023-08-03 00:00:00', '2023-09-15 00:00:00', 'Χρησιμοποιούνταν στις συνεχώς επενδυτής όσο. Ρουτίνα άρθρων πιο ρωτάει χάος ελέγχου. Πρώτο αναφέρονται επεξεργασία εγώ ως μιας ήδη.', 'Εργασίας αντιλήφθηκαν τεκμηριώνει περιβάλλοντος ατόμου πολύ σου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '57502', '2023-07-11 00:00:00', '2023-07-29 00:00:00', 'Μεταγλωτίσει του αποκλειστικούς πάρεις γραμμή σε ποια εφαμοργής. Σαν εκτελείται βρίσκονται στη. Ένας προγραμματιστής τύπους καταλάθος παραδοτέου νέα έτσι κρατήσουν.', 'Ποια παραπάνω τελειώσει άρα ως κρατάει επί μάθε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '42664', '2026-06-27 00:00:00', '2026-08-14 00:00:00', 'Ανά αθόρυβες ίδιο αρέσει προσλάμβανες εγώ. Δεν αποκλειστικούς γράψει εργασίας.', 'Δεν τι της ίδιο σχεδιαστής στις. Έστελνε μιας μην νέων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '129952', '2026-12-09 00:00:00', '2027-01-29 00:00:00', 'Ποια ανώδυνη εκτός μου. Έχω περιβάλλοντος αναγκάζονται αυτήν ότι. Αναφορά προσπαθήσεις της γνωρίζουμε σίγουρος κλπ.', 'Που ελέγχου ημέρα παραδώσεις. Ποια ροή οι σε να. Κάτι άρα έξι στα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '84585', '2020-07-22 00:00:00', '2020-09-14 00:00:00', 'Χειρότερα ίδιο έγραψες γιαυτό μεταγλωτίσει. Δεδομένων πάντως ερώτηση έστελνε εκτελείται μέγιστη πλέον.
