INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '129074', '2024-09-20 00:00:00', '2024-11-08 00:00:00', 'Αρέσει γειτονιάς που στέλνοντάς πες εντολές από διαχειριστής. Ας θα προγραμματιστές αρέσει αρχεία αναφέρονται.', 'Αποφάσισε πολύ δίνοντας ποια χρησιμοποιώντας αναφέρονται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '18253', '2026-02-10 00:00:00', '2026-03-24 00:00:00', 'Ένας δεν δύο φράση παραδώσεις έτοιμος περισσότερη. Ως συγχρόνως δύο χρησιμοποιώντας. Κύκλο πάρα των τοπικές επιστρέφουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '117886', '2024-09-14 00:00:00', '2024-09-30 00:00:00', 'Πλέον αποκλειστικούς ταξινομεί ένας. Από δεν συνηθίζουν βιβλίο εικόνες απίστευτα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '81808', '2025-06-02 00:00:00', '2025-06-06 00:00:00', 'Τρέξει προγραμματιστές κι καλύτερο. Χαρτιού τι δημιουργείς απόλαυσε και ύψος μάλλον.', 'Κανένας φαινόμενο στις κειμένων έτσι λοιπόν. Σημαντικό που μετράει δύο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '135332', '2025-10-03 00:00:00', '2025-11-18 00:00:00', 'Παραδοτέου εξακολουθεί ανταγωνιστής αρέσει εκθέσεις τύπου αυτός λέει. Αναφέρονται εργοστασίου απίστευτα τρόπο λέει θα περιβάλλον. Δύο επιδιορθώσεις χρειάζονται προκύπτουν λαμβάνουν πλέον και.', 'Δύο παράδειγμα συνηθίζουν χαμηλός καλύτερο. Απόλαυσε πρώτης αγοράζοντας πετούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '26387', '2021-12-24 00:00:00', '2021-12-26 00:00:00', 'Παίρνει στα δύο. Εφαρμογή κάνεις έγραψες παράγοντες χαρακτηριστικών ίδιο.', 'Εντολές έτοιμος πάντα ερωτήσεις προϊόντα κρατήσουν ανά κανείς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '110667', '2021-04-27 00:00:00', '2021-06-01 00:00:00', 'Πηγαίου εδώ πάντα άρα δύο αποθηκευτικού μην. Αποδείξεις βασανίζουν πρόσληψη διορθώσεις. Πολύ σου έτσι αποστηθίσει πάρα μερικούς ιδιαίτερα.', 'Αρπάζεις γνωρίζουμε ότι ανταγωνιστής άρθρων τι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '46930', '2025-05-23 00:00:00', '2025-05-26 00:00:00', 'Άλγεβρα εκτός σίγουρος στα δεδομένων. Κανείς κάτι χάος έστειλε μέχρι. Τους κανένας δεν προγραμματιστές. Ότι προσοχή προσεκτικά τους.', 'Σου νιρβάνα μια ανά πόρτες διαχειριστής.');
