INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('147', '55933', '2023-06-19 00:00:00', '2023-07-16 00:00:00', 'Στέλνοντάς ευκολότερο εκτός δεν. Εικόνες κειμένων των προγραμματιστής. Για θέμα ανεπιθύμητη μετράει απαραίτητο πόρτες.', 'Κι έλεγχος σίγουρος. Δίνοντας ότι κανείς διακοπή απαρατήρητο.');
