INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('148', '34453', '2024-10-25 00:00:00', '2024-12-21 00:00:00', 'Ρωτήσει πρώτοι σημεία όσο ξέχασε μάλλον σπίτι τα. Αν ανά συγγραφής στέλνοντάς στο χαρτιού επί. Και τον παίξουν πετούν όταν εδώ τα. Επί δεν χρησιμοποίησέ πως άπειρα ρουτίνα ατόμου.', 'Εφαρμογή φράση υόρκη παραγωγικής πάντως το.');
