INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('149', '134181', '2020-04-24 00:00:00', '2020-05-15 00:00:00', 'Ερώτηση πάντως αναφορά κι γνωρίζουμε περιεχόμενα. Τεσσαρών υπηρεσία εικόνες χαμηλός ως μου του. Χειρότερα σημαντικό δυστυχώς προγραμματιστής.', 'Μια ένα έξι σας γέλασαν στήλες. Μου προσπαθούν κρατάει μετράει μη θέματα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('150', '1412531407', '0910175358');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('150', '105402', '2025-07-27 00:00:00', '2025-08-08 00:00:00', 'Μιας πηγαίου πρώτοι αναφέρονται επιστρέφουν εντολές μέγιστη μας. Μπουν όχι συνεντεύξεις μα θέμα στήλες μερικούς μέχρι. Πακέτων ροή ροή μετράει μα.', 'Μην εργασίας σίγουρος πολύ θα χρόνου. Συγχρόνως ατόμου νόμιζες ανά.');
