INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('151', '133820', '2024-04-29 00:00:00', '2024-05-16 00:00:00', 'Πρόσληψη αναφορά πάντως κλπ σπίτι γιαυτό εκτός. Πηγαίου στραβά διοικητικό γεγονός βιβλίο άρα μην τρόποι. Ναι τι αναγκάζονται δοκιμάσεις φακέλους.', 'Στέλνοντάς συνάδελφος κοιτάζοντας εσωτερικών δύο.');
