INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('152', '138115', '2026-12-05 00:00:00', '2026-12-28 00:00:00', 'Πάρεις υποψήφιο βασανίζουν μάθε διάβασε προσεκτικά. Οι σου έρθει επεξεργασία τα χρονοδιαγράμματα άρα έστελνε.', 'Δυστυχής καλύτερο πάρα.');
