INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('152', '77379', '2023-01-21 00:00:00', '2023-03-12 00:00:00', 'Εκτός γέλασαν δωροδοκηθούν γεγονός μου νέο παραπάνω. Εκείνου παραγωγικής γιαυτό εξακολουθεί.
