INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('154', '1010720591', '2009617682');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '25268', '2024-10-10 00:00:00', '2024-11-10 00:00:00', 'Εργαζόμενων δουλεύει ως ήδη ως έλεγχος το χώρου. Ύψος συγχρόνως ποσοστό.', 'Προϊόντα ειδικά κόψεις βασανίζουν κανόνα σπίτι όσο του. Μπουν κώδικάς κανείς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '141855', '2026-09-09 00:00:00', '2026-10-24 00:00:00', 'Ήδη σταματάς γραφικά στα μετρήσεις για ρωτήσει. Κλπ χρησιμοποιώντας αρχεία αναφορά τον. Είχαμε τελειώσει χρησιμοποιούνταν.', 'Φακέλους αποδείξεις ξέχασε αρπάζεις κειμένων χρησιμοποιώντας πρώτοι σου.');
