INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '61318', '2022-01-10 00:00:00', '2022-01-13 00:00:00', 'Γέλασαν του συγχωνευτεί κοιτάζοντας. Ποσοστό εκδόσεις προσπαθήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '135104', '2022-12-23 00:00:00', '2023-01-04 00:00:00', 'Είχαμε σίγουρος κλπ βασανίζουν υποψήφιο τους θα εδώ.
