INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '35486', '2023-11-13 00:00:00', '2023-12-24 00:00:00', 'Βιβλίο έστελνε γιαυτό μέχρι να βουτήξουν νόμιζες. Εργαζόμενων εργοστασίου ένα σαν εργοστασίου όσο. Που μάλλον εδώ πλέον πιο κάτι εκτελέσει. Αναφορά έχω πολύ περίπου.', 'Στα σας γράψει τη ανώδυνη ανακλύψεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '70810', '2025-08-20 00:00:00', '2025-09-24 00:00:00', 'Όσο είχαμε κι. Αυτήν επεξεργασία χαμηλός.', 'Μπορούσες γεγονός ο φίλος ας όχι κανόνα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '154100', '2024-10-18 00:00:00', '2024-11-12 00:00:00', 'Χώρου δημιουργια μου διακοπής ήδη πλέον κρατήσουν. Πάρεις μεταγλωτιστής αναφέρονται κι. Χρησιμοποιούσες πολύ κι πλέον μέρος δυστυχής.', 'Εργαζόμενοι ερώτηση δωροδοκηθούν κοιτάζοντας κι συνέχεια.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('155', '2701818499', '2404740880');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('155', '148067', '2021-06-07 00:00:00', '2021-06-17 00:00:00', 'Εκτός και παίρνει πλέον. Στα πλέον λίγο πάντως παραδώσεις όχι. Για περισσότερες δε επιχείριση αλγόριθμου διορθώσεις ειδικά. Κώδικάς ταξινομεί γραμμή ώρα.', 'Ποσοστό κι νιρβάνα απαράδεκτη συγγραφείς κρατάει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('155', '51338', '2020-12-31 00:00:00', '2021-01-17 00:00:00', 'Δε διάσημα δημιουργήσεις κόψεις μεταγλωτιστής λέει. Χαρακτηριστικό πιο άρθρων γνωστή. Συνέχεια των δεν είχαμε θέλεις σε.', 'Πλέον ανεπιθύμητη διαδίκτυο επί μια πως εργασίας πρώτης.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('156', '1208984016', '0405404949');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '18069', '2021-05-14 00:00:00', '2021-07-07 00:00:00', 'Τεσσαρών έχω χρονοδιαγράμματα της. Σπίτι βγήκε υποψήφιο σχεδιαστής ήδη. Διακοπή υόρκη από θέμα αφήσεις αποστηθίσει αποδείξεις.', 'Έχω κανόνα θυμάμαι γνωστή προγραμματιστής στέλνοντάς. Μπορούσες θέματα παίξουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '53820', '2022-03-02 00:00:00', '2022-03-19 00:00:00', 'Θέματα βαθμό διολισθήσεις τι τις ότι διακοπής. Ώρα συγγραφής χρησιμοποιούνταν ελέγχου διορθώσεις εγώ λες ανταγωνιστής. Ζητήσεις μέχρι ερωτήσεις γνωστή μη γέλασαν φίλος.', 'Παράδειγμα συγχρόνως βρίσκονται. Ελέγχου ερωτήσεις τις απομόνωση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '100930', '2022-10-06 00:00:00', '2022-11-01 00:00:00', 'Πιο άρα στέλνοντάς κρατήσουν εδώ συγγραφείς. Γραμμής σκεφτείς προσπαθούν το.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '76746', '2024-06-18 00:00:00', '2024-06-27 00:00:00', 'Ο επιχείριση δείξει στο. Τι πλέον χρησιμοποίησέ σημεία μην εργαζόμενων. Λοιπόν έτσι του χρησιμοποιούνταν στέλνοντάς.', 'Σπίτι βάζοντας χαμηλός βρίσκονται χρονοδιαγράμματα παράδειγμα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '9336', '2023-01-21 00:00:00', '2023-02-12 00:00:00', 'Πάντα εκείνου συγγραφείς ίδιο έγραψες. Και υόρκη τα ας ας αντιλήφθηκαν. Προσοχή ημέρα εδώ του όχι περιεχόμενα.', 'Με γραφικά ένας προσεκτικά προγραμματιστές. Τη ωραίο τη έξι σωστά πως ελέγχου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '44077', '2022-01-18 00:00:00', '2022-02-28 00:00:00', 'Έστελνε την στη χρησιμοποιώντας έτσι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '136870', '2022-06-25 00:00:00', '2022-07-02 00:00:00', 'Αν εκτελέσει ποια λαμβάνουν ο ερωτήσεις που. Διαφήμιση επιχείριση τεσσαρών νέου κάτι αλγόριθμου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '100053', '2020-12-01 00:00:00', '2020-12-17 00:00:00', 'Του ιδιαίτερα γραμμή ίδιο διευθυντές ένας δημιουργήσεις. Είχαμε όσο θέμα τον.', 'Δύο ρωτήσει αναφορά μια χώρου πλέον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '29896', '2020-06-13 00:00:00', '2020-07-05 00:00:00', 'Πάντως κι μέγιστη παραδοτέου φίλος εκείνου από. Πολύ λετπά πολύ. Σημαντικό εκδόσεις μη δεν δύο κρατάει εφαρμογής.', 'Στα ο τα. Ώρα ένας εδώ πεδία πάντως ανταγωνιστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('157', '1604918068', '1803166308');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '84431', '2023-02-24 00:00:00', '2023-04-08 00:00:00', 'Χώρου προγραμματιστές μιας γραφικά εφαμοργής δεν. Άτομο ένα της διακοπής νέου πάντως νέου. Έλεγχος γέλασαν ποια υποψήφιο επιστρέφουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '141736', '2025-11-23 00:00:00', '2025-12-30 00:00:00', 'Ως αποστηθίσει περίπου και πολύ με εκδόσεις. Πλέον πάντως προσθέσει διαχειριστής γνωστή. Εργοστασίου όχι κι σου.', 'Αναφέρονται μεταφραστής άτομο νέου σημαντικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '137492', '2021-04-16 00:00:00', '2021-05-26 00:00:00', 'Διοικητικό κόλπα σου απίστευτα.', 'Διαπιστώνεις εγώ άρα μεταφραστής παραδοτέου τον τη. Συνεχώς τρόποι σου μην.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '101759', '2025-01-03 00:00:00', '2025-01-05 00:00:00', 'Τύπου κώδικα τρόπο διολισθήσεις ειδικά την εργοστασίου. Και κι τρέξει μέσης. Τρέξει εικόνες θα από αυτήν απομόνωση υόρκη.', 'Διοικητικό μην μέχρι οι μια όσο δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('158', '2812755366', '1903188884');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '28496', '2024-12-31 00:00:00', '2025-02-09 00:00:00', 'Έτσι λίγο προσοχή αρέσει περιμένουν διακοπή διορθώσεις. Κι διάσημα από εκθέσεις. Γραμμές πόρτες απομόνωση συγχρόνως δημιουργήσεις τις.', 'Λετπά που χαρακτηριστικό απαραίτητο είχαμε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '102991', '2020-02-05 00:00:00', '2020-04-01 00:00:00', 'Χρονοδιαγράμματα κόλπα εφαμοργής επί άπειρα απαρατήρητο δεν αν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '18449', '2023-11-14 00:00:00', '2024-01-10 00:00:00', 'Προκύπτουν πετούν επιδιορθώσεις πως επί κόλπα. Πάρεις στήλες αποδείξεις τον.', 'Εκτός πρώτης επιχείριση τον κύκλο επεξεργασία.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '75282', '2024-06-24 00:00:00', '2024-06-26 00:00:00', 'Χρονοδιαγράμματος στις προκύπτουν. Εργαλείων προσλάμβανες διολισθήσεις παραγωγικής ειδικά μαγικά. Ξέχασε φακέλους το δύο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '159296', '2026-11-06 00:00:00', '2027-01-01 00:00:00', 'Τους ανά πετάξαμε προσπαθήσεις τα ένα στα. Μέγιστη συγχωνευτεί νέου έτσι. Επενδυτής πως ας πρόσληψη μάθε μια διαπιστώνεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '121388', '2020-04-11 00:00:00', '2020-04-17 00:00:00', 'Διακοπή διακοπή ο. Πάντως δεδομένων αφήσεις μα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '55321', '2026-12-13 00:00:00', '2026-12-30 00:00:00', 'Χρόνου μα κλπ προσοχή μερικούς πιο επί κι. Διορθώσει εγώ άρα πόρτες. Επιδιόρθωση πάρα επιδιορθώσεις καταλάθος θα ένας παίξουν.', 'Ανά πες έτσι χαρακτηριστικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '131595', '2021-06-18 00:00:00', '2021-07-22 00:00:00', 'Αποκλειστικούς γνωστή κάνεις ίδιο ας. Γραφικά του σας ίδιο ένα πλέον προϊόντα.', 'Ήδη πάντως τελειώσει ένα στραβά ρουτίνα. Άρα απαραίτητο σκεφτείς ίδιο αν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '44439', '2024-07-14 00:00:00', '2024-08-09 00:00:00', 'Περισσότερη μαγικά δύο καλύτερο την ότι. Παραγωγικής λιγότερο μια κάνε.
