INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '136254', '2021-08-24 00:00:00', '2021-09-11 00:00:00', 'Επιχείριση το στη απόλαυσε. Πάντα προβληματική τελειώσει διάσημα διορθώσει πλέον που.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '97210', '2020-02-16 00:00:00', '2020-02-29 00:00:00', 'Να κοιτάζοντας ορίστε τις έχω μέρος. Στέλνοντάς των κρατάει σίγουρος γιαυτό αναφέρονται ποια. Επιδιορθώσεις ποια ιδιαίτερα τύπου.', 'Δεν εργαζόμενων ειδικά δεν τοπικές συνηθίζουν εργάστηκε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '60582', '2026-10-28 00:00:00', '2026-11-02 00:00:00', 'Δημιουργια συνηθίζουν αλγόριθμου διορθώσει δείξει. Όταν αφήσεις παράδειγμα μας πετάξαμε ζητήσεις. Παράδειγμα εσωτερικών βρίσκονται διορθώσει δε προκύπτουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '130088', '2021-04-05 00:00:00', '2021-05-30 00:00:00', 'Διοικητικό ατόμου αποφάσισε αποστηθίσει σίγουρος δε θέλεις ανταγωνιστής. Δε αποθηκευτικού πως ως παραγωγικής.', 'Έτσι κι ύψος πως στα και βιαστικά. Προϊόντα κλπ δυστυχής ναι όσο πάρα αθόρυβες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '161097', '2020-12-11 00:00:00', '2020-12-20 00:00:00', 'Μη αποδείξεις σημεία έχω παραδώσεις εφαμοργής τεκμηριώνει τρόπο. Άρα τύπου να ερώτηση γιαυτό σαν ιδιαίτερα.', 'Υψηλότερη ώρα εδώ τρόποι στήλες αναφορά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '136878', '2021-10-06 00:00:00', '2021-10-10 00:00:00', 'Συνέχεια στραβά πως. Αθόρυβες σημεία αποκλειστικούς παράγοντες διορθώσεις πλέον προκύπτουν.', 'Δωροδοκηθούν τους κύκλο φίλος κόλπα αλγόριθμου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '68736', '2024-10-24 00:00:00', '2024-12-06 00:00:00', 'Ξέχασε μην περιβάλλον λιγότερο. Καλύτερο χώρου εξακολουθεί χαρακτηριστικών προκαλείς σαν. Χειρότερα δε εγώ δυστυχώς μην τα πολύ.', 'Που ημέρα συγκεντρωμένοι γεγονός διάσημα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '146684', '2022-03-22 00:00:00', '2022-05-10 00:00:00', 'Έγραψες μέρος κρατήσουν χαρακτηριστικό. Λετπά ποια τον εκθέσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '90104', '2021-02-01 00:00:00', '2021-02-17 00:00:00', 'Όσο συγχρόνως άλγεβρα φράση έγραψες δημιουργήσεις σου μιας. Εργαζόμενων δυστυχής ελέγχου γνωστή μάλλον.', 'Για στο εκείνου λετπά που εκτός εκδόσεις. Κι σωστά στήλες πολύ εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '66450', '2026-04-18 00:00:00', '2026-06-17 00:00:00', 'Μάθε μου ο όσο διορθώσει τους. Δίνοντας μπουν αφήσεις κάνεις μεταφραστής. Ως βουτήξουν εκτός προκαλείς στο τα.', 'Εκδόσεις σε βιβλίο εγώ. Τη αρέσει παίρνει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('160', '2812755366', '1104424605');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('160', '10928', '2020-08-23 00:00:00', '2020-10-11 00:00:00', 'Εφαρμογής την εσωτερικών βιαστικά γραφικά όταν. Περίπου στα προσπαθήσεις όσο διαδίκτυο κρατήσουν. Κάτι νέων συγγραφείς τρέξει κρατήσουν ανταγωνιστής.', 'Τα και κανόνα άρα κάνε προσοχή βουτήξουν δωροδοκηθούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('160', '3880', '2026-08-07 00:00:00', '2026-08-14 00:00:00', 'Άρα το εκτός πολύ απαραίτητο εταιρείες. Πλέον έχω τα έτοιμος προϊόντα εργαζόμενοι. Προσοχή παίξουν πως και μια δοκιμάσεις.', 'Παραδοτέου δεν έχω στη προκαλείς ήδη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('161', '2310644379', '2112593692');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '160056', '2025-11-20 00:00:00', '2026-01-11 00:00:00', 'Αυτήν από πάντα δε από σχεδιαστής τύπου. Δείξει κρατάει οι ο χαρακτηριστικών γραμμές ας με.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '157320', '2020-05-13 00:00:00', '2020-05-31 00:00:00', 'Έστειλε μια αποκλειστικούς γνωστή. Ήδη μου χαρακτηριστικών επιστρέφουν χρησιμοποίησέ νέου πάντως. Ρουτίνα υψηλότερη ερώτηση διάσημα προγραμματιστές.', 'Τους αναφέρονται όχι. Στις την δυστυχώς. Κανείς εκτελέσει θυμάμαι γραμμές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '72984', '2021-05-28 00:00:00', '2021-07-07 00:00:00', 'Έστελνε πακέτων τα έγραψες. Χρησιμοποιούνταν περισσότερη κώδικα θέματα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '69015', '2021-11-01 00:00:00', '2021-11-05 00:00:00', 'Λέει πλέον αρχεία χρόνου μέρος νέο σχεδιαστής. Επεξεργασία μια προσλάμβανες και. Των εκτελέσει κάνε οι.', 'Πηγαίου καταλάθος εργαζόμενων πάντα έχω τις μπορούσες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '104301', '2022-06-15 00:00:00', '2022-08-14 00:00:00', 'Πετάνε έτσι σε εργαζόμενοι έτσι. Τεσσαρών μου μάτσο χαρακτηριστικών παίρνουν της.', 'Στη σημεία κάτι. Σημαντικός δύο εκτός προσεκτικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '160446', '2021-02-12 00:00:00', '2021-02-24 00:00:00', 'Παραγωγικής πακέτων χρησιμοποιώντας τη κι ανώδυνη που απαρατήρητο. Στέλνοντάς επιχείριση εκτελείται τις τρόποι εδώ ανεπιθύμητη. Και τους μάτσο.', 'Γραφικά τον λαμβάνουν δεδομένων προϊόντα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '145318', '2024-07-24 00:00:00', '2024-08-01 00:00:00', 'Ώρα χρησιμοποιούσες σίγουρος πρώτης νόμιζες. Κάνε παραπάνω τελειώσει τους.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '108393', '2023-12-30 00:00:00', '2024-01-19 00:00:00', 'Συνέχεια από αν. Προσθέσει στα χρόνου μέχρι εργαλείων που πως. Έτοιμος μη τελειώσει μάτσο καλύτερο τεσσαρών.', 'Μέχρι διακοπή λιγότερο κώδικα μιας θα παίρνει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('162', '0910904414', '1704859147');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '58509', '2022-10-03 00:00:00', '2022-11-18 00:00:00', 'Μην που κόψεις παράδειγμα μέχρι χρονοδιαγράμματα. Σημαντικός και απαραίτητο διορθώσει χαρακτηριστικών. Κανείς ευκολότερο έχω.', 'Ποια την περιεχόμενα χρειάζονται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '86225', '2023-08-11 00:00:00', '2023-08-24 00:00:00', 'Στο επιχείριση συνάδελφος χρησιμοποιούνταν. Σου σωστά σας δημιουργια υόρκη δίνοντας. Δουλεύει κώδικάς προσπαθήσεις έρθει εδώ γιαυτό.', 'Προσπαθήσεις πρόσληψη της κρατήσουν. Ήδη πάρα τις λοιπόν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '75135', '2022-09-07 00:00:00', '2022-09-09 00:00:00', 'Των πάντα κι υόρκη. Προσεκτικά ύψος άλγεβρα παίρνουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('163', '0204747049', '1405927493');
