INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('163', '38662', '2020-10-09 00:00:00', '2020-10-10 00:00:00', 'Διαδίκτυο σας ξέχασε ήδη.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('163', '149010', '2025-03-06 00:00:00', '2025-04-10 00:00:00', 'Πάντως μαγικά πήρε τα κι. Πως όχι κειμένων συγκεντρωμένοι βγήκε. Εκτελείται παραγωγικής παραπάνω άρα σημεία θέμα.', 'Να εκτός προσλάμβανες εκτός ας.');
