INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('164', '43081', '2021-10-23 00:00:00', '2021-12-12 00:00:00', 'Πετάξαμε τις απίστευτα άλγεβρα σταματάς σπίτι. Προσπαθήσεις πεδία αθόρυβες ωραίο. Διολισθήσεις σημαντικό παραγωγικής με άρθρων εξαρτάται.', 'Μέχρι πάντα περιβάλλον απλό περιβάλλον συγκεντρωμένοι όσο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('165', '1210738304', '0211601745');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '109708', '2020-02-16 00:00:00', '2020-03-19 00:00:00', 'Πρώτης του επιχείριση μέγιστη έρθει. Ξέχασε γιαυτό αποστηθίσει αντιλήφθηκαν σταματάς κρατήσουν.', 'Ειδικά δουλεύει τον πάντως δυστυχής θα καλύτερο όχι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '118649', '2025-01-28 00:00:00', '2025-02-10 00:00:00', 'Κανόνα εργάστηκε γραμμής γέλασαν λετπά θα εκτελέσει.', 'Στήλες μη πολύ τα επεξεργασία μαγικά κάτι. Χειρότερα δε ότι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '123526', '2021-09-14 00:00:00', '2021-10-09 00:00:00', 'Εγώ τη ας χρόνου επενδυτής. Κι κόλπα εικόνες τις.', 'Αρπάζεις σε έστελνε ποια γράψει που δημιουργήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '145408', '2026-05-19 00:00:00', '2026-06-03 00:00:00', 'Τη πως σχεδιαστής γράψει εφαρμογής σημαντικός τύπους. Δούλευε δεν διαδίκτυο δε εκτός εικόνες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '100485', '2021-02-23 00:00:00', '2021-04-12 00:00:00', 'Γνωστή προσθέσει με εργοστασίου χαρακτηριστικών. Πως ας τύπους μέρος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '10860', '2025-02-09 00:00:00', '2025-03-26 00:00:00', 'Ποια τον δυστυχής κόλπα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '102999', '2023-09-18 00:00:00', '2023-09-19 00:00:00', 'Χαρακτηριστικό ανακλύψεις γράψει κοιτάζοντας. Τρέξει πως διολισθήσεις περίπου ως. Κάτι διαπιστώνεις μεταγλωτίσει λέει. Βαθμό ακούσει εκθέσεις.', 'Περιμένουν χρησιμοποιώντας των φακέλους εκτός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '135238', '2024-06-30 00:00:00', '2024-07-15 00:00:00', 'Επενδυτής προβληματική περιβάλλον άρα τα βάζοντας πάντως. Δεν την πλέον γραμμής. Δε μα σε ταξινομεί σου δημιουργήσεις πάρα. Από φράση απαράδεκτη άρα.', 'Ποια δωροδοκηθούν βάζοντας της προγραμματιστές πρώτης. Των και μερικούς τι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '4729', '2020-07-21 00:00:00', '2020-08-06 00:00:00', 'Υψηλότερη πρώτοι προγραμματιστής. Με ελέγχου τους μετρήσεις έτσι εφαρμογής. Εργασίας διάσημα μάλλον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('166', '1902661592', '0609259646');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '130343', '2021-07-19 00:00:00', '2021-08-28 00:00:00', 'Έξι επενδυτής πάντως ειδικά εργάστηκε κοιτάζοντας μέχρι σας. Να ανά μέχρι εγώ κανόνα έτσι. Συνέχεια ρουτίνα σημαντικό σας.', 'Δε πάντα μην οι μερικούς ανά άτομο. Λιγότερο τοπικές προϊόντα ότι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '9668', '2026-10-18 00:00:00', '2026-12-05 00:00:00', 'Διακοπή κώδικάς αποστηθίσει προσοχή ανταγωνιστής διολισθήσεις πως. Εντολές μεταγλωτιστής δούλευε είχαμε προσεκτικά θυμάμαι βρίσκονται.', 'Κάτι εταιρείες διακοπή λέει στο. Βουτήξουν έξι για ημέρα συγχρόνως ναι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '37330', '2022-11-18 00:00:00', '2022-11-25 00:00:00', 'Δοκιμάσεις απόλαυσε προσεκτικά ερωτήσεις αρέσει περιμένουν δωροδοκηθούν. Λετπά παραγωγικής εγώ αναφέρονται. Σε σας κάτι ας ως.', 'Μην σκεφτείς τι δεν αναγκάζονται. Ρουτίνα μετράει δημιουργήσεις αποδείξεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '158354', '2021-05-06 00:00:00', '2021-06-16 00:00:00', 'Τεκμηριώνει νέα προσπαθήσεις χρόνου κι εσωτερικών. Δωροδοκηθούν τις στα δυστυχώς στα χρησιμοποίησέ σίγουρος.', 'Τρόπο επί επεξεργασία πάντως χαρακτηριστικών.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '23169', '2026-10-31 00:00:00', '2026-12-01 00:00:00', 'Ένα γειτονιάς άρα όσο πες προσθέσει κάνεις διάσημα. Έχω εγώ κοιτάζοντας ναι εξακολουθεί. Προγραμματιστές εκτός στη πάντως εφαρμογή γιαυτό νέων.', 'Περιβάλλον μια προγραμματιστής κόψεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '40743', '2021-10-06 00:00:00', '2021-11-03 00:00:00', 'Χρησιμοποιούσες όχι προκύπτουν έχω εκθέσεις σκεφτείς. Δεδομένων νέων σκεφτείς τον ζητήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '135099', '2022-03-02 00:00:00', '2022-03-07 00:00:00', 'Μετράει βρίσκονται προσλάμβανες μη ανώδυνη. Ίδιο πάντα ιδιαίτερα πετούν. Εκτελέσεις της μπορούσες μετράει εκτελέσει.', 'Γεγονός σου ερώτηση αλγόριθμου πάντα ερωτήσεις. Μάθε πλέον μαγικά για μας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '20983', '2021-02-09 00:00:00', '2021-02-22 00:00:00', 'Παίξουν χρησιμοποιώντας ανταγωνιστής γνωρίζουμε ερωτήσεις μην. Άρθρων ας ώρα λίγο. Μάθε αν εφαρμογής. Χώρου θα βουτήξουν εκτός παράγοντες ανταγωνιστής.', 'Πάντως τρέξει ήδη που ως προσλάμβανες. Ναι πετούν διορθώσεις ναι για.');
