INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('170', '20087', '2024-05-25 00:00:00', '2024-06-24 00:00:00', 'Υπηρεσία σημαντικός δημιουργήσεις τα σπίτι ύψος πάντα. Μετράει σημαντικός συνέχεια έστελνε σημαντικός βγήκε εφαρμογής λοιπόν. Μετρήσεις ποια δούλευε αλγόριθμου εξοργιστικά μαγικά ναι συγγραφής.', 'Αποφάσισε μας την παράγοντες απίστευτα ας για.');
