INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '104148', '2020-10-05 00:00:00', '2020-11-23 00:00:00', 'Ναι κειμένων τέλειοι έλεγχος αποστηθίσει συνηθίζουν. Παίρνει μεταφραστής ως τρέξει μάτσο πρώτοι.', 'Εκτελείται κι σας πάρα ανά. Πιο τι καταλάθος που βρίσκονται εργαζόμενοι μη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '87711', '2021-09-01 00:00:00', '2021-09-20 00:00:00', 'Διάβασε σαν ταξινομεί. Γεγονός συνέχεια χρησιμοποιούσες αγοράζοντας μπουν έξι όχι την. Τεκμηριώνει ελέγχου ίδιο όχι διευθυντές εδώ μηχανής. Όχι έτσι χρόνου κάτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '158325', '2022-08-24 00:00:00', '2022-10-02 00:00:00', 'Σε λιγότερο χρησιμοποιώντας ατόμου προσπαθούν ως ζητήσεις. Του γραμμής σας κάτι. Δε επί σκεφτείς πιο τρόποι. Εκθέσεις απομόνωση δε έχω μιας δεν χρησιμοποιούσες μην.', 'Ερωτήσεις σας ένα ως. Σημεία τη κάτι ακούσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '134431', '2026-01-31 00:00:00', '2026-02-08 00:00:00', 'Έξι ρουτίνα σε όχι. Πολύ απαράδεκτη ήδη στη τον σημαντικό. Λέει διαπιστώνεις παραγωγικής θα καταλάθος.', 'Γνωρίζουμε δεν μέγιστη αθόρυβες κανόνα. Τα περιεχόμενα αρχεία τι ας εκτελείται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '73952', '2024-09-09 00:00:00', '2024-09-24 00:00:00', 'Πάντως όταν θέμα. Το μεταγλωτίσει έχω αλγόριθμου υψηλότερη ίδιο πόρτες πως. Κειμένων θέλεις κόλπα τι. Αν επενδυτής εκθέσεις την κάνε.', 'Μετράει ήδη ερωτήσεις άρα βασανίζουν σπίτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '159748', '2022-12-15 00:00:00', '2023-01-15 00:00:00', 'Κι πιο μη εσωτερικών τις συνεντεύξεις σημαντικό. Κανένας τελειώσει φαινόμενο ναι ίδιο. Γραμμή σαν τις φαινόμενο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('173', '1510425991', '2206233717');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '25574', '2020-03-04 00:00:00', '2020-03-19 00:00:00', 'Προσλάμβανες πακέτων δε με αναγκάζονται έτσι. Γνωστή ναι ο νιρβάνα εκτελέσει.', 'Άτομο πως εδώ μια. Τύπους μην συγγραφής συγχωνευτεί δεν πρώτης.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '146145', '2025-12-16 00:00:00', '2026-02-11 00:00:00', 'Ας που εργαζόμενων ποια ανταγωνιστής. Χαρακτηριστικών διάβασε ίδιο πρώτης από ως διαχειριστής. Προβληματική εσωτερικών που σου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '93121', '2026-05-05 00:00:00', '2026-06-15 00:00:00', 'Μέχρι σαν προσπαθήσεις πεδία τύπου. Δεν στις λοιπόν λέει. Εκτελέσεις αναφέρονται διάσημα ένας πολύ προσθέσει όταν. Τρόποι έστειλε ως κανόνα ποια στο πολύ.', 'Γέλασαν δε θέματα διακόψουμε μέχρι συγκεντρωμένοι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '143434', '2026-09-28 00:00:00', '2026-10-28 00:00:00', 'Προϊόντα κρατήσουν προσθέσει ας ωραίο ο. Παραδώσεις δείξει μάτσο φαινόμενο ένας. Γραμμές τι μου ρωτάει.', 'Ο παράγοντες πως τι. Έγραψες της μια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '39269', '2021-03-02 00:00:00', '2021-04-30 00:00:00', 'Υπηρεσία συγχρόνως συγχρόνως μας. Ως στα κι σταματάς. Πάντα εκτελέσεις πολύ εικόνες.', 'Εργάστηκε δωροδοκηθούν βιαστικά γραμμής ακούσει λίγο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '1686', '2024-09-27 00:00:00', '2024-10-03 00:00:00', 'Απαράδεκτη υόρκη ανώδυνη απαράδεκτη της ανά επί λέει. Χειρότερα στραβά συγγραφείς δύο κι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '116378', '2020-08-26 00:00:00', '2020-10-20 00:00:00', 'Βιαστικά υπηρεσία επιστρέφουν χάος το θέλεις. Είχαμε βαθμό μέχρι εδώ κειμένων υψηλότερη. Απαραίτητο λέει εδώ εσωτερικών λαμβάνουν ότι.', 'Έτσι τον πρώτης με πάρα δεν. Τη ζητήσεις αναγκάζονται φαινόμενο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('174', '2301866576', '1511821127');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('174', '28118', '2024-03-23 00:00:00', '2024-05-11 00:00:00', 'Και λες γιαυτό τρόπο συνεντεύξεις μην. Διάβασε έχω αφήσεις μη καλύτερο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('174', '149186', '2020-04-26 00:00:00', '2020-05-26 00:00:00', 'Διαφήμιση τις νέα ώρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('175', '1307652974', '0706254385');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '41823', '2022-01-09 00:00:00', '2022-02-06 00:00:00', 'Άτομο ευκολότερο πολύ διαδίκτυο. Κι αγοράζοντας σας οι να. Διασφαλίζεται μα διάσημα παραδώσεις τρόποι μέχρι εξακολουθεί χρησιμοποιούνταν. Στη στα εξακολουθεί θέλεις θέλεις μπορούσες ήδη φαινόμενο.', 'Εγώ πεδία πεδία προκαλείς πιο όταν. Διαπιστώνεις εκτός σας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '31577', '2021-01-26 00:00:00', '2021-03-20 00:00:00', 'Άρα λετπά ελέγχου άρθρων πως νόμιζες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '98155', '2022-05-26 00:00:00', '2022-06-30 00:00:00', 'Πάρα συγχωνευτεί κοιτάζοντας τη ωραίο πιο νέα. Αυτήν ποια καταλάθος στις περιβάλλον κάτι. Σου πάντα διοικητικό ιδιαίτερα.', 'Σε περιβάλλοντος κανένας να ποια.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('176', '2012726759', '1410543195');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '12071', '2022-05-16 00:00:00', '2022-07-08 00:00:00', 'Αποκλειστικούς επιδιορθώσεις πετάνε νέο. Μας δύο υποψήφιο εφαρμογής. Εταιρείες σαν ίδιο της εντολές.', 'Προσοχή προσεκτικά την έτσι υπηρεσία γνωστή περιεχόμενα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '147355', '2022-11-09 00:00:00', '2022-12-26 00:00:00', 'Λίγο χρονοδιαγράμματα ειδικά μας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '5505', '2020-10-05 00:00:00', '2020-11-10 00:00:00', 'Ανά στα διακοπής παίρνουν τρέξει τρόποι σπίτι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '140837', '2026-02-28 00:00:00', '2026-03-20 00:00:00', 'Έτσι ειδικά σημαντικό ανά αν νέα. Δημιουργείς μπουν δύο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '153300', '2022-07-18 00:00:00', '2022-08-16 00:00:00', 'Βιαστικά δούλευε από υψηλότερη ποια. Διασφαλίζεται χρησιμοποιούνταν χαρακτηριστικό ανταγωνιστής διαδίκτυο πετάξαμε λίγο.', 'Δημιουργήσεις παραγωγικής φίλος επιχείριση θα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '98013', '2023-09-11 00:00:00', '2023-09-20 00:00:00', 'Ίδιο καλύτερο μας μου και γνωστή. Συγγραφής χάος που γραμμές γνωστή πάρεις κώδικάς. Ζητήσεις και δε σας αρπάζεις ρουτίνα προβληματική. Εκτός βαθμό άλγεβρα προσπαθούν.', 'Απαρατήρητο χρόνου τη μαγικά. Κλπ διοικητικό τα λέει. Που άρα σωστά στήλες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('177', '0507856932', '1509104877');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '61109', '2023-06-29 00:00:00', '2023-07-18 00:00:00', 'Πρόσληψη εγώ ναι ρωτάει όσο κλπ τα φακέλους. Πεδία μέχρι εικόνες κανείς στη απαραίτητο.', 'Αναγκάζονται νέα μιας δυστυχής θέμα επενδυτής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '118140', '2025-05-31 00:00:00', '2025-06-28 00:00:00', 'Υψηλότερη τη ορίστε ανταγωνιστής ένας μπορούσες ειδικά. Νιρβάνα δεδομένων εργαζόμενων.', 'Αθόρυβες συνεχώς εργάστηκε. Πως έχω περίπου απομόνωση αποκλειστικούς δεν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '22012', '2024-02-25 00:00:00', '2024-04-13 00:00:00', 'Γνωστή σημαντικό αφήσεις. Εγώ συνηθίζουν και κύκλο. Πλέον τέλειοι σας συνηθίζουν. Επί να επί επί χρονοδιαγράμματα εγώ.', 'Τις ένας γράψει ταξινομεί τους. Στις στη βιαστικά τον. Κύκλο μα σωστά κι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '45418', '2025-02-10 00:00:00', '2025-02-20 00:00:00', 'Μη ήδη εκτελέσεις λίγο και δημιουργήσεις. Μη πετάνε έξι ας σημαντικό γραμμής φαινόμενο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '17152', '2020-01-24 00:00:00', '2020-02-08 00:00:00', 'Την μιας αλγόριθμου πολύ. Ως πάντα κοιτάζοντας μα μάλλον χαμηλός μέχρι.', 'Κι ποια ελέγχου θέμα όταν έξι εδώ. Να πόρτες μέσης συνηθίζουν κανένας πετούν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '134158', '2022-09-19 00:00:00', '2022-11-09 00:00:00', 'Κώδικάς διοικητικό για πάρεις του μάλλον ατόμου. Στα προσεκτικά έστειλε δεδομένων πιο ίδιο την.', 'Έχω έχω συνέχεια στα σίγουρος έλεγχος. Ποσοστό επιδιόρθωση με πιο τους έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('178', '0505564167', '3108947881');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '3058', '2024-04-25 00:00:00', '2024-05-01 00:00:00', 'Αποθηκευτικού σε κάνεις. Εργασίας αποδείξεις γραφικά επεξεργασία.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '145237', '2022-07-23 00:00:00', '2022-09-04 00:00:00', 'Τρόποι όχι αναφορά πετάνε γνωρίζουμε κανείς. Ροή πήρε χαρακτηριστικό εξαρτάται διορθώσεις έξι τις πάρα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '36', '2020-09-04 00:00:00', '2020-10-09 00:00:00', 'Χάος ύψος δούλευε χρησιμοποίησέ. Τεσσαρών άτομο αφήσεις σε σωστά προσοχή. Πάντα του τους.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '135471', '2025-08-05 00:00:00', '2025-09-14 00:00:00', 'Κι σαν εργαλείων βουτήξουν τύπου στήλες. Πόρτες εργάστηκε το επιχείριση εκτός μερικούς. Εκείνου αλγόριθμου λίγο με εργαζόμενων απαράδεκτη προγραμματιστές.', 'Μέχρι τύπους απομόνωση τη πάντως κι προϊόντα. Εκτός έτσι εσωτερικών γραμμή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '108775', '2021-03-21 00:00:00', '2021-05-11 00:00:00', 'Τον δεν πακέτων την.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '94329', '2025-10-03 00:00:00', '2025-11-14 00:00:00', 'Κανείς ότι πάντα σαν εφαρμογή ερωτήσεις αποθηκευτικού τεκμηριώνει. Τι ανεπιθύμητη εντολές σε ναι.', 'Διορθώσεις των εταιρείες. Εκτός της γραφικά της μην οι μετράει. Πολύ επί ροή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '141441', '2022-09-08 00:00:00', '2022-09-28 00:00:00', 'Διαφήμιση μέρος εικόνες χρόνου. Εδώ ότι απλό σημεία συγκεντρωμένοι ορίστε δυστυχής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '96202', '2021-10-22 00:00:00', '2021-10-29 00:00:00', 'Κόλπα όταν υψηλότερη προσεκτικά την συνέχεια πάρα σχεδιαστής. Συνέχεια μέσης περιμένουν.', 'Πρώτης χαρακτηριστικών βιαστικά το ταξινομεί διαχειριστής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '101046', '2020-02-11 00:00:00', '2020-02-25 00:00:00', 'Ανακλύψεις ποια βιβλίο χρησιμοποιώντας επί. Δίνοντας είχαμε δε αποφάσισε ιδιαίτερα εταιρείες πρώτοι.
