INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('180', '2602464581', '1108999877');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('180', '112912', '2026-07-15 00:00:00', '2026-08-08 00:00:00', 'Τύπου ώρα χρόνου παραπάνω διάσημα από μάθε. Του ώρα άρα δύο εντολές.', 'Υψηλότερη γραμμής τι δε. Καλύτερο δύο ζητήσεις που.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('181', '1401465442', '1709431072');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '35095', '2023-01-04 00:00:00', '2023-01-29 00:00:00', 'Μάλλον τους ας μέχρι πάρεις. Κειμένων γραμμής περισσότερη τον θυμάμαι αρέσει. Δοκιμάσεις το και διακόψουμε σας μας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '34326', '2021-06-27 00:00:00', '2021-08-08 00:00:00', 'Οι στα διορθώσει θα όσο μαγικά. Ποσοστό τη κανείς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '87933', '2025-03-21 00:00:00', '2025-04-02 00:00:00', 'Εγώ προκύπτουν σχεδιαστής σαν περισσότερη αποστηθίσει οι. Πιο μηχανής πολύ οι ένας ανά μου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '114610', '2022-01-10 00:00:00', '2022-02-22 00:00:00', 'Κάνεις ήδη θυμάμαι ευκολότερο επιχείριση. Ώρα μάθε χρησιμοποιούνταν γραμμές διακόψουμε πες ερωτήσεις.', 'Αν λες εργάστηκε περισσότερη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '145891', '2021-12-06 00:00:00', '2021-12-28 00:00:00', 'Αποφάσισε συνεχώς βιαστικά γράψει λιγότερο. Μέρος αποκλειστικούς ορίστε λες. Μέχρι δύο με κόψεις σίγουρος. Σωστά νιρβάνα εδώ δίνοντας αρχεία δεν υπηρεσία.', 'Φακέλους εφαρμογής διορθώσει σας δεν παραπάνω.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '56818', '2020-06-12 00:00:00', '2020-08-06 00:00:00', 'Δεδομένων σωστά προκαλείς τον κοιτάζοντας εκθέσεις. Προκαλείς κανένας γειτονιάς συνάδελφος δείξει. Χρησιμοποιούσες στις μάθε εφαρμογής.', 'Όταν πακέτων περιεχόμενα επιστρέφουν δημιουργια τη μην.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '58802', '2025-09-07 00:00:00', '2025-09-20 00:00:00', 'Ξέχασε εξακολουθεί παράγοντες προϊόντα εκτελείται αυτός ύψος. Πήρε το σας στα ερωτήσεις μαγικά ξέχασε. Μερικούς γειτονιάς εξαρτάται στις.', 'Ίδιο παραδοτέου ας τρόποι τεκμηριώνει εκδόσεις απίστευτα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '91963', '2023-03-02 00:00:00', '2023-04-17 00:00:00', 'Ως άρα απαραίτητο συνέχεια χαμηλός. Μα πλέον διασφαλίζεται άρθρων και τη γραμμή. Δυστυχώς τελειώσει παράδειγμα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '28275', '2021-06-20 00:00:00', '2021-08-09 00:00:00', 'Εργαζόμενων γνωρίζουμε πάντως. Πρόσληψη πρόσληψη μιας που αναγκάζονται φακέλους.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '45428', '2025-02-15 00:00:00', '2025-03-21 00:00:00', 'Καλύτερο έτσι ναι. Έστελνε όταν επί εκθέσεις χαρτιού. Πρώτο αυτήν μα τι.', 'Απλό γεγονός δύο δεδομένων απίστευτα ποια. Χαρτιού ίδιο αν εφαρμογή τύπου ως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('182', '1802733523', '0501561078');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '21298', '2021-08-13 00:00:00', '2021-09-15 00:00:00', 'Ατόμου ένα απόλαυσε. Έχω επενδυτής μια στο χρησιμοποιούσες προϊόντα έτσι. Τα απαράδεκτη πρώτοι λοιπόν αποφάσισε γραμμή.', 'Μα εδώ εργασίας επί. Τρόπο έξι θα άπειρα χρονοδιαγράμματος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '133211', '2022-05-23 00:00:00', '2022-07-14 00:00:00', 'Διακοπής όταν πάντα. Παράγοντες εκτός έτοιμος πολύ στις. Στο δοκιμάσεις μιας προσπαθούν νέου.', 'Ταξινομεί δημιουργια μην ίδιο μη εδώ. Άλγεβρα που δωροδοκηθούν ήδη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '79358', '2020-07-23 00:00:00', '2020-07-30 00:00:00', 'Έχω δοκιμάσεις να αποδείξεις πλέον στέλνοντάς μας κι. Μέχρι εκτελέσεις προσλάμβανες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '90891', '2024-03-25 00:00:00', '2024-04-11 00:00:00', 'Πως ότι προσπαθούν. Προϊόντα δεν βρίσκονται απαραίτητο σίγουρος πάντα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '75125', '2023-12-09 00:00:00', '2023-12-21 00:00:00', 'Επιστρέφουν επιδιορθώσεις μιας εσωτερικών ποια. Λετπά πρώτης εκτελέσεις περίπου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '24179', '2023-07-08 00:00:00', '2023-07-28 00:00:00', 'Γέλασαν παραδοτέου κρατάει ήδη περιεχόμενα όταν από. Όταν εφαρμογής παραδώσεις τους πάντα συγχωνευτεί άρα.', 'Διαπιστώνεις των εσωτερικών ας έλεγχος αποδείξεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '99444', '2023-05-26 00:00:00', '2023-06-18 00:00:00', 'Έξι σας δύο πάντως περιεχόμενα. Επιστρέφουν αρχεία στο ίδιο επιδιορθώσεις απαραίτητο. Δυστυχής ημέρα ανταγωνιστής χώρου.', 'Περισσότερες σωστά δε γραφικά. Διασφαλίζεται όσο για πολύ δεν πάντα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '2305', '2026-09-10 00:00:00', '2026-09-15 00:00:00', 'Των ας μηχανής δύο τις παραδοτέου άρα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '110645', '2020-06-18 00:00:00', '2020-08-08 00:00:00', 'Άρα αρέσει παραδοτέου πάρεις. Σας γιαυτό γειτονιάς βουτήξουν εκθέσεις πάντως. Ποσοστό του σίγουρος της.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '42045', '2025-03-07 00:00:00', '2025-04-30 00:00:00', 'Ήδη μιας μεταγλωτίσει όταν ποια πιο ιδιαίτερα. Πιο επί αντιλήφθηκαν ο έγραψες τον πεδία ερωτήσεις.', 'Πηγαίου στις δοκιμάσεις στραβά. Προσθέσει διακοπής ζητήσεις αναφέρονται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('183', '1611426076', '2706226965');
