INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('183', '114537', '2021-07-08 00:00:00', '2021-08-07 00:00:00', 'Πες περιβάλλον θα μέχρι εκείνου. Το καταλάθος τους αντιλήφθηκαν ανεπιθύμητη. Αποδείξεις συγχωνευτεί πρόσληψη ώρα εκτελέσεις πηγαίου άρθρων για.', 'Να πάντα αντιλήφθηκαν παράδειγμα ποια μάτσο διοικητικό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('184', '2011656899', '1509427630');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '156671', '2026-11-27 00:00:00', '2027-01-07 00:00:00', 'Ανά μέρος ξέχασε πλέον ένας παραδοτέου μην. Δε προσπαθούν εκτελέσεις δημιουργια μη μιας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '46585', '2023-06-30 00:00:00', '2023-07-08 00:00:00', 'Σκεφτείς προκύπτουν κι ήδη εγώ. Στις τη ας την. Γέλασαν στις σκεφτείς μας στα τι γραμμές ταξινομεί.', 'Εκτελέσεις οι σου εδώ σπίτι προϊόντα λέει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '159325', '2022-05-19 00:00:00', '2022-07-02 00:00:00', 'Δίνοντας βιβλίο κοιτάζοντας έχω μια στα. Τα ερώτηση συνηθίζουν δείξει ζητήσεις σημεία μπουν. Των τεκμηριώνει συνέχεια πρώτοι πάντως βουτήξουν.', 'Ήδη έλεγχος οι όσο απόλαυσε. Παίρνει δείξει προσεκτικά παίρνουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '51015', '2025-04-07 00:00:00', '2025-05-13 00:00:00', 'Περισσότερη σημεία θα μας των εκτός σωστά έστελνε. Πήρε παίξουν αποθηκευτικού δύο χρησιμοποιώντας. Πακέτων εγώ την μου.', 'Ειδικά επιδιόρθωση επιστρέφουν των πρώτο ρωτάει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('185', '0512535877', '1511821127');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '86933', '2023-12-04 00:00:00', '2024-01-26 00:00:00', 'Προγραμματιστής αρχεία του στο δε ο. Ο ίδιο ανεπιθύμητη περίπου παραδώσεις δε μιας. Εφαρμογής πιο έτοιμος λαμβάνουν προσοχή επιδιορθώσεις σας.', 'Εργοστασίου νέο ο τι έρθει αφήσεις ευκολότερο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '154284', '2023-08-29 00:00:00', '2023-09-21 00:00:00', 'Κοιτάζοντας μέσης λετπά αν εκτός τοπικές. Διάσημα προγραμματιστής κειμένων απαραίτητο μέσης ωραίο πεδία.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '621', '2021-05-24 00:00:00', '2021-06-06 00:00:00', 'Βιαστικά ίδιο εργαζόμενων τι μεταφραστής χαρακτηριστικών. Παραγωγικής τις μου νέων κι ένας εργοστασίου συνεχώς.', 'Αποθηκευτικού συγγραφής διακοπή θέμα. Εσωτερικών παραδοτέου πρόσληψη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '93711', '2024-06-12 00:00:00', '2024-08-03 00:00:00', 'Υψηλότερη για πιο που θέμα πλέον καλύτερο. Μερικούς αρπάζεις χρονοδιαγράμματα. Θέλεις απαρατήρητο έξι ορίστε σταματάς πάντα απίστευτα.', 'Τεκμηριώνει πρώτο συνέχεια αναφέρονται δεν συνεχώς σπίτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '109839', '2023-11-06 00:00:00', '2023-12-31 00:00:00', 'Κάτι δοκιμάσεις ήδη εταιρείες έτσι μεταφραστής ρωτάει. Πήρε δυστυχής διασφαλίζεται. Έχω πολύ μάθε όχι πρόσληψη προσεκτικά.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '135799', '2024-08-31 00:00:00', '2024-09-06 00:00:00', 'Τους εφαμοργής προκαλείς χρονοδιαγράμματος. Δίνοντας μιας λετπά παράδειγμα βγήκε όταν εργοστασίου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '115312', '2026-08-20 00:00:00', '2026-10-13 00:00:00', 'Δεδομένων σκεφτείς ευκολότερο στη εφαρμογή και. Στήλες κι δείξει εργασίας.', 'Του κρατήσουν απαράδεκτη λέει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '109875', '2026-05-17 00:00:00', '2026-06-21 00:00:00', 'Ημέρα σαν πετούν σαν διαπιστώνεις πρώτης χρονοδιαγράμματα. Σημαντικό πετούν κόλπα μα την που. Έτσι μια ποια περισσότερη τον ποσοστό ανταγωνιστής.', 'Φίλος περιμένουν ποια μα λετπά χρησιμοποιώντας μέχρι συνάδελφος.');
