INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('186', '27820', '2026-12-14 00:00:00', '2026-12-26 00:00:00', 'Γραμμή δύο τι βασανίζουν θέματα ας φίλος. Εγώ ώρα εγώ ημέρα πηγαίου γεγονός όχι. Χρησιμοποίησέ τελειώσει κανόνα ανά πως μέρος παίρνουν.
