INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('188', '3252', '2026-11-23 00:00:00', '2027-01-11 00:00:00', 'Κάτι ζητήσεις εκτός. Ρουτίνα μα εξακολουθεί άπειρα εκείνου περιβάλλοντος μιας. Απαρατήρητο εδώ γνωρίζουμε κάτι πολύ. Σχεδιαστής προγραμματιστές κάτι γραφικά προκαλείς περισσότερη άρα κάνε.', 'Διακοπής μπουν πες για. Αποκλειστικούς παίξουν πήρε διακοπής κειμένων.');
