INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('189', '85587', '2023-03-16 00:00:00', '2023-05-11 00:00:00', 'Και ταξινομεί χρονοδιαγράμματα μπορούσες οι σημαντικός προβληματική. Εκδόσεις έλεγχος πολύ ανακλύψεις. Γραμμές απαρατήρητο θυμάμαι διορθώσεις στις συγγραφής νέου.', 'Παραγωγικής επιδιόρθωση διαδίκτυο γραφικά ανακλύψεις δοκιμάσεις έτσι.');
