INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('190', '92386', '2025-11-21 00:00:00', '2025-12-28 00:00:00', 'Εδώ κάτι έστειλε. Διάσημα μεταγλωτίσει της πετούν για και που διασφαλίζεται. Προσθέσει της ότι ανά λετπά διευθυντές.', 'Ανά ανακλύψεις διευθυντές κώδικα. Ο χαρακτηριστικό αποθηκευτικού.');
