INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '134631', '2021-05-29 00:00:00', '2021-07-10 00:00:00', 'Μη πολύ μα μιας χρειάζονται στις πιο. Μην δυστυχής φράση βιαστικά εκτός. Τον τι μα στέλνοντάς για.', 'Κι αρχεία θα σταματάς. Ανώδυνη συγγραφής εγώ και.');
