INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '78413', '2026-12-08 00:00:00', '2026-12-15 00:00:00', 'Θα δύο έστελνε ώρα πως πηγαίου. Διακόψουμε μέσης αναφέρονται δούλευε σημαντικό ποια απλό άπειρα.
