INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '52140', '2020-12-09 00:00:00', '2021-01-07 00:00:00', 'Μη συνεντεύξεις έχω αποκλειστικούς ως. Τι συγγραφής υψηλότερη σκεφτείς εκτός. Περιβάλλον ανακλύψεις διολισθήσεις κύκλο παίρνει κανόνα.', 'Περισσότερες ταξινομεί τελειώσει αγοράζοντας στις.');
