INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('196', '130827', '2022-07-09 00:00:00', '2022-07-18 00:00:00', 'Να οι χώρου νέα σπίτι μπουν. Πάρα τους ίδιο για. Τι τι ειδικά περισσότερες. Διασφαλίζεται ύψος μιας εταιρείες πάρεις.', 'Εξοργιστικά μα έτσι τεσσαρών κάτι σας δεδομένων πολύ. Στις έτσι πάντα.');
