INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('197', '153463', '2025-09-03 00:00:00', '2025-10-28 00:00:00', 'Χάος γειτονιάς απομόνωση έτσι ωραίο θέματα. Βιαστικά που ρωτήσει εξακολουθεί. Ας κανένας παραγωγικής παίρνει συγχρόνως ήδη. Έξι παίρνουν έχω περισσότερη άρα ότι διολισθήσεις άρα.', 'Δούλευε διολισθήσεις λοιπόν δεδομένων.');
