INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '153190', '2022-09-25 00:00:00', '2022-11-23 00:00:00', 'Μου προβληματική χαρακτηριστικό δύο ποια αυτήν. Τον αρχεία ανακλύψεις πετάξαμε.', 'Αρπάζεις απλό γεύματος διαπιστώνεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '45914', '2023-11-01 00:00:00', '2023-11-29 00:00:00', 'Σπίτι αφήσεις δουλεύει έρθει αντιλήφθηκαν επί. Δεδομένων πήρε τρέξει παραπάνω προγραμματιστές τι. Επιστρέφουν στη μα πάντα πως πιο.', 'Αρχεία διοικητικό λετπά περίπου ανακλύψεις φράση παράδειγμα.');
