INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '52358', '2026-08-08 00:00:00', '2026-08-25 00:00:00', 'Έτσι εντολές σημαντικό φίλος διοικητικό προσπαθήσεις ίδιο. Χρονοδιαγράμματα είχαμε βρίσκονται. Περιμένουν αγοράζοντας βαθμό που αν φακέλους στραβά λες.', 'Παραδοτέου ακούσει σταματάς μας εργοστασίου το πιο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '5135', '2026-12-12 00:00:00', '2027-01-11 00:00:00', 'Νιρβάνα οι γιαυτό μερικούς λετπά όταν τι. Θέματα πολύ έξι βιαστικά πιο μια. Αποθηκευτικού γειτονιάς διευθυντές σωστά υπηρεσία άτομο.', 'Ήδη μερικούς μάτσο πιο μπορούσες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '96279', '2021-03-31 00:00:00', '2021-04-21 00:00:00', 'Ρουτίνα συγχρόνως μέχρι κοιτάζοντας δημιουργείς. Δημιουργείς χρονοδιαγράμματος ένα χαρακτηριστικών. Εργαζόμενοι της σε αρχεία. Ρουτίνα εδώ παίρνει πρόσληψη εξοργιστικά σε μη.', 'Και από τη ορίστε δείξει προκύπτουν. Της είχαμε αναφορά δε εκτελέσει.');
