INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '123073', '2020-02-29 00:00:00', '2020-03-16 00:00:00', 'Μέχρι άρθρων συνεχώς πες ανεπιθύμητη. Τις μια εκείνου στήλες χάος πλέον χρησιμοποιούσες. Παράγοντες συνέχεια κανείς επί με έτσι εγώ.', 'Εξαρτάται απαράδεκτη γράψει. Σε τύπου γραμμές διακοπής απομόνωση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '65743', '2025-02-26 00:00:00', '2025-04-18 00:00:00', 'Εκδόσεις απίστευτα του ναι ένα πολύ. Από παραγωγικής επιστρέφουν τέλειοι κειμένων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '89258', '2020-08-06 00:00:00', '2020-08-16 00:00:00', 'Φράση λαμβάνουν όχι έξι απαράδεκτη για συνέχεια ημέρα. Οι διάσημα θέμα μάθε ελέγχου να. Ως εργαζόμενων γραμμές. Ναι συγγραφείς χαρακτηριστικών μεταφραστής.', 'Αναγκάζονται προϊόντα τις μάθε σταματάς γράψει κλπ.');
