INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '112769', '2026-03-08 00:00:00', '2026-03-09 00:00:00', 'Έτσι ήδη υόρκη γιαυτό προκαλείς νέο μας. Αυτός προγραμματιστές εκτός στήλες μπορούσες δημιουργήσεις. Γνωρίζουμε ότι βουτήξουν ιδιαίτερα περιβάλλον σας κρατάει διαχειριστής.', 'Έτσι πάντως ορίστε τι νέων ώρα επί. Διακοπής εργαλείων έστελνε λετπά.');
