INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '34784', '2024-08-28 00:00:00', '2024-10-04 00:00:00', 'Απλό χώρου στο ξέχασε χρονοδιαγράμματα ημέρα. Πάρα άπειρα χρονοδιαγράμματα. Περιεχόμενα σημαντικός στραβά στέλνοντάς απόλαυσε εκδόσεις εκτελείται.', 'Ανώδυνη ρουτίνα ανά ήδη νέα πρώτο. Ένα εγώ δύο ένας παίρνουν.');
