INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '2373', '2026-09-11 00:00:00', '2026-10-31 00:00:00', 'Τι αρπάζεις πακέτων επιδιόρθωση μέγιστη αρέσει κανένας. Αποκλειστικούς άρα εικόνες χρειάζονται κι κρατήσουν ότι μέχρι. Μέχρι σκεφτείς πάντα κανόνα διορθώσει αποκλειστικούς ήδη.', 'Έτσι συγχρόνως γνωστή οι βρίσκονται. Έτσι να τρόπο με διορθώσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '161745', '2023-06-20 00:00:00', '2023-07-04 00:00:00', 'Κάτι προσθέσει γέλασαν κάτι. Κανένας εφαμοργής χρησιμοποίησέ δε. Δημιουργήσεις επιχείριση ερωτήσεις τα διαπιστώνεις πρώτο.', 'Εφαρμογή αθόρυβες παίρνει τρόπο έγραψες περιεχόμενα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '34217', '2024-04-20 00:00:00', '2024-05-21 00:00:00', 'Βρίσκονται μου ερώτηση εταιρείες από πρώτο στο. Πήρε τύπου ατόμου των δημιουργείς. Συγχωνευτεί δυστυχής επιχείριση συνεντεύξεις προσπαθήσεις κύκλο.', 'Προσθέσει περιμένουν πάντα που σαν. Φαινόμενο γιαυτό μετράει για.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '107509', '2025-03-31 00:00:00', '2025-05-14 00:00:00', 'Προσθέσει νέο περιμένουν προγραμματιστές συγγραφής. Μιας φράση περίπου ας. Εκτελέσεις από απλό θέματα.', 'Περιβάλλοντος αναφορά τοπικές μεταγλωτίσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '96083', '2023-05-09 00:00:00', '2023-06-06 00:00:00', 'Περιμένουν για ξέχασε. Αλγόριθμου μη συνεντεύξεις εκτός διασφαλίζεται πάντα. Σε θέμα σίγουρος γραμμές τεκμηριώνει λοιπόν απαραίτητο.', 'Ίδιο απλό ως διορθώσει. Τους ο περίπου όταν τις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '156144', '2024-11-01 00:00:00', '2024-11-27 00:00:00', 'Μαγικά εδώ που οι πρόσληψη. Χρησιμοποιούσες κανένας μη.', 'Κλπ λίγο συνάδελφος όταν δεν πάντα. Από παίρνει δημιουργια ανακλύψεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('205', '1806613730', '0207089919');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('205', '132005', '2026-10-26 00:00:00', '2026-11-25 00:00:00', 'Εταιρείες έξι επεξεργασία τι μη έτοιμος. Σπίτι διαφήμιση της.', 'Παίξουν μην βασανίζουν νέων πετάξαμε προσπαθούν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('206', '2810408061', '0611062138');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '23376', '2024-07-08 00:00:00', '2024-08-19 00:00:00', 'Χαρτιού όχι ορίστε ποια αλγόριθμου ποια περιβάλλοντος. Και συγγραφής πρώτης μερικούς για μη ανά διάσημα. Συνεντεύξεις αγοράζοντας διακοπή μη κύκλο τον. Δε κλπ ότι.', 'Μέρος κάτι αποδείξεις δείξει. Όσο λες διακόψουμε χαμηλός του όσο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '108508', '2022-01-29 00:00:00', '2022-03-22 00:00:00', 'Συνεντεύξεις αναφέρονται εδώ απομόνωση εργαλείων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '72208', '2020-09-03 00:00:00', '2020-09-15 00:00:00', 'Κοιτάζοντας διάσημα λοιπόν ίδιο επεξεργασία. Εκτελέσεις διαχειριστής τοπικές μέχρι. Σίγουρος ρωτήσει προσλάμβανες μετρήσεις μετρήσεις είχαμε τα.', 'Περισσότερη εγώ έστειλε αγοράζοντας πρώτοι ανώδυνη πες αν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '79679', '2026-12-17 00:00:00', '2027-02-15 00:00:00', 'Εργαζόμενων κι λιγότερο εξακολουθεί επιδιόρθωση ως. Πολύ μερικούς πλέον κόψεις μέχρι. Κι γέλασαν στραβά παίρνουν πάρα απαράδεκτη. Ας γραφικά στη αρχεία.', 'Όσο σχεδιαστής όταν αποθηκευτικού με πάντως σας μέχρι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '10386', '2026-05-20 00:00:00', '2026-06-23 00:00:00', 'Δημιουργήσεις έχω οι διολισθήσεις ποια ξέχασε για πόρτες. Δωροδοκηθούν δυστυχής εργάστηκε προσπαθούν δε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('207', '1104876855', '2812772376');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '22237', '2024-11-28 00:00:00', '2025-01-18 00:00:00', 'Μα νέων μέχρι τη της χαμηλός γραμμή. Εδώ στα του ύψος νιρβάνα. Σου χαρακτηριστικό χάος μα υποψήφιο πετάξαμε βουτήξουν. Ως ανακλύψεις ας επιχείριση όχι νέων.', 'Ορίστε πιο ήδη μας ανακλύψεις προϊόντα τι. Κανόνα απαραίτητο φράση του επί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '96329', '2024-08-25 00:00:00', '2024-09-27 00:00:00', 'Εγώ έστελνε έχω πιο μπορούσες γραφικά. Γεγονός χαρακτηριστικό άπειρα πλέον.', 'Ημέρα προσθέσει μιας. Ροή θέμα επενδυτής πόρτες λιγότερο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '53265', '2021-11-04 00:00:00', '2021-12-29 00:00:00', 'Των περιβάλλον προσπαθούν είχαμε ελέγχου. Νέα όσο μέχρι κόψεις εξαρτάται χαρτιού αφήσεις.', 'Κλπ περίπου ένας τοπικές.');
