INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '134561', '2021-09-11 00:00:00', '2021-11-02 00:00:00', 'Ως χειρότερα πιο κειμένων σχεδιαστής συγγραφείς εργοστασίου. Περισσότερες προκαλείς εντολές τι κειμένων πρώτοι πήρε μπουν. Ναι τους περίπου νόμιζες.', 'Διορθώσει λίγο κάνε μια τη τι νέου. Μάτσο όχι παράδειγμα ακούσει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '65497', '2022-06-28 00:00:00', '2022-07-23 00:00:00', 'Εφαρμογής όχι εκδόσεις ως ορίστε κώδικα. Σωστά χαμηλός θέμα εκτελέσει ανά όταν.', 'Άρα διακοπής σχεδιαστής έξι αναγκάζονται.');
