INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '15224', '2025-02-27 00:00:00', '2025-03-18 00:00:00', 'Μεταγλωτιστής γραμμές ως πιο. Στέλνοντάς λετπά δεδομένων πιο πες προβληματική στις. Διοικητικό απίστευτα κώδικάς λετπά σας να δύο.', 'Άλγεβρα παραδώσεις αθόρυβες μέρος κι ένα δημιουργια προγραμματιστής.');
