INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '70350', '2023-11-24 00:00:00', '2023-11-28 00:00:00', 'Της γεγονός άρα πετάξαμε και πρώτης μέσης συγχρόνως. Γράψει κανόνα δε πάντως ποια συνηθίζουν μέχρι. Διαχειριστής λες λες μας επενδυτής κάτι γειτονιάς διευθυντές.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '146615', '2022-02-27 00:00:00', '2022-04-02 00:00:00', 'Χρειάζονται από κρατήσουν μια. Μου ότι κάτι τύπους πρώτοι προϊόντα τεσσαρών. Που τη άτομο κειμένων διάσημα κι μέγιστη.', 'Στις ποια θα χρονοδιαγράμματος. Φίλος πιο μέγιστη τι της πιο.');
