INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '161148', '2020-11-30 00:00:00', '2020-12-17 00:00:00', 'Μπορούσες βιβλίο ωραίο ήδη συγκεντρωμένοι τον μας. Πλέον λίγο άρα κοιτάζοντας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '53279', '2021-11-07 00:00:00', '2021-12-12 00:00:00', 'Έτσι αποθηκευτικού πηγαίου αγοράζοντας χαρτιού ρωτήσει κάνε. Πάντως πλέον βάζοντας σπίτι. Προσλάμβανες αποκλειστικούς διάσημα διευθυντές έτσι προβληματική γειτονιάς.', 'Μας μερικούς άλγεβρα πήρε μια όταν ότι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '21556', '2022-10-28 00:00:00', '2022-11-02 00:00:00', 'Σας σίγουρος περιβάλλοντος ωραίο ώρα. Πρώτοι κύκλο ανεπιθύμητη δεν ορίστε πετάξαμε δουλεύει. Στο με προσπαθήσεις έξι ρωτάει διαχειριστής στη γνωρίζουμε.', 'Αφήσεις χρησιμοποιώντας επιχείριση αυτήν νιρβάνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('216', '0808816951', '1109820892');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '56417', '2021-02-04 00:00:00', '2021-04-04 00:00:00', 'Με επιχείριση ακούσει ημέρα στο. Εφαρμογής δημιουργείς τοπικές πολύ εκτελείται που. Γέλασαν διαδίκτυο μετρήσεις των σαν αντιλήφθηκαν μην.', 'Κι των εργαζόμενων σταματάς. Πλέον γειτονιάς τι μπορούσες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '85578', '2026-04-25 00:00:00', '2026-05-06 00:00:00', 'Χρησιμοποίησέ στις του μα μάτσο σημαντικό νόμιζες. Έχω άρα σωστά την αντιλήφθηκαν απίστευτα. Ως γραμμές μου όσο πως βαθμό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '44585', '2021-10-07 00:00:00', '2021-10-21 00:00:00', 'Προγραμματιστής έγραψες χαρτιού χρησιμοποίησέ. Διακοπής δημιουργείς ροή δημιουργια. Περιβάλλοντος θα ένα περιεχόμενα κώδικάς.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '36971', '2024-06-27 00:00:00', '2024-07-22 00:00:00', 'Ο εκτός ξέχασε προκύπτουν κάνεις απίστευτα χρησιμοποιούσες. Πρώτο κλπ άρα διάσημα εγώ.', 'Θα περιβάλλον χρησιμοποιούσες ρουτίνα τέλειοι τρόπο ίδιο.');
