INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '80027', '2024-08-16 00:00:00', '2024-10-01 00:00:00', 'Αν πρώτης το επιστρέφουν. Δούλευε ποια στο. Εγώ αλγόριθμου βασανίζουν πάρεις απαραίτητο βάζοντας έχω δε. Αποκλειστικούς την τοπικές σημαντικό εργαλείων εικόνες.', 'Ταξινομεί αντιλήφθηκαν αυτήν επί το τελειώσει ότι.');
