INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '118165', '2023-02-04 00:00:00', '2023-03-04 00:00:00', 'Χρόνου εσωτερικών δεδομένων ο τα διαδίκτυο. Επιδιόρθωση χρησιμοποιώντας συγχρόνως δύο άρα από γραμμή. Είχαμε τα γράψει στις ένας.', 'Εργαλείων νέου θα μερικούς δεν εταιρείες. Προκύπτουν διευθυντές περιμένουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '5643', '2022-01-03 00:00:00', '2022-01-28 00:00:00', 'Το του άρα. Συνάδελφος προγραμματιστής μηχανής αποθηκευτικού γιαυτό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '42230', '2023-12-12 00:00:00', '2024-01-09 00:00:00', 'Διοικητικό ανταγωνιστής συγγραφής. Σε κάτι εφαρμογή τρόποι απαράδεκτη έλεγχος πλέον. Αθόρυβες να εικόνες κόψεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '139335', '2022-09-09 00:00:00', '2022-10-16 00:00:00', 'Ήδη πάντως χαρακτηριστικών αντιλήφθηκαν από περιβάλλον εξοργιστικά της.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('219', '0512535877', '3005654782');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '18449', '2026-08-03 00:00:00', '2026-09-29 00:00:00', 'Κι μεταγλωτιστής εκτελείται εφαρμογή προσλάμβανες τέλειοι έστειλε μιας. Πόρτες μάτσο γιαυτό μου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '116957', '2022-08-09 00:00:00', '2022-08-18 00:00:00', 'Εσωτερικών νόμιζες ναι ακούσει. Φράση στέλνοντάς λέει συγκεντρωμένοι στέλνοντάς γειτονιάς ναι. Απαρατήρητο εργαζόμενοι τις ο.', 'Λαμβάνουν κειμένων που αυτήν έχω.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '71680', '2023-04-08 00:00:00', '2023-05-20 00:00:00', 'Περιμένουν χρόνου πιο ποια σίγουρος πλέον παραπάνω. Πάντως γραμμή ατόμου λιγότερο. Στήλες εξοργιστικά θέμα λέει αναγκάζονται δε νιρβάνα.', 'Τοπικές εργασίας πλέον μη σας έτσι τα χρονοδιαγράμματα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '130067', '2025-07-14 00:00:00', '2025-08-08 00:00:00', 'Όταν πως συνεχώς συνηθίζουν. Χειρότερα επί ποσοστό εκείνου. Όταν πλέον δεν περιεχόμενα θυμάμαι σκεφτείς.', 'Άλγεβρα πετούν περιβάλλον χρονοδιαγράμματος νέο απαράδεκτη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '157419', '2022-03-19 00:00:00', '2022-03-22 00:00:00', 'Τι τεκμηριώνει προϊόντα διαχειριστής χρειάζονται μη μερικούς. Ζητήσεις δυστυχής εργοστασίου μα βασανίζουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '23255', '2026-08-08 00:00:00', '2026-08-14 00:00:00', 'Τεσσαρών δίνοντας βρίσκονται ξέχασε προγραμματιστής ήδη. Τις κώδικα προσοχή νέου τρέξει πάντως ρουτίνα συνεχώς. Της τι τα ταξινομεί ίδιο θυμάμαι περιβάλλον παραδοτέου.', 'Διαφήμιση πάντα βαθμό του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '134103', '2026-08-23 00:00:00', '2026-09-21 00:00:00', 'Λαμβάνουν βιαστικά κώδικάς εσωτερικών ναι ρωτάει προσλάμβανες πόρτες. Δυστυχής διαχειριστής εδώ είχαμε υψηλότερη γέλασαν κρατάει.', 'Γνωστή συγχρόνως δημιουργήσεις. Δε χαρακτηριστικό πάντως δύο μάθε σου πως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '93347', '2020-08-10 00:00:00', '2020-10-05 00:00:00', 'Αυτός περιεχόμενα τέλειοι πάρα στο μεταγλωτίσει δίνοντας. Συνέχεια έχω πιο δεν μου.', 'Ανεπιθύμητη μιας ναι οι. Ειδικά επί νέου γέλασαν. Δημιουργια άτομο ερωτήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '142160', '2022-01-28 00:00:00', '2022-02-03 00:00:00', 'Όσο πάρα μα από λοιπόν παραδώσεις δύο το. Πως έστελνε χρησιμοποιώντας πιο. Άπειρα σε επεξεργασία χρησιμοποιώντας χρονοδιαγράμματα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('220', '1606420374', '2806235869');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '131364', '2020-05-02 00:00:00', '2020-06-27 00:00:00', 'Κρατήσουν πιο πεδία εταιρείες προγραμματιστές. Καλύτερο ποια ώρα συγγραφείς τους απαράδεκτη ανταγωνιστής στέλνοντάς. Χειρότερα τρόποι στα αλγόριθμου.', 'Πλέον τον τεσσαρών κανείς. Για μιας προσπαθούν κι που. Δείξει μας διευθυντές.');
