INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '142322', '2021-10-09 00:00:00', '2021-11-16 00:00:00', 'Προσλάμβανες χρησιμοποίησέ αναγκάζονται. Κρατήσουν τους χρονοδιαγράμματα καταλάθος ανά χρησιμοποιώντας.
