INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('221', '154429', '2024-03-10 00:00:00', '2024-05-08 00:00:00', 'Υόρκη κρατάει γραμμές κι. Σπίτι βρίσκονται εργαζόμενων πάντα εδώ το. Παίξουν πολύ να γραμμές δωροδοκηθούν.', 'Πρόσληψη μπορούσες κάτι ρωτάει κι ατόμου.');
