INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '106522', '2022-03-29 00:00:00', '2022-03-30 00:00:00', 'Μέχρι δεν νιρβάνα λετπά κι συγχρόνως βγήκε. Πιο θυμάμαι μου πολύ μεταγλωτιστής.', 'Τι ανά του βγήκε κάτι ναι. Μας αφήσεις επί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '119280', '2023-10-18 00:00:00', '2023-12-06 00:00:00', 'Μάτσο εργαλείων ο μη μέρος της.', 'Αλγόριθμου αφήσεις εντολές χρησιμοποιούσες φίλος στα τα.');
