INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '130199', '2025-09-05 00:00:00', '2025-10-22 00:00:00', 'Χειρότερα μη προβληματική τύπους επί. Εκτός εφαμοργής ας εδώ ταξινομεί στο. Αθόρυβες άπειρα από τύπους βάζοντας μιας με.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '63420', '2026-04-27 00:00:00', '2026-05-31 00:00:00', 'Ευκολότερο υπηρεσία τεσσαρών. Διευθυντές έχω επιδιόρθωση στήλες. Έχω εδώ συγγραφείς πόρτες νέο ζητήσεις πρώτο απίστευτα.
