INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '98367', '2025-11-01 00:00:00', '2025-11-25 00:00:00', 'Πόρτες αρχεία θα των. Βασανίζουν προσπαθήσεις αθόρυβες γέλασαν φακέλους σας προσεκτικά τη. Κανόνα κειμένων βιβλίο βουτήξουν.', 'Συγκεντρωμένοι ευκολότερο αθόρυβες μου λετπά. Για κάτι νόμιζες έλεγχος και.');
