INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '101206', '2024-09-24 00:00:00', '2024-11-17 00:00:00', 'Και του εδώ εκτός αναγκάζονται εκτός. Μας γράψει χρησιμοποίησέ δε εντολές μαγικά. Και χαρακτηριστικό νέων ερώτηση για μέχρι.', 'Φακέλους τρέξει χρησιμοποιώντας ελέγχου. Ανά άλγεβρα στήλες χαμηλός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '137367', '2024-11-24 00:00:00', '2025-01-20 00:00:00', 'Μου χαρακτηριστικό εκτελέσει προγραμματιστής συνηθίζουν επενδυτής μιας ερωτήσεις. Συνέχεια συγχωνευτεί με άτομο.', 'Μέγιστη τα δεν ύψος. Εργοστασίου φακέλους τεκμηριώνει προσπαθήσεις άρα ώρα.');
