INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '11067', '2022-03-22 00:00:00', '2022-05-04 00:00:00', 'Άρα γραφικά ένα βασανίζουν τρόποι. Νέα προσθέσει βιαστικά αντιλήφθηκαν.', 'Πήρε ορίστε προγραμματιστές δείξει χειρότερα προβληματική διακοπή.');
