INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '52353', '2026-05-28 00:00:00', '2026-07-22 00:00:00', 'Τι έτσι πρόσληψη. Κάτι όχι κάνε μηχανής χρησιμοποιώντας. Άλγεβρα έχω εργαζόμενων τελειώσει.', 'Προκαλείς προσοχή και πρώτης ότι ποσοστό του.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '49410', '2026-04-03 00:00:00', '2026-05-03 00:00:00', 'Σχεδιαστής αυτός πρόσληψη ροή εγώ. Άρα έχω πάντως συγχωνευτεί κανένας αρπάζεις για. Πάντως ελέγχου παραπάνω. Άρα διασφαλίζεται έτσι παίρνει στα μας εγώ.', 'Μπορούσες πετάξαμε ροή να τους χειρότερα. Μια έστελνε μην γραμμές τα κλπ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '47877', '2022-07-06 00:00:00', '2022-07-12 00:00:00', 'Διαδίκτυο τρόπο ειδικά σημαντικό θυμάμαι. Σταματάς κάνε ανταγωνιστής μάλλον έρθει κάνε με. Κανόνα έτσι υπηρεσία ανταγωνιστής διασφαλίζεται ρουτίνα δυστυχώς μια.', 'Λέει τοπικές διαφήμιση αλγόριθμου στις. Ίδιο ταξινομεί πρώτοι ρωτήσει ροή.');
