INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '89509', '2020-09-20 00:00:00', '2020-11-05 00:00:00', 'Σας κειμένων γειτονιάς. Τέλειοι παραδώσεις τρόπο μεταγλωτίσει στις απαρατήρητο φίλος. Πιο εκτελέσει πλέον έτσι.', 'Συγγραφής έτσι διάβασε παραγωγικής συγκεντρωμένοι ποια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '159936', '2026-04-10 00:00:00', '2026-05-03 00:00:00', 'Εσωτερικών άρα μετρήσεις ερωτήσεις κρατάει. Παραδοτέου πετάξαμε αυτήν που χαμηλός διάσημα έτσι. Μέχρι διολισθήσεις έτσι συνέχεια χρησιμοποιούνταν διευθυντές σπίτι αποφάσισε. Εργασίας ως πως.', 'Εκτός αυτός παραπάνω δείξει δουλεύει πρώτης. Με θα ανταγωνιστής μερικούς μια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '12879', '2020-07-12 00:00:00', '2020-07-30 00:00:00', 'Μερικούς διακοπής κάνε δοκιμάσεις εξαρτάται αποθηκευτικού. Δημιουργια όχι έγραψες. Εξακολουθεί ο θα πόρτες δημιουργια επιδιόρθωση έστειλε. Για πακέτων προκαλείς.', 'Μπορούσες αναγκάζονται θέμα διάσημα βάζοντας γέλασαν γεγονός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '147265', '2026-10-08 00:00:00', '2026-12-07 00:00:00', 'Περιβάλλον μετράει διορθώσει διασφαλίζεται εντολές μου βγήκε έχω. Ανά κώδικα δε χρησιμοποιούνταν αυτός βιβλίο.', 'Εργαζόμενοι όχι την πλέον θέματα χρειάζονται απίστευτα άτομο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '41048', '2026-06-04 00:00:00', '2026-07-14 00:00:00', 'Διάσημα μέχρι άλγεβρα διορθώσει επί.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('235', '0501573361', '1212598129');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '132542', '2022-02-11 00:00:00', '2022-02-28 00:00:00', 'Υπηρεσία όχι αγοράζοντας προσοχή τοπικές πετούν. Λίγο εικόνες ο λίγο αν. Χαρτιού ότι πρώτοι τεκμηριώνει από της της. Πες των την με χρησιμοποίησέ σαν ας προγραμματιστής.', 'Οι πήρε ώρα ανταγωνιστής εντολές.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '147988', '2021-05-21 00:00:00', '2021-06-28 00:00:00', 'Ο προκαλείς έξι μια έχω. Διακοπής ώρα δύο διαχειριστής στήλες. Μέχρι μπουν επιστρέφουν ήδη παραπάνω.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '9926', '2024-07-22 00:00:00', '2024-07-24 00:00:00', 'Αποστηθίσει ένα σου τον νιρβάνα απαραίτητο νόμιζες. Ποια μέχρι σε όταν νέο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '26612', '2023-12-08 00:00:00', '2023-12-13 00:00:00', 'Ποια έξι γνωρίζουμε εφαρμογής χρησιμοποιούσες απομόνωση σημαντικό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '144237', '2025-04-18 00:00:00', '2025-05-15 00:00:00', 'Λοιπόν χρονοδιαγράμματα μου στη αποκλειστικούς εξοργιστικά μετράει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '161029', '2026-01-24 00:00:00', '2026-03-02 00:00:00', 'Δυστυχής δεν ρωτάει μεταγλωτιστής κρατάει έξι γειτονιάς. Κόψεις μέχρι νέα στις προγραμματιστές διολισθήσεις δυστυχής.', 'Προγραμματιστής για της εργασίας. Τοπικές έγραψες ζητήσεις μιας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '70097', '2020-12-13 00:00:00', '2021-01-05 00:00:00', 'Ναι την μέρος σχεδιαστής τελειώσει του. Ρωτήσει μηχανής τη αυτός ένας αποδείξεις γραμμές.', 'Στα έτσι ιδιαίτερα συγγραφείς τελειώσει. Διακόψουμε ρουτίνα χρόνου τις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '8520', '2021-04-15 00:00:00', '2021-04-22 00:00:00', 'Τι συνάδελφος εργαζόμενων γέλασαν. Μιας νόμιζες εργαζόμενοι ανεπιθύμητη τύπους. Σου ερωτήσεις εικόνες.', 'Εντολές σημαντικός γεγονός αναφορά διολισθήσεις ρωτάει εκτελέσεις προσπαθήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('236', '0910904414', '2410539174');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '110147', '2025-09-26 00:00:00', '2025-11-07 00:00:00', 'Ακούσει χρειάζονται πως τα της που παραπάνω. Βαθμό έλεγχος αλγόριθμου.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '101392', '2025-07-08 00:00:00', '2025-07-18 00:00:00', 'Πάρεις απλό ναι απλό ανακλύψεις χρησιμοποίησέ χρειάζονται εντολές. Στραβά στις γραφικά.', 'Άρα πως φακέλους απλό περιεχόμενα. Εγώ εσωτερικών σπίτι σε δεδομένων.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '19158', '2026-08-06 00:00:00', '2026-08-29 00:00:00', 'Γραφικά εκείνου να. Είχαμε μην τέλειοι μου έρθει μη. Τεσσαρών χρησιμοποιούνταν συνηθίζουν γιαυτό διάσημα ως. Πάντως που μηχανής σημαντικό πιο κάνε.', 'Παραδώσεις έστελνε δείξει. Περιμένουν έχω χρονοδιαγράμματος θέματα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '95864', '2025-11-07 00:00:00', '2025-11-19 00:00:00', 'Δούλευε αν σε συγγραφείς σημαντικός ναι. Επενδυτής αποθηκευτικού παραγωγικής κάτι στις πάρεις. Κύκλο γεγονός μου ίδιο έλεγχος δωροδοκηθούν αποστηθίσει.', 'Αν στο σου κάτι παράδειγμα. Έστελνε δεδομένων απαρατήρητο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '6931', '2023-11-12 00:00:00', '2023-12-23 00:00:00', 'Εργαζόμενων συνέχεια χαρτιού τον δίνοντας αποδείξεις έστειλε. Κανόνα μας λίγο εφαρμογή προκαλείς συνεχώς. Μη μιας διάσημα ανακλύψεις.', 'Στα επί ανακλύψεις παίξουν. Πήρε μπορούσες δεν ημέρα κρατάει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '103430', '2022-07-07 00:00:00', '2022-08-08 00:00:00', 'Βιβλίο εκτελείται σου και πως. Ανταγωνιστής εικόνες στις άρα με. Εντολές άπειρα διαδίκτυο του.', 'Προγραμματιστής χαρακτηριστικών κειμένων τους φίλος υπηρεσία.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '72467', '2023-03-22 00:00:00', '2023-05-13 00:00:00', 'Παραπάνω ανά σε εγώ επιδιορθώσεις. Ας εγώ θέμα. Διαχειριστής γραφικά ανακλύψεις χρησιμοποιώντας προσπαθούν πιο.', 'Βαθμό σημαντικός πάντα διευθυντές επιστρέφουν βιαστικά για.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '70494', '2022-10-24 00:00:00', '2022-11-30 00:00:00', 'Της μέγιστη φίλος έξι πόρτες οι χρησιμοποιούσες. Προσπαθούν γειτονιάς στις έξι κι προσπαθούν.', 'Εδώ μου κρατήσουν πηγαίου βουτήξουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '66083', '2022-11-20 00:00:00', '2022-12-12 00:00:00', 'Λαμβάνουν αναγκάζονται δημιουργια απαρατήρητο. Ζητήσεις γραμμές για σημεία εκτελέσει όταν αρχεία δυστυχώς. Αρέσει ειδικά μη έχω δε πάντως.', 'Απίστευτα δείξει γεγονός. Πως κι κοιτάζοντας. Ελέγχου κάνεις σαν εδώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('237', '2608605682', '1401089547');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '110471', '2020-08-02 00:00:00', '2020-10-01 00:00:00', 'Δίνοντας γεγονός μέχρι μιας. Ορίστε μάτσο συγχρόνως εργαλείων. Σπίτι λαμβάνουν διαχειριστής μας πολύ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '25932', '2022-05-15 00:00:00', '2022-07-12 00:00:00', 'Πιο απαρατήρητο τον τα πακέτων ρωτάει κρατήσουν. Παραδοτέου τύπου επί. Ρουτίνα αντιλήφθηκαν χρονοδιαγράμματα ανά προσλάμβανες εγώ ωραίο πάντα. Φράση στέλνοντάς κώδικάς προσλάμβανες.', 'Εκτός απαράδεκτη βιαστικά ρουτίνα εγώ σημαντικό στα επιδιόρθωση.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '114043', '2024-08-19 00:00:00', '2024-10-17 00:00:00', 'Επιχείριση απόλαυσε πες εξοργιστικά θα στο πάντα. Τρόπο από νιρβάνα μέχρι αυτός εκδόσεις αντιλήφθηκαν τεκμηριώνει. Κι τα μπορούσες δύο θέματα.', 'Εγώ από διευθυντές πρόσληψη. Εκτός δείξει πάρεις τη πάντα ένας.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '16559', '2020-05-18 00:00:00', '2020-06-09 00:00:00', 'Διευθυντές μεταγλωτιστής σκεφτείς. Εργαζόμενων θέλεις διακοπή ανά προβληματική μην σαν. Παραγωγικής αποφάσισε λέει αν.', 'Βασανίζουν οι άλγεβρα τα να.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '102512', '2022-07-15 00:00:00', '2022-08-03 00:00:00', 'Δεν δημιουργείς εξακολουθεί φίλος εργαζόμενοι στήλες. Της στη τον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('238', '1412531407', '2707220533');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '91026', '2022-04-14 00:00:00', '2022-04-19 00:00:00', 'Περιμένουν ναι προσπαθούν προσεκτικά διαφήμιση μη ένα. Εκτελέσεις έρθει χρονοδιαγράμματα. Σχεδιαστής ναι τη δυστυχής διαχειριστής αφήσεις πετάνε. Ατόμου επί νέου αναγκάζονται.', 'Μετρήσεις πάντα ο ίδιο γειτονιάς ως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '102194', '2024-08-12 00:00:00', '2024-08-17 00:00:00', 'Έτσι ένας ατόμου σου ανακλύψεις πηγαίου διάσημα στη. Περίπου επιστρέφουν χαρτιού μα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '108958', '2022-10-22 00:00:00', '2022-11-10 00:00:00', 'Σας επιχείριση για τελειώσει μια ωραίο τα εκθέσεις. Τη διακοπή τρόπο προσπαθήσεις κρατάει αλγόριθμου. Τι περιβάλλοντος βασανίζουν εγώ συνηθίζουν ένα.', 'Παίρνουν διασφαλίζεται σαν ανταγωνιστής. Ερωτήσεις ως εδώ κι θα τα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('239', '0106934607', '0604585459');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '161757', '2020-01-23 00:00:00', '2020-02-18 00:00:00', 'Φίλος στραβά διορθώσει δεν δεν. Ζητήσεις κρατάει τα στις έξι. Λέει που σου από ευκολότερο.', 'Άτομο στις τον κανένας έτοιμος του τον. Ποια όχι περιμένουν ευκολότερο κάτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '82909', '2025-02-05 00:00:00', '2025-03-16 00:00:00', 'Σου αφήσεις συνέχεια ερωτήσεις κύκλο που. Ας με εντολές διευθυντές διοικητικό. Πετούν ένα κώδικα κι.', 'Γνωστή γράψει της κώδικάς περιμένουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '130773', '2025-10-10 00:00:00', '2025-10-12 00:00:00', 'Κι ποσοστό πιο μάθε συνεντεύξεις πάρεις. Μας ήδη αρχεία διαπιστώνεις παραδοτέου έτσι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '84558', '2022-09-21 00:00:00', '2022-10-28 00:00:00', 'Απόλαυσε ρωτήσει σαν μέσης περισσότερη. Δύο προϊόντα έστελνε μας. Επί ώρα παραπάνω σε τι κανένας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('240', '2607586104', '0312710224');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('240', '81815', '2024-05-03 00:00:00', '2024-06-01 00:00:00', 'Ένας ροή μα αυτός ερώτηση στη έτσι. Των εργαζόμενοι στο εκτός εργασίας ότι υψηλότερη επί. Πως περισσότερη εργαζόμενων μέρος όταν πάντα διευθυντές.', 'Την τύπους μου λαμβάνουν πολύ ανά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('241', '1811522342', '0104513511');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '71794', '2026-01-24 00:00:00', '2026-02-19 00:00:00', 'Πλέον ερωτήσεις τα συγκεντρωμένοι διαδίκτυο βασανίζουν. Κανόνα νέο εφαρμογή ειδικά εσωτερικών έστελνε κανόνα. Στήλες κι συνάδελφος μεταφραστής πόρτες.', 'Δεν προσεκτικά λέει κανείς. Εκτός ας κάνεις χάος παίξουν ποια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '14459', '2021-02-16 00:00:00', '2021-03-09 00:00:00', 'Ορίστε υποψήφιο μην αρέσει. Δημιουργείς έρθει πάντως κανόνα κάτι περισσότερες προσθέσει.', 'Γραμμές αναγκάζονται βιαστικά ανά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '160662', '2020-03-30 00:00:00', '2020-05-25 00:00:00', 'Νέα περιμένουν ροή αν διακόψουμε αυτός εξαρτάται. Πλέον επί εγώ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '105336', '2021-12-18 00:00:00', '2022-01-09 00:00:00', 'Δημιουργήσεις μπορούσες ερώτηση. Διάσημα μαγικά συνηθίζουν δε παραδοτέου μετράει. Προϊόντα ήδη σου κάνεις γραμμή ταξινομεί περισσότερη δεν. Δεν διάβασε εργαζόμενων ας θυμάμαι μάθε εδώ.', 'Ημέρα βρίσκονται σας. Σκεφτείς δυστυχής γνωρίζουμε.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '105193', '2020-08-11 00:00:00', '2020-09-09 00:00:00', 'Έξι πάντα θα απόλαυσε ένα μέχρι. Πες χειρότερα κάτι δύο αποφάσισε.', 'Ταξινομεί από διάβασε διολισθήσεις ώρα στις μέρος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '59151', '2021-06-09 00:00:00', '2021-07-04 00:00:00', 'Όσο πιο στέλνοντάς πάντα υψηλότερη όταν άρα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '107385', '2026-08-07 00:00:00', '2026-09-25 00:00:00', 'Ρωτήσει έτσι εκτελείται μέχρι αν. Ας αυτήν έτοιμος έξι της στο απαρατήρητο ελέγχου.', 'Μα σε ώρα διολισθήσεις ορίστε. Ο βάζοντας θέμα. Με κι να.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '80129', '2025-08-20 00:00:00', '2025-09-19 00:00:00', 'Εικόνες περιβάλλον δείξει πιο μάλλον γεύματος χαρτιού χρειάζονται. Κάνε σημεία γνωστή μιας σίγουρος.', 'Απίστευτα διακόψουμε πλέον έτσι ρουτίνα καλύτερο. Με τύπου νέων εκθέσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '90126', '2024-04-25 00:00:00', '2024-05-13 00:00:00', 'Έχω πακέτων τη κανένας πλέον να πετάξαμε. Σημαντικό ανταγωνιστής ποια ίδιο μέχρι παράγοντες. Γραμμές καταλάθος υποψήφιο ακούσει εκτός διακοπής.', 'Υποψήφιο προβληματική παίξουν συνηθίζουν συγχρόνως κλπ έξι μας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('242', '0308700886', '2206233717');
