INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '110115', '2020-12-08 00:00:00', '2021-01-19 00:00:00', 'Σπίτι αποφάσισε συγχωνευτεί δείξει οι λέει. Στήλες ρωτάει για ως διευθυντές.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '30456', '2020-02-10 00:00:00', '2020-02-20 00:00:00', 'Κόψεις λιγότερο περισσότερη κοιτάζοντας κανένας δύο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '123922', '2021-05-19 00:00:00', '2021-06-21 00:00:00', 'Σχεδιαστής αρπάζεις μαγικά πλέον μάλλον όχι. Περιβάλλοντος ύψος ημέρα εκτελείται λοιπόν συγγραφείς. Ας πλέον συνάδελφος μπορούσες. Εκτελείται επί σημαντικός παραδώσεις κόλπα θέμα πρώτης.', 'Νέο όχι την σταματάς λαμβάνουν υψηλότερη συγγραφής.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '137914', '2022-10-06 00:00:00', '2022-11-26 00:00:00', 'Ένας χρησιμοποιούσες βιβλίο παραγωγικής έξι εργοστασίου. Όταν πάντα επεξεργασία.
