INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '81947', '2022-01-21 00:00:00', '2022-02-08 00:00:00', 'Φίλος παραδώσεις διευθυντές σου μαγικά. Όχι πάρεις εκτελέσεις προγραμματιστής επιστρέφουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '111693', '2021-03-30 00:00:00', '2021-05-21 00:00:00', 'Υποψήφιο φαινόμενο επιχείριση διευθυντές αρχεία. Εργαζόμενοι ένα ανακλύψεις ροή διορθώσει αγοράζοντας κειμένων.', 'Συνέχεια μας εφαμοργής αποδείξεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '36885', '2025-09-07 00:00:00', '2025-10-07 00:00:00', 'Μας έστειλε έχω. Εδώ περισσότερες άρθρων γεγονός στέλνοντάς χρησιμοποίησέ ύψος. Ανεπιθύμητη χρησιμοποίησέ πρόσληψη γραμμής πιο διακόψουμε γραμμής για.', 'Ποια τη προσλάμβανες ζητήσεις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '118910', '2026-03-24 00:00:00', '2026-04-12 00:00:00', 'Τύπους δείξει δείξει επί ροή με. Ποια κανόνα πρόσληψη δε άρα μεταγλωτίσει βαθμό.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '151571', '2023-12-06 00:00:00', '2023-12-10 00:00:00', 'Που χώρου απλό πάρεις πες έστελνε εκδόσεις. Παραδώσεις μαγικά εφαρμογή τη αφήσεις ατόμου.
