INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '130572', '2026-12-07 00:00:00', '2027-01-01 00:00:00', 'Κάνε πάντα εκείνου κι. Πλέον πάντα ας προγραμματιστής πιο. Θέματα διαδίκτυο κρατάει όσο πλέον παίξουν ύψος ποια.', 'Και ανταγωνιστής ήδη εκθέσεις. Τρόπο σας παραδώσεις γεύματος.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '108224', '2025-10-08 00:00:00', '2025-11-04 00:00:00', 'Μετράει που μάτσο εδώ. Εκτός πεδία του σαν αναφορά κύκλο ανταγωνιστής έτοιμος. Αναφέρονται παίρνει λοιπόν ποσοστό κι πρόσληψη χαμηλός.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '71176', '2022-09-08 00:00:00', '2022-09-30 00:00:00', 'Επί πόρτες αποστηθίσει ζητήσεις. Ωραίο αγοράζοντας περισσότερη. Κώδικα αρπάζεις βιαστικά ταξινομεί λαμβάνουν προσλάμβανες πετούν.', 'Υόρκη αναφέρονται στις μην από εκδόσεις. Μια απαράδεκτη ρουτίνα.');
