INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '34847', '2023-03-15 00:00:00', '2023-04-12 00:00:00', 'Καταλάθος αφήσεις για πάρα είχαμε ένα. Πάντα προσπαθούν χαρακτηριστικό προγραμματιστές.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '74071', '2024-05-21 00:00:00', '2024-07-14 00:00:00', 'Κόψεις νόμιζες μεταγλωτιστής αποθηκευτικού. Άπειρα ευκολότερο όταν διοικητικό μάλλον. Που τρόποι γραμμές.
