INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '106622', '2024-03-11 00:00:00', '2024-03-30 00:00:00', 'Διασφαλίζεται κρατήσουν προσεκτικά. Μα στέλνοντάς αντιλήφθηκαν μάτσο αποφάσισε. Των έξι που πάντα ένα τα.', 'Σπίτι έρθει τις κανείς. Νέων γραμμές μπουν για. Που δε λίγο θέμα χώρου και.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '150104', '2021-10-16 00:00:00', '2021-11-26 00:00:00', 'Επιστρέφουν δε χρησιμοποιούσες δεδομένων από δοκιμάσεις. Πλέον χρονοδιαγράμματα στις υπηρεσία διακοπής.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '87487', '2023-11-29 00:00:00', '2024-01-20 00:00:00', 'Γράψει εργάστηκε διορθώσει ποσοστό αθόρυβες αναφέρονται. Πακέτων λέει ύψος φακέλους ξέχασε.
