INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '113070', '2021-11-11 00:00:00', '2021-12-29 00:00:00', 'Άτομο κάτι και εκθέσεις. Διάσημα πάρα εγώ νέων οι διαπιστώνεις. Για γραφικά πετάνε μαγικά. Εγώ έλεγχος στο κάτι προκαλείς.', 'Εικόνες αποδείξεις ημέρα των μέγιστη με ποια ποσοστό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '81704', '2021-09-25 00:00:00', '2021-11-17 00:00:00', 'Την δημιουργείς ζητήσεις εκτός περιβάλλον μέσης χρησιμοποίησέ χάος. Μας τρόπο έτοιμος εκτελέσει παράδειγμα αγοράζοντας.', 'Εκτός μετρήσεις υόρκη διάβασε απαραίτητο χαρακτηριστικό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '66867', '2025-06-21 00:00:00', '2025-08-06 00:00:00', 'Εξακολουθεί χώρου αναφορά ανακλύψεις στις ίδιο χρειάζονται. Πρώτοι στις χαρακτηριστικό πολύ σημαντικός στις απαρατήρητο. Μια απλό προσπαθούν ταξινομεί για τύπου αρχεία.', 'Περισσότερες ζητήσεις ήδη από εργαλείων. Μάθε γεγονός σπίτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '63506', '2021-04-09 00:00:00', '2021-05-22 00:00:00', 'Απαραίτητο στις αντιλήφθηκαν φαινόμενο τους πετούν εκτελέσει. Κανόνα επιστρέφουν εντολές δούλευε κάνεις εκδόσεις διαδίκτυο. Μάθε χειρότερα κύκλο χρησιμοποιούνταν δείξει γράψει ακούσει τελειώσει.', 'Προγραμματιστής εκτελέσει κύκλο προσοχή φακέλους πρώτης ήδη μη.');
