INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '46603', '2025-03-21 00:00:00', '2025-05-14 00:00:00', 'Δε όχι πως από συνέχεια αποφάσισε ήδη γέλασαν. Τι αυτήν παράγοντες έξι υπηρεσία χάος. Γραμμή ας εργαζόμενων δεδομένων πετάξαμε πολύ αθόρυβες.', 'Αποθηκευτικού δεν λίγο άρθρων μάθε μα. Σαν σου σκεφτείς βάζοντας την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '99418', '2024-07-12 00:00:00', '2024-09-08 00:00:00', 'Τύπου πάντως εργοστασίου διοικητικό αφήσεις πεδία. Μη μεταφραστής διαδίκτυο νέων σε επιδιορθώσεις.', 'Ταξινομεί εργάστηκε εκτός παραδοτέου διακοπή αναφορά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '50564', '2023-07-31 00:00:00', '2023-08-26 00:00:00', 'Αποστηθίσει φίλος πεδία αναγκάζονται όσο έξι. Λοιπόν των έτσι άρα ελέγχου το.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '7536', '2023-04-15 00:00:00', '2023-05-21 00:00:00', 'Μάτσο μέχρι ανά φράση. Ερώτηση παράγοντες κανείς απίστευτα εκτελέσει όσο. Εργοστασίου κάτι πετούν.
