INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('252', '125143', '2026-06-23 00:00:00', '2026-08-05 00:00:00', 'Δοκιμάσεις πόρτες και εκθέσεις κανένας όχι περισσότερη. Από ήδη κανείς εγώ. Ευκολότερο θα νέων δημιουργήσεις πρώτοι εγώ.', 'Κώδικα παραδοτέου γραμμή φαινόμενο. Δε τελειώσει διευθυντές.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('253', '1710921659', '2604876770');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '25804', '2026-05-17 00:00:00', '2026-06-23 00:00:00', 'Εφαρμογής φράση μια δύο προγραμματιστής. Συνεχώς τύπου πως θέλεις προϊόντα.', 'Απαρατήρητο εφαρμογή εκθέσεις οι σταματάς στέλνοντάς. Ήδη επί να γνωρίζουμε μη.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '6309', '2025-02-28 00:00:00', '2025-04-12 00:00:00', 'Δείξει για συγκεντρωμένοι εκτελέσεις ορίστε πολύ. Ανεπιθύμητη πιο μιας μέγιστη συνάδελφος που. Ποσοστό πολύ χάος σπίτι στις. Δε προσλάμβανες κοιτάζοντας ποσοστό καλύτερο.', 'Μέχρι σκεφτείς απομόνωση έγραψες πάρα εργαζόμενων ήδη ένα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '25313', '2026-10-18 00:00:00', '2026-10-24 00:00:00', 'Εφαρμογής εφαρμογής ως κόλπα. Άρα εξακολουθεί ερώτηση για.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '146378', '2026-03-22 00:00:00', '2026-04-15 00:00:00', 'Τη προσπαθούν πάρα ερωτήσεις συνηθίζουν.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '30119', '2021-08-25 00:00:00', '2021-10-07 00:00:00', 'Αναγκάζονται επί χαρακτηριστικό εδώ. Τέλειοι άτομο στέλνοντάς βρίσκονται τοπικές ακούσει. Πιο εργασίας κι.', 'Εγώ διακοπής κλπ πιο. Άπειρα τον αρπάζεις μεταγλωτίσει πετάνε ότι άρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '37035', '2026-03-26 00:00:00', '2026-05-18 00:00:00', 'Για μη τον. Σου εκτός ίδιο γραμμές και έτσι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '125601', '2026-04-11 00:00:00', '2026-04-28 00:00:00', 'Πολύ εγώ ποια όχι ακούσει. Προβληματική δε τρέξει χρησιμοποιώντας. Τα σας για έτοιμος ρωτήσει.
