INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('255', '1604918068', '2307998267');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '43986', '2021-10-08 00:00:00', '2021-10-27 00:00:00', 'Επενδυτής εγώ έτσι ποια το λιγότερο έτσι. Χειρότερα επί αν μιας από. Αρέσει τύπους εργάστηκε τις. Αναφέρονται αποθηκευτικού εκείνου.', 'Κάνεις παίρνει αν περιβάλλοντος περιμένουν επί εδώ προκύπτουν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '160260', '2024-07-06 00:00:00', '2024-08-27 00:00:00', 'Γνωρίζουμε ίδιο μέχρι εκδόσεις ναι επί άλγεβρα εργάστηκε. Στήλες διορθώσεις αθόρυβες τα σκεφτείς ίδιο για. Διακόψουμε πρώτοι τελειώσει ακούσει σταματάς υπηρεσία. Ποια πιο βουτήξουν ένα μιας.', 'Σας μηχανής συγγραφείς περισσότερη σίγουρος. Στις παραγωγικής ένας ταξινομεί.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '34564', '2026-04-25 00:00:00', '2026-06-05 00:00:00', 'Γραμμές ποσοστό αγοράζοντας γράψει δύο ένας. Ευκολότερο και πρόσληψη έτσι εκτελείται.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '85630', '2025-02-06 00:00:00', '2025-02-26 00:00:00', 'Αναφορά ήδη ότι μη βιαστικά κανόνα γραμμή. Διακόψουμε ακούσει τοπικές. Ανά ήδη τέλειοι είχαμε.', 'Τρέξει κάνεις ναι μάθε. Πετούν αφήσεις αγοράζοντας αφήσεις εκτός ωραίο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '131998', '2025-06-10 00:00:00', '2025-07-14 00:00:00', 'Δυστυχής μάθε πολύ υψηλότερη εκδόσεις απόλαυσε βρίσκονται. Συγγραφείς ήδη έχω ερώτηση πακέτων μέχρι φράση.', 'Ας μέχρι περίπου δύο όχι. Πως τι διαπιστώνεις ότι δύο μην συνεχώς άρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '119773', '2024-05-29 00:00:00', '2024-06-14 00:00:00', 'Θυμάμαι ιδιαίτερα στη κάνε σκεφτείς γραμμής. Τα περιεχόμενα διοικητικό μη προσθέσει για εταιρείες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '92615', '2026-07-17 00:00:00', '2026-08-21 00:00:00', 'Χαμηλός μου μάτσο μέγιστη διοικητικό. Αρχεία περιβάλλον πολύ προσπαθήσεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '100695', '2026-12-13 00:00:00', '2027-01-15 00:00:00', 'Συγγραφείς εκτός τον ζητήσεις ανακλύψεις τι. Προσεκτικά μεταγλωτιστής άρθρων πιο επεξεργασία έξι διάσημα μέρος.', 'Όταν κειμένων έχω υψηλότερη σωστά τοπικές. Όταν προγραμματιστής βάζοντας νέο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '57212', '2022-07-30 00:00:00', '2022-09-07 00:00:00', 'Πάρεις αυτήν συγχωνευτεί εκτός τύπους. Κι προσπαθούν του ως είχαμε. Πλέον λέει αποθηκευτικού μας οι ήδη κανόνα.', 'Λοιπόν άρα εκθέσεις ερώτηση εδώ κρατάει έτοιμος βιαστικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '584', '2024-07-26 00:00:00', '2024-09-14 00:00:00', 'Ταξινομεί εργασίας πρώτοι αποδείξεις αποστηθίσει ένας πετάξαμε αποδείξεις. Εδώ κειμένων τρόποι κόψεις μεταγλωτίσει μέγιστη.', 'Φίλος ροή δύο ποσοστό αφήσεις οι πεδία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('256', '2205543692', '1202844163');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '88958', '2024-12-07 00:00:00', '2025-01-28 00:00:00', 'Πάντως προγραμματιστής υόρκη ελέγχου. Για πάρεις νόμιζες έχω τύπους ακούσει δημιουργια. Διαδίκτυο μάτσο έτσι περιβάλλον διευθυντές. Συγχρόνως σου μάθε συγγραφείς εξοργιστικά μάθε λίγο.', 'Μα διαδίκτυο διακοπής. Γραφικά ερωτήσεις εγώ τις.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '57169', '2021-12-14 00:00:00', '2022-01-10 00:00:00', 'Αποδείξεις συνεχώς θέματα πρόσληψη γραμμή. Μην επιδιόρθωση έξι δούλευε έξι απόλαυσε γραμμές.', 'Συνεχώς πλέον χαρτιού χάος. Της λαμβάνουν ότι έτοιμος την τύπου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '49704', '2020-12-10 00:00:00', '2020-12-27 00:00:00', 'Καλύτερο πάντως μεταγλωτιστής αποθηκευτικού ως έρθει μάλλον έρθει. Μερικούς δεν πως δυστυχώς κι έτοιμος.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '143456', '2026-07-30 00:00:00', '2026-08-23 00:00:00', 'Ατόμου αναγκάζονται κόψεις σημεία περιβάλλον ορίστε χειρότερα χρησιμοποιώντας. Για έστελνε ανεπιθύμητη. Κανόνα με παίξουν του χρησιμοποιούνταν.', 'Απαρατήρητο ημέρα διαπιστώνεις γράψει δυστυχώς θα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '3982', '2024-06-22 00:00:00', '2024-07-15 00:00:00', 'Πλέον επί κύκλο ας μεταγλωτιστής έξι το. Αποκλειστικούς διαχειριστής από αυτός συνάδελφος. Εγώ έχω μεταγλωτίσει έστελνε πολύ δεν. Πετάνε της μια ανακλύψεις δεν.', 'Επιχείριση δημιουργείς προσπαθούν ανά δύο σίγουρος. Πάντα στη μην.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '160600', '2026-09-17 00:00:00', '2026-10-18 00:00:00', 'Εγώ και πάντως εγώ. Προσοχή για ως παραπάνω έτσι συγγραφής σταματάς. Είχαμε που σε.', 'Πλέον ελέγχου πηγαίου πλέον εσωτερικών αν πηγαίου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '126480', '2024-02-05 00:00:00', '2024-03-21 00:00:00', 'Άρα χρησιμοποιούσες μέσης διορθώσεις να βάζοντας για. Μέγιστη γνωστή θέμα μεταγλωτίσει θα. Έξι καταλάθος έξι σταματάς γραμμής όχι.', 'Τον όταν προσεκτικά. Αν προκαλείς δύο δυστυχής άρα των την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('257', '3110634127', '2206071697');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '75121', '2025-01-06 00:00:00', '2025-03-04 00:00:00', 'Νέων βιβλίο εγώ ημέρα ανά κάτι γραμμές. Που έχω πάντα παραδοτέου ένας μάτσο προσπαθούν ρωτήσει.', 'Νιρβάνα νιρβάνα μηχανής τις δυστυχώς μα ωραίο εγώ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '154833', '2021-06-28 00:00:00', '2021-07-24 00:00:00', 'Όταν εκτός συνέχεια κι προγραμματιστές επί νέου. Διαφήμιση μετρήσεις εξαρτάται χρόνου νιρβάνα γιαυτό συγχρόνως αναφορά. Αυτός τελειώσει πήρε και τα άλγεβρα.', 'Χρησιμοποιούσες δεν αρέσει μέχρι θα μιας πιο σπίτι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '56372', '2022-10-13 00:00:00', '2022-11-20 00:00:00', 'Προσοχή έρθει έτσι συγχρόνως. Δημιουργια τύπου διολισθήσεις ότι αλγόριθμου απαραίτητο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '62533', '2020-11-19 00:00:00', '2021-01-16 00:00:00', 'Τα γραμμή αφήσεις φακέλους έλεγχος συνάδελφος εξακολουθεί. Συγγραφής σταματάς άτομο επεξεργασία έτσι ανά και εργάστηκε.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '152387', '2023-04-16 00:00:00', '2023-05-07 00:00:00', 'Δύο να με ζητήσεις μεταφραστής γραμμή περιβάλλον. Να ημέρα παραδοτέου είχαμε μετράει ταξινομεί. Συνεντεύξεις και τοπικές αναγκάζονται περιεχόμενα βγήκε.', 'Σαν εκτελείται περισσότερη εργασίας κώδικα τεκμηριώνει πλέον.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '20507', '2025-10-10 00:00:00', '2025-10-30 00:00:00', 'Τα ανά χώρου πρώτο γράψει. Ήδη πρώτο για αρπάζεις φίλος πως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('258', '0111720422', '2806235869');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '90624', '2022-12-29 00:00:00', '2023-01-03 00:00:00', 'Προγραμματιστής σας μάθε διακόψουμε ορίστε αν πιο. Να το περιεχόμενα μάθε εργάστηκε ημέρα γεγονός.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '32767', '2020-05-29 00:00:00', '2020-07-21 00:00:00', 'Καταλάθος βιαστικά ανώδυνη κανόνα ιδιαίτερα επί ο. Μάθε θυμάμαι τοπικές παραδώσεις τεκμηριώνει. Διοικητικό χρησιμοποιούνταν πετάνε μιας.', 'Πολύ πάρα προσεκτικά προϊόντα μέχρι πηγαίου ίδιο. Μάθε ίδιο προσπαθούν βαθμό.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '64822', '2026-06-18 00:00:00', '2026-07-09 00:00:00', 'Ως περισσότερες χαμηλός βάζοντας κόλπα. Αν μα οι. Πρώτης πιο διακόψουμε τύπου μην ταξινομεί το λέει.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '131630', '2020-07-02 00:00:00', '2020-07-24 00:00:00', 'Δύο ένα συγχωνευτεί τα καλύτερο. Πηγαίου σου διακόψουμε διορθώσεις νέο υπηρεσία εκείνου απαρατήρητο. Εταιρείες πακέτων βγήκε αναφορά θα.', 'Οι χάος ρουτίνα εργοστασίου πόρτες στο όχι όταν.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '157485', '2021-03-21 00:00:00', '2021-03-26 00:00:00', 'Κάτι πάντα από κι σημεία μεταγλωτίσει γραμμές. Να σε πρώτης δύο πάντως σας σταματάς. Πολύ από τα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '77470', '2023-08-02 00:00:00', '2023-09-19 00:00:00', 'Τρόποι πάρεις επιχείριση ορίστε της στο ως. Σαν τεσσαρών σταματάς εδώ μετρήσεις νέα ύψος. Άρθρων τρέξει εφαρμογής λίγο όταν επιδιορθώσεις όχι ένα.', 'Κώδικάς διαδίκτυο θα πάντα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '80452', '2026-01-21 00:00:00', '2026-02-12 00:00:00', 'Προσπαθήσεις δε έτσι συνεντεύξεις. Προσεκτικά των δυστυχής περιμένουν στήλες.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('258', '149970', '2024-08-06 00:00:00', '2024-09-09 00:00:00', 'Έτοιμος κειμένων με προσλάμβανες νέα λέει πολύ βρίσκονται. Εφαρμογής μεταφραστής σαν αυτός ως επιδιόρθωση διαπιστώνεις.', 'Προσπαθήσεις εργοστασίου κώδικα μάθε ανά με. Κώδικάς πόρτες επί νόμιζες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('259', '1210738304', '1903188884');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '114208', '2021-12-05 00:00:00', '2022-01-15 00:00:00', 'Μάλλον επί εργασίας σκεφτείς αποδείξεις. Υόρκη πεδία θέλεις αρχεία. Μέχρι δεν γειτονιάς μας θυμάμαι φίλος διαδίκτυο ρουτίνα.', 'Ανά υποψήφιο ξέχασε σημαντικός πάντως και που.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '53766', '2024-05-24 00:00:00', '2024-07-23 00:00:00', 'Εταιρείες χρειάζονται αρχεία εκτός. Εκτός κειμένων διασφαλίζεται το τοπικές χάος ανακλύψεις.', 'Όσο πετούν μέγιστη πάντα. Χαρτιού άρα παράγοντες μη τρόποι μεταφραστής.');
