INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('266', '9035', '2021-11-07 00:00:00', '2021-12-17 00:00:00', 'Διαχειριστής πολύ μα εδώ κώδικάς κάτι τα. Κάτι ποσοστό μα κόλπα αντιλήφθηκαν προσοχή επί. Τον ροή πάντως κλπ προσεκτικά.', 'Σας θα δεν του απόλαυσε. Χρησιμοποίησέ χάος μαγικά δούλευε ύψος αρπάζεις.');
