INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '113743', '2023-05-30 00:00:00', '2023-07-12 00:00:00', 'Που δε μα πάρεις προσπαθούν ναι διάσημα. Πλέον ότι μεταγλωτιστής.', 'Χαρακτηριστικό καταλάθος ότι εταιρείες δύο θέματα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '4641', '2021-08-15 00:00:00', '2021-09-17 00:00:00', 'Κάνε κάνεις γεύματος. Μπορούσες για προγραμματιστές άρα στέλνοντάς διαπιστώνεις. Στις πολύ εργαζόμενων.', 'Σημεία δε γειτονιάς υόρκη τρόπο τύπου τους. Χρησιμοποίησέ ωραίο εκτός παίρνει.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '37169', '2020-12-30 00:00:00', '2021-02-21 00:00:00', 'Βιαστικά τη χρησιμοποιώντας. Πρώτο εγώ σου πρώτοι έστειλε. Μάλλον και ανά που γράψει γεύματος πάντα. Δίνοντας μεταγλωτίσει πιο συγχρόνως λαμβάνουν νέων περιβάλλον.', 'Εντολές λετπά τοπικές από θέλεις. Νόμιζες δουλεύει ροή πως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '122994', '2023-08-29 00:00:00', '2023-10-17 00:00:00', 'Πλέον πόρτες μου σκεφτείς φράση μεταφραστής. Κώδικα εδώ εφαρμογής γραμμές κόλπα οι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('271', '2201959666', '2101430205');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '54746', '2024-05-27 00:00:00', '2024-06-13 00:00:00', 'Εκτελέσεις εργοστασίου γραμμή παίρνει εκείνου νέου.', 'Πλέον δίνοντας άρα γιαυτό για της πετάνε πρώτο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '74636', '2022-11-10 00:00:00', '2022-11-18 00:00:00', 'Πλέον πετάξαμε προκαλείς υόρκη. Χειρότερα χρονοδιαγράμματος περιβάλλον της μάλλον στη.', 'Γεγονός χάος εγώ παίξουν πηγαίου. Αποφάσισε έλεγχος αν πάντως.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '35666', '2022-03-31 00:00:00', '2022-04-03 00:00:00', 'Εφαμοργής ανά νέου δεν μέγιστη δημιουργείς. Επιδιορθώσεις ανά αρχεία διορθώσει βάζοντας διακοπής χρειάζονται ίδιο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '100179', '2021-02-21 00:00:00', '2021-04-05 00:00:00', 'Σημεία βασανίζουν νέου επιδιορθώσεις. Προσλάμβανες ακούσει στήλες τελειώσει τον ναι. Δεν πηγαίου ωραίο κάτι άλγεβρα κάτι αρπάζεις.', 'Ξέχασε και ευκολότερο θα ώρα μιας γνωστή.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '52045', '2025-07-17 00:00:00', '2025-08-29 00:00:00', 'Απαρατήρητο αυτήν συνάδελφος συνάδελφος εγώ διασφαλίζεται. Όσο μάθε σου παράγοντες εκείνου δύο έτσι. Πιο τι πετούν διαπιστώνεις τεκμηριώνει έξι.', 'Χώρου τύπου χαρακτηριστικών κανείς.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '71756', '2021-06-24 00:00:00', '2021-08-04 00:00:00', 'Φίλος προκαλείς επιστρέφουν βουτήξουν ήδη ύψος ακούσει. Βιβλίο πηγαίου κρατήσουν του τη μερικούς κύκλο. Για στη σπίτι πως όχι δυστυχής ορίστε ζητήσεις.', 'Εκείνου εργάστηκε συνεχώς παραγωγικής που.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '88087', '2023-01-05 00:00:00', '2023-02-19 00:00:00', 'Έστειλε δε όσο εικόνες σίγουρος περιμένουν σας.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '106494', '2024-05-22 00:00:00', '2024-06-19 00:00:00', 'Σαν εργοστασίου δυστυχής μην συγχρόνως γεγονός περιμένουν. Γειτονιάς δεν χάος εκτός.', 'Άρα δύο γεύματος ποια διάβασε ίδιο. Σας θέλεις πως έγραψες συγκεντρωμένοι.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '1138', '2021-09-14 00:00:00', '2021-10-22 00:00:00', 'Έτσι νόμιζες μερικούς δεν μπουν. Έτσι νέων σημαντικό. Γνωστή ποσοστό εκτός εικόνες δημιουργια ας σκεφτείς.', 'Γέλασαν πετάνε χαρακτηριστικό απομόνωση ο. Γεύματος πολύ χαρακτηριστικό της με.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '125277', '2024-08-08 00:00:00', '2024-09-02 00:00:00', 'Εκτελέσεις κάτι ας χαμηλός κύκλο. Μέχρι και τοπικές διορθώσεις παραπάνω υόρκη νέο.', 'Τους καταλάθος άρα περιβάλλον άρα επιστρέφουν.');
