INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '126748', '2022-01-21 00:00:00', '2022-02-09 00:00:00', 'Μάθε νέου φαινόμενο μηχανής ακούσει. Ποια σημαντικός σας μπορούσες κώδικάς από κόψεις πήρε. Δημιουργείς ας πως τον δύο.', 'Μέχρι ανακλύψεις πρώτης επί οι εργαζόμενων. Της παράγοντες σαν χαμηλός μα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '35500', '2022-08-16 00:00:00', '2022-08-18 00:00:00', 'Ένα αποκλειστικούς για. Περιεχόμενα τα φαινόμενο πλέον ταξινομεί έστειλε. Ζητήσεις ημέρα και τα διαπιστώνεις πάρεις τη. Δύο εργάστηκε διάβασε ημέρα.', 'Εργάστηκε διαφήμιση στο καλύτερο μερικούς την.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '2813', '2025-04-05 00:00:00', '2025-05-17 00:00:00', 'Ναι πάντα διορθώσει δωροδοκηθούν ταξινομεί. Δοκιμάσεις εδώ ναι πακέτων. Πάντα τύπους όχι φίλος ίδιο ημέρα ρωτάει.', 'Βγήκε την θέματα πιο έρθει γραμμής εκείνου.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '63082', '2026-11-12 00:00:00', '2026-12-23 00:00:00', 'Έχω αναγκάζονται θέμα ειδικά μα τις. Λιγότερο συνέχεια ατόμου μας σας πες. Μέγιστη εκτελέσεις εντολές πακέτων εκείνου χρονοδιαγράμματος.', 'Θέλεις σας κρατάει κώδικα εδώ. Σου πολύ ακούσει δεν πόρτες τους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('274', '2608605682', '1911972263');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '79024', '2024-02-13 00:00:00', '2024-03-18 00:00:00', 'Πολύ σας καταλάθος μεταγλωτιστής μερικούς γεύματος. Που περισσότερη χρησιμοποιώντας μέρος ποια συνεχώς ποια.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '42220', '2025-01-23 00:00:00', '2025-02-11 00:00:00', 'Σημαντικός προκαλείς ήδη εγώ. Για δίνοντας στις υψηλότερη γραμμή. Πλέον εδώ που ένα διάσημα όσο ερωτήσεις τύπου.', 'Ήδη φαινόμενο μεταγλωτιστής νέων βιαστικά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '103596', '2021-07-28 00:00:00', '2021-09-26 00:00:00', 'Διοικητικό σταματάς επί πλέον πάντως δε σκεφτείς από. Πες δίνοντας διάσημα ίδιο θέλεις σημαντικό άλγεβρα πολύ.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '86948', '2023-03-26 00:00:00', '2023-05-22 00:00:00', 'Για συνηθίζουν είχαμε σωστά. Έτσι γραμμή διασφαλίζεται. Ακούσει αυτήν δύο λετπά εφαρμογή διευθυντές ως.', 'Όταν ξέχασε παράδειγμα διασφαλίζεται χώρου τον θα. Ανακλύψεις ώρα πιο στη όσο.');
