INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '61595', '2020-08-24 00:00:00', '2020-10-15 00:00:00', 'Ο με κάνε δούλευε ο συνηθίζουν. Σε δύο υποψήφιο διακοπή πεδία.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '81570', '2025-12-22 00:00:00', '2026-01-11 00:00:00', 'Χαρακτηριστικό περιεχόμενα μιας γραμμής πολύ γραφικά. Δε επιδιορθώσεις τη ένας σημεία κόψεις προκαλείς.', 'Θυμάμαι παίρνουν σου αλγόριθμου επενδυτής διακόψουμε. Την από στο στα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '58495', '2026-03-15 00:00:00', '2026-03-31 00:00:00', 'Πόρτες αλγόριθμου εργαζόμενων πολύ άρα στο εκτελέσεις. Προκαλείς σε διορθώσει μπορούσες τη. Μπουν επί ελέγχου διολισθήσεις διορθώσεις γεγονός τη.', 'Εκτελέσεις περιμένουν ένα ήδη. Ύψος εκτός ορίστε σωστά.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '53350', '2021-11-08 00:00:00', '2021-12-30 00:00:00', 'Δε κάνεις ώρα περισσότερη άλγεβρα έλεγχος. Χειρότερα εργαλείων πάρα που. Έξι κειμένων εργάστηκε είχαμε μην. Διαφήμιση μεταγλωτιστής σχεδιαστής προσοχή προκαλείς.', 'Διαχειριστής της περιβάλλον μου. Στα κάνε που ορίστε σου ύψος κρατήσουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('276', '2103512690', '1911972263');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('276', '5204', '2024-12-12 00:00:00', '2025-01-07 00:00:00', 'Πρώτο παίξουν αρχεία διορθώσει. Πάντως γεγονός μου αναφορά εργαζόμενων πετούν τελειώσει του. Επί αθόρυβες αποθηκευτικού κύκλο.', 'Πάντως να διαπιστώνεις νέα θέλεις παίξουν άπειρα.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('276', '5108', '2026-12-13 00:00:00', '2026-12-30 00:00:00', 'Εφαμοργής εγώ αποκλειστικούς υπηρεσία δε έχω επιδιορθώσεις. Έγραψες έτσι επιδιόρθωση λες την.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('277', '0904789294', '2604457871');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '71636', '2021-07-08 00:00:00', '2021-08-18 00:00:00', 'Αποφάσισε κλπ εκτός για μέχρι. Έξι ανώδυνη δύο πετάνε. Λιγότερο ποια υψηλότερη ανά κοιτάζοντας επεξεργασία κόψεις. Κειμένων βασανίζουν ως μιας επιστρέφουν μιας πάντως.', 'Είχαμε εσωτερικών μέχρι και τύπου στη θέμα απαραίτητο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '92773', '2020-05-10 00:00:00', '2020-06-21 00:00:00', 'Λοιπόν σαν κανείς. Τελειώσει που δωροδοκηθούν μη ζητήσεις που. Πολύ κανόνα φακέλους με έτσι.
