INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '25022', '2023-08-28 00:00:00', '2023-09-10 00:00:00', 'Πάντα σαν ποια ποσοστό διάσημα ναι κάτι άρα. Μέχρι εσωτερικών θα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '72007', '2025-05-11 00:00:00', '2025-06-19 00:00:00', 'Αποδείξεις παίξουν λέει χάος χάος πάντα δείξει. Πολύ έτσι περισσότερη κι.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '147872', '2025-01-11 00:00:00', '2025-03-01 00:00:00', 'Νιρβάνα βιβλίο του χρονοδιαγράμματος. Έξι πολύ κι διορθώσεις ίδιο έστελνε χάος σου.', 'Χειρότερα απαραίτητο εντολές περισσότερη χρόνου στο εδώ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '51672', '2022-09-18 00:00:00', '2022-09-26 00:00:00', 'Εκτός μέσης ερωτήσεις εκτελέσει αποδείξεις προσπαθήσεις. Μηχανής κύκλο πολύ τεκμηριώνει. Κι ανταγωνιστής άρθρων αυτήν.', 'Στις σαν πιο. Ανταγωνιστής βουτήξουν δουλεύει μέχρι ποια.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '147025', '2021-06-20 00:00:00', '2021-08-13 00:00:00', 'Αντιλήφθηκαν αφήσεις ωραίο κώδικα ταξινομεί. Αθόρυβες μεταγλωτίσει απλό εγώ λέει μηχανής. Άπειρα ανταγωνιστής πρώτο για. Λιγότερο δωροδοκηθούν χρειάζονται διορθώσεις εφαρμογής βρίσκονται ένα.', 'Όταν ναι σου ποια εταιρείες τα. Μας αλγόριθμου μέχρι μέρος αναγκάζονται.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '45728', '2020-09-14 00:00:00', '2020-11-01 00:00:00', 'Διακοπής ανά προσοχή θα προγραμματιστές. Ως προσπαθήσεις για εγώ τελειώσει αν παραδοτέου ώρα.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '8159', '2023-10-12 00:00:00', '2023-12-05 00:00:00', 'Κρατάει τους βρίσκονται τύπου ας μη πάντως στις. Κώδικάς διασφαλίζεται βασανίζουν έτσι αποστηθίσει λοιπόν. Λαμβάνουν νέου στο μέρος συνηθίζουν την διάσημα.', 'Έξι ορίστε αγοράζοντας γνωστή. Αυτός φαινόμενο για προσοχή με παραγωγικής όσο.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '150497', '2021-03-28 00:00:00', '2021-04-19 00:00:00', 'Αθόρυβες απόλαυσε μου νόμιζες. Ποια περισσότερη αναγκάζονται χρησιμοποιούνταν επιδιορθώσεις βουτήξουν. Γραμμές περιβάλλοντος τη τα κειμένων.', 'Απαρατήρητο δε ας. Διακοπής πρόσληψη προγραμματιστής στα βάζοντας σας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('279', '2108896469', '0309799563');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '6259', '2026-08-12 00:00:00', '2026-08-31 00:00:00', 'Λοιπόν για από νέου συγγραφής στη. Ιδιαίτερα ποια κάνεις συνέχεια χρειάζονται.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '58205', '2026-08-15 00:00:00', '2026-08-24 00:00:00', 'Τις πολύ παραπάνω τελειώσει χαρτιού ανά. Τρόποι δεν μέχρι έχω.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('280', '0503773019', '1305799211');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '149285', '2021-03-05 00:00:00', '2021-04-18 00:00:00', 'Πετούν γιαυτό πάντα εδώ. Άλγεβρα βιαστικά υόρκη πάντα τέλειοι προσλάμβανες. Σου στραβά τον πρώτο μα διαπιστώνεις μην. Το πάρα σε πηγαίου σχεδιαστής ζητήσεις ορίστε.', 'Εργαζόμενοι δείξει μιας πετάξαμε. Απίστευτα χρονοδιαγράμματα γνωστή γεγονός.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '158646', '2025-02-09 00:00:00', '2025-02-10 00:00:00', 'Μέχρι λετπά πολύ μην διοικητικό γεγονός. Προσοχή αρέσει μέχρι δεν ύψος λοιπόν. Από χαρτιού δοκιμάσεις ήδη άτομο.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '66931', '2021-10-27 00:00:00', '2021-11-26 00:00:00', 'Συνέχεια σημαντικό πιο συνέχεια ξέχασε περιμένουν είχαμε. Χρησιμοποιούσες προσθέσει χρονοδιαγράμματα ανά χρονοδιαγράμματος χρησιμοποιούσες προκαλείς. Πετάνε δημιουργια κειμένων άλγεβρα.', 'Μην εργαζόμενων αποκλειστικούς επί τους μη εγώ.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '64974', '2020-04-25 00:00:00', '2020-06-08 00:00:00', 'Λετπά μα για. Επί χαρακτηριστικό εδώ χρησιμοποιούσες ότι χώρου θέλεις.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '102419', '2025-12-11 00:00:00', '2026-02-06 00:00:00', 'Προσπαθήσεις ναι εργοστασίου ζητήσεις διολισθήσεις. Μου νέου πηγαίου εκτός. Περισσότερες στήλες χώρου παίξουν.', 'Έξι πόρτες άρα. Συγγραφείς συνέχεια γραμμής μάλλον λες.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '134718', '2024-01-09 00:00:00', '2024-02-19 00:00:00', 'Δε όσο σκεφτείς με σας. Είχαμε εγώ ένα γραμμή μέρος λες κάνε πακέτων.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '71166', '2025-05-29 00:00:00', '2025-05-31 00:00:00', 'Επιδιόρθωση πρώτο συγχρόνως κώδικα έλεγχος έστελνε γέλασαν. Σαν επί γιαυτό τα πάντως σε. Μάτσο δωροδοκηθούν μετρήσεις τον.
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '30846', '2023-10-24 00:00:00', '2023-11-23 00:00:00', 'Την στέλνοντάς και θέλεις όχι περιβάλλον μιας. Ορίστε υψηλότερη χρησιμοποιούνταν μα για νέου ο κώδικάς.', 'Λιγότερο δούλευε μηχανής τρόπο παραδώσεις. Στα από ήδη στις μέσης.');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '56436', '2026-10-01 00:00:00', '2026-11-19 00:00:00', 'Εσωτερικών θέλεις αντιλήφθηκαν επί. Τεσσαρών να πάρα καλύτερο απαραίτητο.
